import type { PublicCard } from '../../../types';

export const psychologyCards: PublicCard[] = [
  { id: 'dc-psychology-0001', deck_id: 'deck-psychology', front: 'Cognitive Dissonance', back: 'The mental discomfort experienced when holding two or more contradictory beliefs simultaneously, often motivating attitude or behavior change to reduce the conflict.', sort_order: 1 , front_translations: {"es":"Dissonancia Cognitiva","de":"Kognitive Dissonanz","fr":"Dissonance cognitive","tr":"Bilişsel Uyumsuzluk","nl":"Cognitieve dissonantie","ru":"Когнитивный диссонанс","zh":"认知失调","pt_BR":"Dissonância Cognitiva","pt_PT":"Dissonância Cognitiva"}, back_translations: {"es":"El malestar mental experimentado al mantener de los o más creencias contradictorias simultáneamente, frecuentemente motivando cambios de atitude o comportamiento para reduzir el conflito.","de":"Das mentale Unbehagen, das entsteht, wenn man zwei oder mehr widersprüchliche Überzeugungen gleichzeitig hält, und das häufig eine Einstellungs- oder Verhaltensänderung motiviert, um den Konflikt zu verringern.","fr":"L'inconfort mental ressenti lorsqu'on détient simultanément deux ou plusieurs croyances contradictoires, motivant souvent un changement d'attitude ou de comportement pour réduire le conflit.","tr":"Aynı anda iki veya daha fazla çelişkili inancı taşırken yaşanan zihinsel rahatsızlık; çoğunlukla çatışmayı azaltmak için tutum ya da davranış değişikliğini tetikler.","nl":"Het mentale ongemak dat wordt ervaren bij het gelijktijdig aanhangen van twee of meer tegenstrijdige overtuigingen, wat vaak leidt tot een verandering in houding of gedrag om het conflict te verminderen.","ru":"Психологический дискомфорт, возникающий при одновременном удержании двух или более противоречивых убеждений, часто побуждающий к изменению установок или поведения для уменьшения конфликта.","zh":"同时持有两种或两种以上相互矛盾的信念时所产生的心理不适感，通常会驱使人们改变态度或行为以减少这种冲突。","pt_BR":"O desconforto mental experimentado ao manter duas ou mais crenças contraditórias simultaneamente, frequentemente motivando mudanças de atitude ou comportamento para reduzir o conflito.","pt_PT":"O desconforto mental experimentado ao manter duas ou mais crenças contraditórias simultaneamente, frequentemente motivando alterações de atitude ou comportamento para reduzir o conflito."}},
  { id: 'dc-psychology-0002', deck_id: 'deck-psychology', front: 'Classical Conditioning', back: 'A learning process in which a neutral stimulus becomes associated with a meaningful stimulus (as demonstrated by Pavlov), eventually eliciting a similar response on its own.', sort_order: 2 , front_translations: {"es":"Condicionamento Clássico","de":"Klassische Konditionierung","fr":"Conditionnement classique","tr":"Klasik Koşullanma","nl":"Klassieke conditionering","ru":"Классическое обусловливание","zh":"经典条件反射","pt_BR":"Condicionamento Clássico","pt_PT":"Condicionamento Clássico"}, back_translations: {"es":"Un proceso de aprendizaje en el qual un estímulo neutro se associa a un estímulo significativo (como demonstrado por Pavlov), eventualmente provocando una respuesta semelhante por si só.","de":"Ein Lernprozess, bei dem ein neutraler Reiz mit einem bedeutungsvollen Reiz verknüpft wird (wie von Pawlow demonstriert) und schließlich allein eine ähnliche Reaktion auslöst.","fr":"Un processus d'apprentissage dans lequel un stimulus neutre devient associé à un stimulus significatif (comme démontré par Pavlov), finissant par provoquer une réponse similaire à lui seul.","tr":"Nötr bir uyaranın anlamlı bir uyaranla ilişkilendirildiği (Pavlov tarafından gösterildiği gibi) ve sonunda kendi başına benzer bir tepki uyandırdığı bir öğrenme süreci.","nl":"Een leerproces waarbij een neutrale stimulus geassocieerd raakt met een betekenisvolle stimulus (zoals aangetoond door Pavlov) en uiteindelijk op zichzelf een vergelijkbare reactie oproept.","ru":"Процесс научения, при котором нейтральный стимул связывается со значимым стимулом (как продемонстрировал Павлов) и в конечном итоге сам по себе вызывает аналогичную реакцию.","zh":"一种学习过程，其中中性刺激与有意义的刺激相关联（如巴甫洛夫所证明的），最终能够单独引发类似的反应。","pt_BR":"Um processo de aprendizagem no qual um estímulo neutro se associa a um estímulo significativo (como demonstrado por Pavlov), eventualmente provocando uma resposta semelhante por si só.","pt_PT":"Um processo de aprendizagem no qual um estímulo neutro se associa a um estímulo significativo (como demonstrado por Pavlov), acabando por provocar uma resposta semelhante por si só."}},
  { id: 'dc-psychology-0003', deck_id: 'deck-psychology', front: 'Confirmation Bias', back: 'The tendency to search for, interpret, and recall information in a way that confirms one\'s pre-existing beliefs while ignoring or discounting contradicting evidence.', sort_order: 3 , front_translations: {"es":"Viés de Confirmación","de":"Bestätigungsfehler","fr":"Biais de confirmation","tr":"Doğrulama Yanlılığı","nl":"Bevestigingsbias","ru":"Предвзятость подтверждения","zh":"确认偏误","pt_BR":"Viés de Confirmação","pt_PT":"Viés de Confirmação"}, back_translations: {"es":"La tendencia de buscar, interpretar y recordar informaciones de forma a confirmar creencias preexistentes, ignorando o descartando evidencias contradictorias.","de":"Die Tendenz, Informationen so zu suchen, zu interpretieren und zu erinnern, dass sie die eigenen Überzeugungen bestätigen, während widersprechende Belege ignoriert oder abgewertet werden.","fr":"La tendance à rechercher, interpréter et se souvenir des informations de manière à confirmer ses croyances préexistantes tout en ignorant ou en minimisant les preuves contradictoires.","tr":"Bilgiyi, kişinin önceden var olan inançlarını doğrulayacak şekilde arama, yorumlama ve hatırlama eğilimi; çelişen kanıtları görmezden gelme veya önemsizleştirme.","nl":"De neiging om informatie te zoeken, te interpreteren en te herinneren op een manier die de eigen bestaande overtuigingen bevestigt, terwijl tegenstrijdig bewijs wordt genegeerd.","ru":"Склонность искать, интерпретировать и запоминать информацию таким образом, чтобы она подтверждала уже существующие убеждения, игнорируя или обесценивая противоречащие доказательства.","zh":"倾向于以确认自己已有信念的方式来搜索、解读和回忆信息，同时忽略或贬低相矛盾的证据。","pt_BR":"A tendência de buscar, interpretar e recordar informações de forma a confirmar crenças preexistentes, ignorando ou descartando evidências contraditórias.","pt_PT":"A tendência de procurar, interpretar e recordar informações de forma a confirmar crenças preexistentes, ignorando ou descartando evidências contraditórias."}},
  { id: 'dc-psychology-0004', deck_id: 'deck-psychology', front: 'Operant Conditioning', back: 'B.F. Skinner\'s learning theory in which behavior is shaped by its consequences: reinforcement (increases behavior) and punishment (decreases behavior).', sort_order: 4 , front_translations: {"es":"Condicionamento Operante","de":"Operante Konditionierung","fr":"Conditionnement opérant","tr":"Edimsel Koşullanma","nl":"Operante conditionering","ru":"Оперантное обусловливание","zh":"操作性条件反射","pt_BR":"Condicionamento Operante","pt_PT":"Condicionamento Operante"}, back_translations: {"es":"La teoría de aprendizaje de B.F. Skinner en la qual el comportamiento es moldado por las sus consecuencias: refuerzo (aumenta el comportamiento) y castigo (disminuye el comportamiento).","de":"B.F. Skinners Lerntheorie, nach der Verhalten durch seine Konsequenzen geformt wird: Verstärkung (erhöht Verhalten) und Bestrafung (verringert Verhalten).","fr":"La théorie de l'apprentissage de B.F. Skinner selon laquelle le comportement est façonné par ses conséquences : le renforcement (augmente le comportement) et la punition (diminue le comportement).","tr":"B.F. Skinner'ın, davranışın sonuçlarıyla şekillendirildiğini öne süren öğrenme teorisi: pekiştirme (davranışı artırır) ve ceza (davranışı azaltır).","nl":"B.F. Skinners leertheorie waarin gedrag wordt gevormd door de gevolgen ervan: bekrachtiging (verhoogt gedrag) en straf (vermindert gedrag).","ru":"Теория научения Б.Ф. Скиннера, согласно которой поведение формируется его последствиями: подкрепление (увеличивает поведение) и наказание (уменьшает поведение).","zh":"B.F.斯金纳的学习理论，认为行为由其后果塑造：强化（增加行为）和惩罚（减少行为）。","pt_BR":"A teoria de aprendizagem de B.F. Skinner na qual o comportamento é moldado pelas suas consequências: reforço (aumenta o comportamento) e punição (diminui o comportamento).","pt_PT":"A teoria de aprendizagem de B.F. Skinner na qual o comportamento é moldado pelas suas consequências: reforço (aumenta o comportamento) e punição (diminui o comportamento)."}},
  { id: 'dc-psychology-0005', deck_id: 'deck-psychology', front: 'Positive Reinforcement', back: 'Adding a pleasant stimulus following a behavior to increase the likelihood of that behavior recurring. Example: giving praise after a student answers correctly.', sort_order: 5 , front_translations: {"es":"Reforço Positivo","de":"Positive Verstärkung","fr":"Renforcement positif","tr":"Pozitif Pekiştirme","nl":"Positieve bekrachtiging","ru":"Положительное подкрепление","zh":"正强化","pt_BR":"Reforço Positivo","pt_PT":"Reforço Positivo"}, back_translations: {"es":"Adicionar un estímulo agradable após un comportamiento para aumentar a probabilidad de esse comportamiento se repetir. Exemplo: elogiar un aluno após responder corretamente.","de":"Das Hinzufügen eines angenehmen Reizes nach einem Verhalten, um die Wahrscheinlichkeit zu erhöhen, dass dieses Verhalten erneut auftritt. Beispiel: Lob nach einer richtigen Antwort eines Schülers.","fr":"L'ajout d'un stimulus agréable après un comportement pour augmenter la probabilité que ce comportement se reproduise. Exemple : féliciter un élève après une bonne réponse.","tr":"Bir davranışın ardından hoş bir uyaran eklenerek o davranışın tekrarlanma olasılığının artırılması. Örnek: Bir öğrenci doğru cevap verdikten sonra övgüde bulunma.","nl":"Het toevoegen van een aangename stimulus na een gedrag om de kans te vergroten dat dat gedrag opnieuw voorkomt. Voorbeeld: een leerling prijzen na een correct antwoord.","ru":"Добавление приятного стимула после поведения для увеличения вероятности его повторения. Пример: похвала ученика после правильного ответа.","zh":"在某行为之后添加一个愉悦的刺激，以增加该行为再次发生的可能性。例如：学生回答正确后给予表扬。","pt_BR":"Adicionar um estímulo agradável após um comportamento para aumentar a probabilidade de esse comportamento se repetir. Exemplo: elogiar um aluno após responder corretamente.","pt_PT":"Adicionar um estímulo agradável após um comportamento para aumentar a probabilidade de esse comportamento se repetir. Exemplo: elogiar um aluno após responder corretamente."}},
  { id: 'dc-psychology-0006', deck_id: 'deck-psychology', front: 'Negative Reinforcement', back: 'Removing an unpleasant stimulus following a behavior to increase that behavior. Example: taking painkillers removes pain, reinforcing the pill-taking behavior.', sort_order: 6 , front_translations: {"es":"Reforço Negativo","de":"Negative Verstärkung","fr":"Renforcement négatif","tr":"Negatif Pekiştirme","nl":"Negatieve bekrachtiging","ru":"Отрицательное подкрепление","zh":"负强化","pt_BR":"Reforço Negativo","pt_PT":"Reforço Negativo"}, back_translations: {"es":"Remover un estímulo desagradable após un comportamiento para aumentar esse comportamiento. Exemplo: tomar analgésicos elimina a dor, reforçando el comportamiento de tomar comprimidos.","de":"Das Entfernen eines unangenehmen Reizes nach einem Verhalten, um dieses Verhalten zu verstärken. Beispiel: Schmerzmittel beseitigen den Schmerz und verstärken so das Einnahmeverhalten.","fr":"Le retrait d'un stimulus désagréable après un comportement pour augmenter ce comportement. Exemple : prendre un analgésique supprime la douleur, renforçant ainsi le comportement de prise de médicaments.","tr":"Bir davranışın ardından hoş olmayan bir uyaranın kaldırılmasıyla o davranışın artırılması. Örnek: Ağrı kesici almak ağrıyı giderir ve ilaç alma davranışını pekiştirir.","nl":"Het wegnemen van een onaangename stimulus na een gedrag om dat gedrag te versterken. Voorbeeld: pijnstillers nemen verwijdert de pijn en versterkt zo het pilinnamegedrag.","ru":"Устранение неприятного стимула после поведения для его усиления. Пример: приём обезболивающего устраняет боль, подкрепляя поведение приёма таблеток.","zh":"在某行为之后移除一个不愉快的刺激以增加该行为的发生。例如：服用止痛药消除疼痛，从而强化了服药行为。","pt_BR":"Remover um estímulo desagradável após um comportamento para aumentar esse comportamento. Exemplo: tomar analgésicos remove a dor, reforçando o comportamento de tomar comprimidos.","pt_PT":"Remover um estímulo desagradável após um comportamento para aumentar esse comportamento. Exemplo: tomar analgésicos remove a dor, reforçando o comportamento de tomar comprimidos."}},
  { id: 'dc-psychology-0007', deck_id: 'deck-psychology', front: 'Punishment (Operant Conditioning)', back: 'A consequence that decreases the likelihood of a behavior: positive punishment adds an unpleasant stimulus; negative punishment removes a pleasant stimulus.', sort_order: 7 , front_translations: {"es":"Punición (Condicionamento Operante)","de":"Bestrafung (Operante Konditionierung)","fr":"Punition (Conditionnement opérant)","tr":"Ceza (Edimsel Koşullanma)","nl":"Straf (Operante conditionering)","ru":"Наказание (оперантное обусловливание)","zh":"惩罚（操作性条件反射）","pt_BR":"Punição (Condicionamento Operante)","pt_PT":"Punição (Condicionamento Operante)"}, back_translations: {"es":"Una consecuencia que disminuye a probabilidad de un comportamiento: a castigo positiva adiciona un estímulo desagradable; a castigo negativa elimina un estímulo agradable.","de":"Eine Konsequenz, die die Wahrscheinlichkeit eines Verhaltens verringert: Positive Bestrafung fügt einen unangenehmen Reiz hinzu; negative Bestrafung entzieht einen angenehmen Reiz.","fr":"Une conséquence qui diminue la probabilité d'un comportement : la punition positive ajoute un stimulus désagréable ; la punition négative retire un stimulus agréable.","tr":"Bir davranışın olasılığını azaltan bir sonuç: Pozitif ceza hoş olmayan bir uyaran ekler; negatif ceza hoş bir uyaranı kaldırır.","nl":"Een gevolg dat de waarschijnlijkheid van een gedrag vermindert: positieve straf voegt een onaangename stimulus toe; negatieve straf verwijdert een aangename stimulus.","ru":"Последствие, снижающее вероятность поведения: положительное наказание добавляет неприятный стимул; отрицательное наказание убирает приятный стимул.","zh":"降低某行为发生可能性的后果：正惩罚添加不愉快刺激；负惩罚移除愉快刺激。","pt_BR":"Uma consequência que diminui a probabilidade de um comportamento: a punição positiva adiciona um estímulo desagradável; a punição negativa remove um estímulo agradável.","pt_PT":"Uma consequência que diminui a probabilidade de um comportamento: a punição positiva adiciona um estímulo desagradável; a punição negativa remove um estímulo agradável."}},
  { id: 'dc-psychology-0008', deck_id: 'deck-psychology', front: 'Observational Learning (Modeling)', back: 'Learning by watching and imitating others; Albert Bandura\'s Bobo doll experiments showed children imitate aggressive behavior observed in adults.', sort_order: 8 , front_translations: {"es":"Aprendizaje Observacional (Modelaje)","de":"Beobachtungslernen (Modelllernen)","fr":"Apprentissage par observation (Modelage)","tr":"Gözlemsel Öğrenme (Model Alma)","nl":"Observationeel leren (Modellering)","ru":"Обучение через наблюдение (моделирование)","zh":"观察学习（模仿）","pt_BR":"Aprendizagem Observacional (Modelagem)","pt_PT":"Aprendizagem Observacional (Modelagem)"}, back_translations: {"es":"Aprender observando y imitando los outros; los experimentos de la boneca Bobo de Albert Bandura mostraram que niños imitam comportamientos agressivos observados en adultos.","de":"Lernen durch Beobachten und Nachahmen anderer; Albert Banduras Bobo-Puppen-Experimente zeigten, dass Kinder aggressives Verhalten nachahmen, das sie bei Erwachsenen beobachtet haben.","fr":"Apprendre en observant et en imitant les autres ; les expériences de la poupée Bobo d'Albert Bandura ont montré que les enfants imitent les comportements agressifs observés chez les adultes.","tr":"Başkalarını izleyerek ve taklit ederek öğrenme; Albert Bandura'nın Bobo bebek deneyleri, çocukların yetişkinlerde gözlemlenen saldırgan davranışı taklit ettiğini göstermiştir.","nl":"Leren door anderen te observeren en na te bootsen; Albert Bandura's Bobo-popexperimenten toonden aan dat kinderen agressief gedrag nabootsen dat ze bij volwassenen hebben gezien.","ru":"Научение путём наблюдения и подражания другим; эксперименты Альберта Бандуры с куклой Бобо показали, что дети подражают агрессивному поведению, наблюдаемому у взрослых.","zh":"通过观察和模仿他人来学习；阿尔伯特·班杜拉的波波玩偶实验表明，儿童会模仿在成人身上观察到的攻击性行为。","pt_BR":"Aprender observando e imitando os outros; os experimentos da boneca Bobo de Albert Bandura mostraram que crianças imitam comportamentos agressivos observados em adultos.","pt_PT":"Aprender observando e imitando os outros; as experiências do boneco Bobo de Albert Bandura mostraram que as crianças imitam comportamentos agressivos observados em adultos."}},
  { id: 'dc-psychology-0009', deck_id: 'deck-psychology', front: 'Schema', back: 'A mental framework or structure that organizes and interprets incoming information based on prior knowledge and experience; new information is assimilated or accommodated into schemas.', sort_order: 9 , front_translations: {"es":"Esquema","de":"Schema","fr":"Schéma","tr":"Şema","nl":"Schema","ru":"Схема","zh":"图式","pt_BR":"Esquema","pt_PT":"Esquema"}, back_translations: {"es":"Una estructura o quadro mental que organiza y interpreta informaciones recebidas con base en el conocimiento y experiencia prévios; nuevas informaciones son assimiladas o acomodadas en los esquemas.","de":"Ein mentales Rahmenwerk oder eine Struktur, die eingehende Informationen auf der Grundlage von Vorwissen und Erfahrung organisiert und interpretiert; neue Informationen werden in Schemata assimiliert oder akkommodiert.","fr":"Un cadre ou une structure mentale qui organise et interprète les informations entrantes sur la base des connaissances et de l'expérience antérieures ; les nouvelles informations sont assimilées ou accommodées dans les schémas.","tr":"Önceki bilgi ve deneyime dayalı olarak gelen bilgiyi düzenleyen ve yorumlayan zihinsel bir çerçeve veya yapı; yeni bilgi şemalara özümsenir veya uyumlanır.","nl":"Een mentaal kader of structuur dat binnenkomende informatie organiseert en interpreteert op basis van eerdere kennis en ervaring; nieuwe informatie wordt geassimileerd of geaccommodeerd in schema's.","ru":"Мысленная структура или рамка, которая организует и интерпретирует поступающую информацию на основе предшествующих знаний и опыта; новая информация ассимилируется или аккомодируется в схемы.","zh":"一种心理框架或结构，基于先前的知识和经验来组织和解释传入的信息；新信息被同化或顺应到图式中。","pt_BR":"Uma estrutura ou quadro mental que organiza e interpreta informações recebidas com base no conhecimento e experiência prévios; novas informações são assimiladas ou acomodadas nos esquemas.","pt_PT":"Uma estrutura ou quadro mental que organiza e interpreta informações recebidas com base no conhecimento e experiência prévios; novas informações são assimiladas ou acomodadas nos esquemas."}},
  { id: 'dc-psychology-0010', deck_id: 'deck-psychology', front: 'Cognitive Schema (Piaget)', back: 'Piaget used schemas to describe how children organize knowledge. Assimilation fits new information into existing schemas; accommodation changes the schema to fit new information.', sort_order: 10 , front_translations: {"es":"Esquema Cognitivo (Piaget)","de":"Kognitives Schema (Piaget)","fr":"Schéma cognitif (Piaget)","tr":"Bilişsel Şema (Piaget)","nl":"Cognitief schema (Piaget)","ru":"Когнитивная схема (Пиаже)","zh":"认知图式（皮亚杰）","pt_BR":"Esquema Cognitivo (Piaget)","pt_PT":"Esquema Cognitivo (Piaget)"}, back_translations: {"es":"Piaget usou esquemas para descrever como las niños organizam el conocimiento. La assimilación encaixa nuevas informaciones en los esquemas existentes; a acomodación altera el esquema para se ajustar a las nuevas informaciones.","de":"Piaget verwendete Schemata, um zu beschreiben, wie Kinder Wissen organisieren. Assimilation passt neue Informationen in bestehende Schemata ein; Akkommodation verändert das Schema, um neue Informationen aufzunehmen.","fr":"Piaget a utilisé les schémas pour décrire comment les enfants organisent les connaissances. L'assimilation intègre les nouvelles informations dans les schémas existants ; l'accommodation modifie le schéma pour intégrer les nouvelles informations.","tr":"Piaget, çocukların bilgiyi nasıl düzenlediklerini tanımlamak için şemaları kullandı. Özümseme yeni bilgiyi mevcut şemalara yerleştirir; uyumlama şemayı yeni bilgiye göre değiştirir.","nl":"Piaget gebruikte schema's om te beschrijven hoe kinderen kennis organiseren. Assimilatie past nieuwe informatie in bestaande schema's; accommodatie wijzigt het schema om nieuwe informatie te passen.","ru":"Пиаже использовал схемы для описания того, как дети организуют знания. Ассимиляция встраивает новую информацию в существующие схемы; аккомодация изменяет схему, чтобы вместить новую информацию.","zh":"皮亚杰用图式来描述儿童如何组织知识。同化将新信息纳入已有图式；顺应则改变图式以适应新信息。","pt_BR":"Piaget usou esquemas para descrever como as crianças organizam o conhecimento. A assimilação encaixa novas informações nos esquemas existentes; a acomodação altera o esquema para se ajustar às novas informações.","pt_PT":"Piaget usou esquemas para descrever como as crianças organizam o conhecimento. A assimilação encaixa novas informações nos esquemas existentes; a acomodação altera o esquema para se ajustar às novas informações."}},
  { id: 'dc-psychology-0011', deck_id: 'deck-psychology', front: 'Heuristic', back: 'A mental shortcut or rule of thumb used to make judgments quickly with less cognitive effort; efficient but can lead to systematic errors (cognitive biases).', sort_order: 11 , front_translations: {"es":"Heurística","de":"Heuristik","fr":"Heuristique","tr":"Sezgisel Kestirme (Heuristik)","nl":"Heuristiek","ru":"Эвристика","zh":"启发法","pt_BR":"Heurística","pt_PT":"Heurística"}, back_translations: {"es":"Un atalho mental o regra prática usado para fazer julgamentos rápidamente con menos esforço cognitivo; eficiente, pero puede levar a erros sistemáticos (vieses cognitivos).","de":"Eine mentale Abkürzung oder Faustregel, die verwendet wird, um schnell und mit weniger kognitivem Aufwand Urteile zu fällen; effizient, kann aber zu systematischen Fehlern (kognitiven Verzerrungen) führen.","fr":"Un raccourci mental ou une règle empirique utilisé pour porter des jugements rapidement avec moins d'effort cognitif ; efficace mais pouvant mener à des erreurs systématiques (biais cognitifs).","tr":"Daha az bilişsel çabayla hızlı yargılarda bulunmak için kullanılan zihinsel kestirme yolu veya pratik kural; verimlidir ancak sistematik hatalara (bilişsel yanlılıklara) yol açabilir.","nl":"Een mentale snelkoppeling of vuistregel die wordt gebruikt om snel met minder cognitieve inspanning oordelen te vormen; efficiënt maar kan leiden tot systematische fouten (cognitieve biases).","ru":"Мысленный ярлык или эмпирическое правило, используемое для быстрого вынесения суждений с меньшими когнитивными усилиями; эффективно, но может приводить к систематическим ошибкам (когнитивным искажениям).","zh":"一种用于以较少认知努力快速做出判断的心理捷径或经验法则；虽高效但可能导致系统性错误（认知偏差）。","pt_BR":"Um atalho mental ou regra prática usado para fazer julgamentos rapidamente com menos esforço cognitivo; eficiente, mas pode levar a erros sistemáticos (vieses cognitivos).","pt_PT":"Um atalho mental ou regra prática usado para fazer julgamentos rapidamente com menos esforço cognitivo; eficiente, mas pode levar a erros sistemáticos (vieses cognitivos)."}},
  { id: 'dc-psychology-0012', deck_id: 'deck-psychology', front: 'Availability Heuristic', back: 'The tendency to judge the likelihood of events based on how easily examples come to mind; overestimates the frequency of vivid, memorable, or recent events.', sort_order: 12 , front_translations: {"es":"Heurística de la Disponibilidad","de":"Verfügbarkeitsheuristik","fr":"Heuristique de disponibilité","tr":"Bulunabilirlik Heuristiği","nl":"Beschikbaarheidsheuristiek","ru":"Эвристика доступности","zh":"可得性启发法","pt_BR":"Heurística da Disponibilidade","pt_PT":"Heurística da Disponibilidade"}, back_translations: {"es":"La tendencia de julgar a probabilidad de eventos con base en la facilidad con que ejemplos vem a la mente; superestima a frecuencia de eventos vívidos, memorables o recentes.","de":"Die Tendenz, die Wahrscheinlichkeit von Ereignissen danach zu beurteilen, wie leicht Beispiele in den Sinn kommen; überschätzt die Häufigkeit von lebhaften, einprägsamen oder jüngsten Ereignissen.","fr":"La tendance à juger la probabilité d'événements en fonction de la facilité avec laquelle des exemples viennent à l'esprit ; surestime la fréquence des événements frappants, mémorables ou récents.","tr":"Olayların olasılığını, örneklerin zihne ne kadar kolay geldiğine göre değerlendirme eğilimi; canlı, akılda kalıcı veya yakın zamanlı olayların sıklığını abartır.","nl":"De neiging om de waarschijnlijkheid van gebeurtenissen te beoordelen op basis van hoe gemakkelijk voorbeelden in gedachten komen; overschat de frequentie van levendige, memorabele of recente gebeurtenissen.","ru":"Склонность оценивать вероятность событий на основании того, насколько легко примеры приходят на ум; переоценивает частоту ярких, запоминающихся или недавних событий.","zh":"根据想到例子的容易程度来判断事件发生可能性的倾向；会高估生动、令人印象深刻或近期事件的发生频率。","pt_BR":"A tendência de julgar a probabilidade de eventos com base na facilidade com que exemplos vêm à mente; superestima a frequência de eventos vívidos, memoráveis ou recentes.","pt_PT":"A tendência de julgar a probabilidade de eventos com base na facilidade com que exemplos vêm à mente; sobrestima a frequência de eventos vívidos, memoráveis ou recentes."}},
  { id: 'dc-psychology-0013', deck_id: 'deck-psychology', front: 'Representativeness Heuristic', back: 'Judging the probability that something belongs to a category based on how closely it resembles a typical member, often ignoring base rate information.', sort_order: 13 , front_translations: {"es":"Heurística de la Representatividad","de":"Repräsentativitätsheuristik","fr":"Heuristique de représentativité","tr":"Temsiliyet Heuristiği","nl":"Representativiteitsheuristiek","ru":"Эвристика репрезентативности","zh":"代表性启发法","pt_BR":"Heurística da Representatividade","pt_PT":"Heurística da Representatividade"}, back_translations: {"es":"Julgar a probabilidad de algo pertencer a una categoria con base en quão semelhante es a un membro típico, frecuentemente ignorando informaciones de taxa base.","de":"Die Beurteilung der Wahrscheinlichkeit, dass etwas einer Kategorie angehört, basierend darauf, wie sehr es einem typischen Mitglied ähnelt, wobei Basisrateninformationen oft ignoriert werden.","fr":"Juger la probabilité qu'un élément appartienne à une catégorie en se basant sur sa ressemblance avec un membre typique, en ignorant souvent les informations de base.","tr":"Bir şeyin bir kategoriye ait olma olasılığını, tipik bir üyeye ne kadar benzediğine göre değerlendirmek; çoğunlukla temel oran bilgisini göz ardı eder.","nl":"De waarschijnlijkheid beoordelen dat iets tot een categorie behoort op basis van hoe sterk het lijkt op een typisch lid, waarbij basisfrequentie-informatie vaak wordt genegeerd.","ru":"Оценка вероятности принадлежности объекта к категории на основании его сходства с типичным представителем, часто с игнорированием базовой частоты.","zh":"根据某事物与典型成员的相似程度来判断其属于某类别的概率，往往忽略基础概率信息。","pt_BR":"Julgar a probabilidade de algo pertencer a uma categoria com base em quão semelhante é a um membro típico, frequentemente ignorando informações de taxa base.","pt_PT":"Julgar a probabilidade de algo pertencer a uma categoria com base em quão semelhante é a um membro típico, frequentemente ignorando informações de taxa base."}},
  { id: 'dc-psychology-0014', deck_id: 'deck-psychology', front: 'Anchoring Bias', back: 'The tendency to rely too heavily on the first piece of information encountered (the "anchor") when making subsequent judgments or estimates.', sort_order: 14 , front_translations: {"es":"Viés de Ancoraje","de":"Ankerheuristik","fr":"Biais d'ancrage","tr":"Çıpalama Yanlılığı","nl":"Verankeringsbias","ru":"Эффект якоря","zh":"锚定偏误","pt_BR":"Viés de Ancoragem","pt_PT":"Viés de Ancoragem"}, back_translations: {"es":"La tendencia de confiar excessivamente en la primera información encontrada (a «ancora») al fazer julgamentos o estimativas subsequentes.","de":"Die Tendenz, sich bei nachfolgenden Urteilen oder Schätzungen zu stark auf die erste erhaltene Information (den «Anker») zu verlassen.","fr":"La tendance à s'appuyer trop fortement sur la première information rencontrée (l'«ancre») lors de jugements ou estimations ultérieurs.","tr":"Sonraki yargılarda veya tahminlerde karşılaşılan ilk bilgiye («çıpa») aşırı derecede güvenme eğilimi.","nl":"De neiging om te zwaar te leunen op het eerste stuk informatie dat men tegenkomt (het «anker») bij het maken van daaropvolgende oordelen of schattingen.","ru":"Склонность чрезмерно полагаться на первую полученную информацию («якорь») при вынесении последующих суждений или оценок.","zh":"在做后续判断或估计时，过度依赖最先接触到的信息（«锚»）的倾向。","pt_BR":"A tendência de confiar excessivamente na primeira informação encontrada (a «âncora») ao fazer julgamentos ou estimativas subsequentes.","pt_PT":"A tendência de confiar excessivamente na primeira informação encontrada (a «âncora») ao fazer julgamentos ou estimativas subsequentes."}},
  { id: 'dc-psychology-0015', deck_id: 'deck-psychology', front: 'Hindsight Bias', back: 'The tendency to perceive past events as having been predictable after they have occurred; the "I knew it all along" phenomenon that distorts memory of prior uncertainty.', sort_order: 15 , front_translations: {"es":"Viés Retrospectivo","de":"Rückschaufehler","fr":"Biais rétrospectif","tr":"Geçmişe Bakış Yanlılığı","nl":"Wijsheid achteraf-bias","ru":"Ошибка хиндсайта","zh":"后见之明偏误","pt_BR":"Viés Retrospectivo","pt_PT":"Viés Retrospetivo"}, back_translations: {"es":"La tendencia de perceber eventos passados como teniendo sido previsibles após terem ocorrido; el fenómeno del «eu ya sabia» que distorce a memoria de la incerteza anterior.","de":"Die Tendenz, vergangene Ereignisse als vorhersehbar wahrzunehmen, nachdem sie eingetreten sind; das «Ich hab es doch gewusst»-Phänomen, das die Erinnerung an frühere Unsicherheit verzerrt.","fr":"La tendance à percevoir les événements passés comme ayant été prévisibles après leur survenue ; le phénomène du «je le savais depuis le début» qui déforme le souvenir de l'incertitude antérieure.","tr":"Geçmiş olayları gerçekleştikten sonra tahmin edilebilir olarak algılama eğilimi; önceki belirsizliğin anısını çarpıtan «ben zaten biliyordum» olgusu.","nl":"De neiging om gebeurtenissen uit het verleden als voorspelbaar te beschouwen nadat ze hebben plaatsgevonden; het «ik wist het wel»-fenomeen dat de herinnering aan eerdere onzekerheid vertekent.","ru":"Склонность воспринимать прошлые события как предсказуемые после того, как они произошли; феномен «я так и знал», искажающий воспоминания о прежней неопределённости.","zh":"在事件发生后倾向于认为过去的事件是可预见的；即«我早就知道了»现象，会扭曲对先前不确定性的记忆。","pt_BR":"A tendência de perceber eventos passados como tendo sido previsíveis após terem ocorrido; o fenômeno do «eu já sabia» que distorce a memória da incerteza anterior.","pt_PT":"A tendência de perceber eventos passados como tendo sido previsíveis após terem ocorrido; o fenómeno do «eu já sabia» que distorce a memória da incerteza anterior."}},
  { id: 'dc-psychology-0016', deck_id: 'deck-psychology', front: 'Fundamental Attribution Error (FAE)', back: 'The tendency to overestimate dispositional (personality) factors and underestimate situational factors when explaining other people\'s behavior.', sort_order: 16 , front_translations: {"es":"Erro Fundamental de Atribuición (EFA)","de":"Fundamentaler Attributionsfehler (FAE)","fr":"Erreur fondamentale d'attribution (EFA)","tr":"Temel Atıf Hatası (TAH)","nl":"Fundamentele attributiefout (FAE)","ru":"Фундаментальная ошибка атрибуции (ФОА)","zh":"基本归因错误（FAE）","pt_BR":"Erro Fundamental de Atribuição (EFA)","pt_PT":"Erro Fundamental de Atribuição (EFA)"}, back_translations: {"es":"La tendencia de superestimar fatores disposicionais (de personalidad) y subestimar fatores situacionais al explicar el comportamiento de outras personas.","de":"Die Tendenz, dispositionelle (Persönlichkeits-)Faktoren zu überschätzen und situative Faktoren zu unterschätzen, wenn man das Verhalten anderer Menschen erklärt.","fr":"La tendance à surestimer les facteurs dispositionnels (de personnalité) et à sous-estimer les facteurs situationnels lorsqu'on explique le comportement d'autrui.","tr":"Başkalarının davranışlarını açıklarken içsel (kişilik) faktörleri abartma ve durumsal faktörleri küçümseme eğilimi.","nl":"De neiging om dispositionele (persoonlijkheids-)factoren te overschatten en situationele factoren te onderschatten bij het verklaren van het gedrag van anderen.","ru":"Склонность переоценивать диспозиционные (личностные) факторы и недооценивать ситуационные при объяснении поведения других людей.","zh":"在解释他人行为时，倾向于高估性格（人格）因素而低估情境因素。","pt_BR":"A tendência de superestimar fatores disposicionais (de personalidade) e subestimar fatores situacionais ao explicar o comportamento de outras pessoas.","pt_PT":"A tendência de sobrestimar fatores disposicionais (de personalidade) e subestimar fatores situacionais ao explicar o comportamento de outras pessoas."}},
  { id: 'dc-psychology-0017', deck_id: 'deck-psychology', front: 'Actor-Observer Bias', back: 'The tendency to attribute one\'s own actions to situational factors but attribute others\' actions to their character; an extension of the fundamental attribution error.', sort_order: 17 , front_translations: {"es":"Viés Ator-Observador","de":"Akteur-Beobachter-Verzerrung","fr":"Biais acteur-observateur","tr":"Aktör-Gözlemci Yanlılığı","nl":"Actor-observatorbias","ru":"Искажение «актёр — наблюдатель»","zh":"行动者-观察者偏差","pt_BR":"Viés Ator-Observador","pt_PT":"Viés Ator-Observador"}, back_translations: {"es":"La tendencia de atribuir las propias acciones a fatores situacionais, pero atribuir las acciones de los outros al caráter deles; una extensão del erro fundamental de atribuición.","de":"Die Tendenz, das eigene Handeln auf situative Faktoren zurückzuführen, das Handeln anderer jedoch auf deren Charakter; eine Erweiterung des fundamentalen Attributionsfehlers.","fr":"La tendance à attribuer ses propres actions à des facteurs situationnels tout en attribuant les actions des autres à leur caractère ; une extension de l'erreur fondamentale d'attribution.","tr":"Kişinin kendi eylemlerini durumsal faktörlere, başkalarının eylemlerini ise onların karakterine atfetme eğilimi; temel atıf hatasının bir uzantısıdır.","nl":"De neiging om het eigen handelen toe te schrijven aan situationele factoren maar het handelen van anderen aan hun karakter; een uitbreiding van de fundamentele attributiefout.","ru":"Склонность приписывать собственные действия ситуационным факторам, а действия других — их характеру; расширение фундаментальной ошибки атрибуции.","zh":"倾向于将自己的行为归因于情境因素，却将他人的行为归因于其性格特征；是基本归因错误的延伸。","pt_BR":"A tendência de atribuir as próprias ações a fatores situacionais, mas atribuir as ações dos outros ao caráter deles; uma extensão do erro fundamental de atribuição.","pt_PT":"A tendência de atribuir as próprias ações a fatores situacionais, mas atribuir as ações dos outros ao caráter deles; uma extensão do erro fundamental de atribuição."}},
  { id: 'dc-psychology-0018', deck_id: 'deck-psychology', front: 'Self-Serving Bias', back: 'The tendency to attribute successes to one\'s own abilities and failures to external factors; it protects self-esteem and is more pronounced in individualistic cultures.', sort_order: 18 , front_translations: {"es":"Viés Autosservidor","de":"Selbstwertdienliche Verzerrung","fr":"Biais d'autocomplaisance","tr":"Benliğe Hizmet Eden Yanlılık","nl":"Zelfbedienende bias","ru":"Эгоцентрическое искажение","zh":"自利性偏差","pt_BR":"Viés Autosservidor","pt_PT":"Viés Autosservidor"}, back_translations: {"es":"La tendencia de atribuir sucessos a las propias habilidades y fracassos a fatores externos; protege a autoestima y es más pronunciado en culturas individualistas.","de":"Die Tendenz, Erfolge den eigenen Fähigkeiten und Misserfolge äußeren Faktoren zuzuschreiben; es schützt das Selbstwertgefühl und ist in individualistischen Kulturen stärker ausgeprägt.","fr":"La tendance à attribuer ses réussites à ses propres capacités et ses échecs à des facteurs externes ; il protège l'estime de soi et est plus prononcé dans les cultures individualistes.","tr":"Başarıları kendi yeteneklerine, başarısızlıkları ise dış faktörlere atfetme eğilimi; özsaygıyı korur ve bireyci kültürlerde daha belirgindir.","nl":"De neiging om successen toe te schrijven aan eigen vaardigheden en mislukkingen aan externe factoren; het beschermt het zelfbeeld en is sterker aanwezig in individualistische culturen.","ru":"Склонность приписывать успехи собственным способностям, а неудачи — внешним факторам; защищает самооценку и более выражена в индивидуалистических культурах.","zh":"倾向于将成功归因于自身能力，将失败归因于外部因素；这种偏差保护自尊，在个人主义文化中更为显著。","pt_BR":"A tendência de atribuir sucessos às próprias habilidades e fracassos a fatores externos; protege a autoestima e é mais pronunciado em culturas individualistas.","pt_PT":"A tendência de atribuir sucessos às próprias capacidades e fracassos a fatores externos; protege a autoestima e é mais pronunciado em culturas individualistas."}},
  { id: 'dc-psychology-0019', deck_id: 'deck-psychology', front: 'Conformity (Asch)', back: 'The tendency to change one\'s behavior or beliefs to match those of a group. Solomon Asch\'s line experiments showed people conform to obviously wrong group answers about 37% of the time.', sort_order: 19 , front_translations: {"es":"Conformidad (Asch)","de":"Konformität (Asch)","fr":"Conformité (Asch)","tr":"Uyma Davranışı (Asch)","nl":"Conformiteit (Asch)","ru":"Конформизм (Аш)","zh":"从众（阿希）","pt_BR":"Conformidade (Asch)","pt_PT":"Conformidade (Asch)"}, back_translations: {"es":"La tendencia de mudar el comportamiento o las creencias para se adequar a los de un grupo. Los experimentos de líneas de Solomon Asch mostraram que las personas se conformam a respuestas de grupo obviamente erradas cerca de 37% de las veces.","de":"Die Tendenz, das eigene Verhalten oder die eigenen Überzeugungen an die einer Gruppe anzupassen. Solomon Aschs Linienexperimente zeigten, dass Menschen in etwa 37 % der Fälle offensichtlich falschen Gruppenantworten zustimmen.","fr":"La tendance à modifier son comportement ou ses croyances pour correspondre à ceux d'un groupe. Les expériences des lignes de Solomon Asch ont montré que les gens se conforment à des réponses de groupe manifestement erronées environ 37 % du temps.","tr":"Davranışını veya inançlarını bir grubunkilerle eşleştirmek için değiştirme eğilimi. Solomon Asch'ın çizgi deneyleri, insanların yaklaşık %37 oranında açıkça yanlış grup yanıtlarına uyduğunu göstermiştir.","nl":"De neiging om het eigen gedrag of overtuigingen aan te passen aan die van een groep. Solomon Aschs lijnexperimenten toonden aan dat mensen zich in ongeveer 37% van de gevallen conformeren aan duidelijk foutieve groepsantwoorden.","ru":"Склонность менять своё поведение или убеждения в соответствии с групповыми. Эксперименты Соломона Аша с линиями показали, что люди соглашаются с очевидно неправильными ответами группы примерно в 37% случаев.","zh":"改变自己的行为或信念以与群体保持一致的倾向。所罗门·阿希的线段实验表明，人们约37%的时间会顺从明显错误的群体答案。","pt_BR":"A tendência de mudar o comportamento ou as crenças para se adequar aos de um grupo. Os experimentos de linhas de Solomon Asch mostraram que as pessoas se conformam a respostas de grupo obviamente erradas cerca de 37% das vezes.","pt_PT":"A tendência de mudar o comportamento ou as crenças para se adequar aos de um grupo. As experiências de linhas de Solomon Asch mostraram que as pessoas se conformam a respostas de grupo obviamente erradas cerca de 37% das vezes."}},
  { id: 'dc-psychology-0020', deck_id: 'deck-psychology', front: 'Obedience (Milgram)', back: 'Stanley Milgram\'s experiments showed ~65% of participants would administer what they believed were dangerous electric shocks to others when ordered to by an authority figure.', sort_order: 20 , front_translations: {"es":"Obediencia (Milgram)","de":"Gehorsam (Milgram)","fr":"Obéissance (Milgram)","tr":"İtaat (Milgram)","nl":"Gehoorzaamheid (Milgram)","ru":"Подчинение (Милгрэм)","zh":"服从（米尔格拉姆）","pt_BR":"Obediência (Milgram)","pt_PT":"Obediência (Milgram)"}, back_translations: {"es":"Los experimentos de Stanley Milgram mostraram que ~65% de los participantes administravam el que acreditavam ser choques elétricos perigosos en outras personas cuando ordenados por una figura de autoridad.","de":"Stanley Milgrams Experimente zeigten, dass ca. 65 % der Teilnehmer bereit waren, vermeintlich gefährliche Elektroschocks zu verabreichen, wenn sie von einer Autoritätsperson dazu aufgefordert wurden.","fr":"Les expériences de Stanley Milgram ont montré qu'environ 65 % des participants administraient ce qu'ils croyaient être des chocs électriques dangereux à d'autres personnes lorsqu'un personnage d'autorité le leur ordonnait.","tr":"Stanley Milgram'ın deneyleri, katılımcıların yaklaşık %65'inin bir otorite figürünün emriyle başkalarına tehlikeli olduğuna inandıkları elektrik şokları uygulayacağını göstermiştir.","nl":"De experimenten van Stanley Milgram toonden aan dat ~65% van de deelnemers bereid was om wat zij geloofden gevaarlijke elektrische schokken te zijn aan anderen toe te dienen wanneer een autoriteitsfiguur dit beval.","ru":"Эксперименты Стэнли Милгрэма показали, что ~65% участников были готовы наносить, как они полагали, опасные удары электрическим током другим людям по приказу авторитетной фигуры.","zh":"斯坦利·米尔格拉姆的实验表明，约65%的参与者在权威人物的命令下，会对他人施加他们认为具有危险性的电击。","pt_BR":"Os experimentos de Stanley Milgram mostraram que ~65% dos participantes administravam o que acreditavam ser choques elétricos perigosos em outras pessoas quando ordenados por uma figura de autoridade.","pt_PT":"As experiências de Stanley Milgram mostraram que ~65% dos participantes administravam o que acreditavam ser choques elétricos perigosos a outras pessoas quando ordenados por uma figura de autoridade."}},
  { id: 'dc-psychology-0021', deck_id: 'deck-psychology', front: 'Groupthink', back: 'A phenomenon where the desire for group harmony and conformity overrides critical thinking; groups make poor decisions because members suppress dissent to maintain consensus.', sort_order: 21 , front_translations: {"es":"Pensamento de Grupo","de":"Gruppendenken","fr":"Pensée de groupe","tr":"Grup Düşüncesi","nl":"Groepsdenken","ru":"Групповое мышление","zh":"群体思维","pt_BR":"Pensamento de Grupo","pt_PT":"Pensamento de Grupo"}, back_translations: {"es":"Un fenómeno en que el desejo de harmonia y conformidad del grupo sobrepõe-se al pensamiento crítico; grupos tomam decisões ruins porque los membros suprimem a dissidencia para mantener el consenso.","de":"Ein Phänomen, bei dem das Streben nach Gruppenharmonie und Konformität das kritische Denken überlagert; Gruppen treffen schlechte Entscheidungen, weil Mitglieder abweichende Meinungen unterdrücken, um den Konsens aufrechtzuerhalten.","fr":"Un phénomène où le désir d'harmonie et de conformité au sein du groupe prime sur la pensée critique ; les groupes prennent de mauvaises décisions car les membres répriment la dissidence pour maintenir le consensus.","tr":"Grup uyumu ve uyumluluğu arzusunun eleştirel düşünmeyi bastırdığı bir olgu; uzlaşmayı sürdürmek için üyelerin muhalefeti bastırması nedeniyle gruplar kötü kararlar alır.","nl":"Een fenomeen waarbij het verlangen naar groepsharmonie en conformiteit het kritisch denken overschaduwt; groepen nemen slechte beslissingen omdat leden afwijkende meningen onderdrukken om consensus te handhaven.","ru":"Феномен, при котором стремление к групповой гармонии и конформизму подавляет критическое мышление; группы принимают плохие решения, потому что участники подавляют инакомыслие ради сохранения консенсуса.","zh":"一种现象，群体对和谐与一致性的渴望压过了批判性思维；群体做出糟糕的决策，因为成员为维护共识而压制异议。","pt_BR":"Um fenômeno em que o desejo de harmonia e conformidade do grupo sobrepõe-se ao pensamento crítico; grupos tomam decisões ruins porque os membros suprimem a dissidência para manter o consenso.","pt_PT":"Um fenómeno em que o desejo de harmonia e conformidade do grupo se sobrepõe ao pensamento crítico; grupos tomam más decisões porque os membros suprimem a dissidência para manter o consenso."}},
  { id: 'dc-psychology-0022', deck_id: 'deck-psychology', front: 'Social Facilitation', back: 'The tendency for people to perform simple or well-practiced tasks better in the presence of others, but perform complex or novel tasks worse; first described by Norman Triplett.', sort_order: 22 , front_translations: {"es":"Facilitación Social","de":"Soziale Erleichterung","fr":"Facilitation sociale","tr":"Sosyal Kolaylaştırma","nl":"Sociale facilitatie","ru":"Социальная фасилитация","zh":"社会助长","pt_BR":"Facilitação Social","pt_PT":"Facilitação Social"}, back_translations: {"es":"La tendencia de las personas executarem tarefas simples o bem praticadas mejor en la presencia de outros, pero executarem tarefas complexas o nuevas de forma peor; descrita por la primera vez por Norman Triplett.","de":"Die Tendenz, einfache oder gut eingeübte Aufgaben in Anwesenheit anderer besser auszuführen, aber komplexe oder neue Aufgaben schlechter; erstmals von Norman Triplett beschrieben.","fr":"La tendance à mieux accomplir des tâches simples ou bien maîtrisées en présence d'autres personnes, mais moins bien les tâches complexes ou nouvelles ; décrite pour la première fois par Norman Triplett.","tr":"İnsanların başkalarının yanında basit veya iyi uygulanmış görevleri daha iyi, ancak karmaşık veya yeni görevleri daha kötü yerine getirme eğilimi; ilk kez Norman Triplett tarafından tanımlanmıştır.","nl":"De neiging om eenvoudige of goed geoefende taken beter uit te voeren in de aanwezigheid van anderen, maar complexe of nieuwe taken slechter; voor het eerst beschreven door Norman Triplett.","ru":"Склонность лучше выполнять простые или хорошо отработанные задачи в присутствии других, но хуже — сложные или новые; впервые описана Норманом Триплеттом.","zh":"人们在他人在场时倾向于更好地完成简单或熟练的任务，但在执行复杂或新任务时表现更差；由诺曼·特里普利特首先描述。","pt_BR":"A tendência de as pessoas executarem tarefas simples ou bem praticadas melhor na presença de outros, mas executarem tarefas complexas ou novas de forma pior; descrita pela primeira vez por Norman Triplett.","pt_PT":"A tendência de as pessoas executarem tarefas simples ou bem praticadas melhor na presença de outros, mas executarem tarefas complexas ou novas de forma pior; descrita pela primeira vez por Norman Triplett."}},
  { id: 'dc-psychology-0023', deck_id: 'deck-psychology', front: 'Social Loafing', back: 'The tendency for individuals to exert less effort when working in a group than when working alone; occurs because individual contributions are less identifiable.', sort_order: 23 , front_translations: {"es":"Vadiaje Social","de":"Soziales Faulenzen","fr":"Paresse sociale","tr":"Sosyal Kaytarma","nl":"Sociaal lanterfanten","ru":"Социальная лень","zh":"社会惰化","pt_BR":"Vadiagem Social","pt_PT":"Preguiça Social"}, back_translations: {"es":"La tendencia de indivíduos exercerem menos esforço al trabalhar en grupo del que al trabalhar sozinhos; ocurre porque las contribuciones individuais son menos identificables.","de":"Die Tendenz von Individuen, in einer Gruppe weniger Anstrengung aufzuwenden als bei Einzelarbeit; tritt auf, weil individuelle Beiträge weniger identifizierbar sind.","fr":"La tendance des individus à fournir moins d'efforts lorsqu'ils travaillent en groupe que lorsqu'ils travaillent seuls ; se produit parce que les contributions individuelles sont moins identifiables.","tr":"Bireylerin bir grupta çalışırken tek başına çalışmaya kıyasla daha az çaba gösterme eğilimi; bireysel katkıların daha az tanımlanabilir olmasından kaynaklanır.","nl":"De neiging van individuen om minder inspanning te leveren wanneer ze in een groep werken dan wanneer ze alleen werken; treedt op omdat individuele bijdragen minder identificeerbaar zijn.","ru":"Склонность людей прилагать меньше усилий при работе в группе, чем при индивидуальной работе; возникает из-за того, что индивидуальный вклад менее заметен.","zh":"个人在群体中工作时比单独工作时付出更少努力的倾向；之所以发生是因为个人贡献较难被识别。","pt_BR":"A tendência de indivíduos exercerem menos esforço ao trabalhar em grupo do que ao trabalhar sozinhos; ocorre porque as contribuições individuais são menos identificáveis.","pt_PT":"A tendência de indivíduos exercerem menos esforço ao trabalhar em grupo do que ao trabalhar sozinhos; ocorre porque as contribuições individuais são menos identificáveis."}},
  { id: 'dc-psychology-0024', deck_id: 'deck-psychology', front: 'Bystander Effect', back: 'The tendency for individuals to be less likely to offer help in an emergency when other people are present; diffusion of responsibility increases with group size.', sort_order: 24 , front_translations: {"es":"Efeito Espectador","de":"Zuschauer-Effekt","fr":"Effet du spectateur","tr":"Seyirci Etkisi","nl":"Omstandereffect","ru":"Эффект свидетеля","zh":"旁观者效应","pt_BR":"Efeito Espectador","pt_PT":"Efeito Espetador"}, back_translations: {"es":"La tendencia de indivíduos serem menos propensos a oferecer ayuda en una emergencia cuando outras personas están presentes; a difusão de responsabilidad aumenta con el tamaño del grupo.","de":"Die Tendenz, dass Individuen in einem Notfall weniger wahrscheinlich Hilfe leisten, wenn andere Personen anwesend sind; die Verantwortungsdiffusion nimmt mit der Gruppengröße zu.","fr":"La tendance des individus à être moins enclins à offrir de l'aide lors d'une urgence lorsque d'autres personnes sont présentes ; la diffusion de la responsabilité augmente avec la taille du groupe.","tr":"Başka insanların bulunduğu bir acil durumda bireylerin yardım etme olasılığının azalması eğilimi; sorumluluk dağılımı grup büyüklüğüyle birlikte artar.","nl":"De neiging van individuen om minder snel hulp te bieden bij een noodgeval wanneer er andere mensen aanwezig zijn; de spreiding van verantwoordelijkheid neemt toe met de groepsgrootte.","ru":"Склонность людей реже оказывать помощь в чрезвычайной ситуации, когда рядом присутствуют другие; размывание ответственности возрастает с увеличением группы.","zh":"当其他人在场时，个人在紧急情况下提供帮助的可能性降低的倾向；责任分散随群体规模增大而加剧。","pt_BR":"A tendência de indivíduos serem menos propensos a oferecer ajuda em uma emergência quando outras pessoas estão presentes; a difusão de responsabilidade aumenta com o tamanho do grupo.","pt_PT":"A tendência de indivíduos serem menos propensos a oferecer ajuda numa emergência quando outras pessoas estão presentes; a difusão de responsabilidade aumenta com a dimensão do grupo."}},
  { id: 'dc-psychology-0025', deck_id: 'deck-psychology', front: 'Deindividuation', back: 'A process where individuals lose self-awareness and personal responsibility when part of a group or crowd, often leading to behaviors they would not engage in alone.', sort_order: 25 , front_translations: {"es":"Desindividuación","de":"Deindividuation","fr":"Désindividuation","tr":"Bireysizleşme","nl":"De-individuatie","ru":"Деиндивидуация","zh":"去个体化","pt_BR":"Desindividuação","pt_PT":"Desindividuação"}, back_translations: {"es":"Un proceso en el qual indivíduos perdem a autoconsciencia y a responsabilidad pessoal cuando hacen parte de un grupo o multidão, frecuentemente levando a comportamientos que no teriam sozinhos.","de":"Ein Prozess, bei dem Individuen das Selbstbewusstsein und die persönliche Verantwortung verlieren, wenn sie Teil einer Gruppe oder Menge sind, was oft zu Verhaltensweisen führt, die sie allein nicht zeigen würden.","fr":"Un processus par lequel les individus perdent la conscience de soi et le sens de la responsabilité personnelle lorsqu'ils font partie d'un groupe ou d'une foule, conduisant souvent à des comportements qu'ils n'adopteraient pas seuls.","tr":"Bireylerin bir grubun veya kalabalığın parçası olduğunda öz farkındalık ve kişisel sorumluluk duygusunu kaybettiği ve çoğu zaman tek başına sergilemeyecekleri davranışlara yol açan bir süreç.","nl":"Een proces waarbij individuen het zelfbewustzijn en de persoonlijke verantwoordelijkheid verliezen wanneer ze deel uitmaken van een groep of menigte, wat vaak leidt tot gedrag dat ze alleen niet zouden vertonen.","ru":"Процесс, при котором люди утрачивают самосознание и чувство личной ответственности, находясь в группе или толпе, что часто ведёт к поведению, которого они не допустили бы в одиночку.","zh":"个体在成为群体或人群的一部分时失去自我意识和个人责任感的过程，常导致他们独处时不会做出的行为。","pt_BR":"Um processo no qual indivíduos perdem a autoconsciência e a responsabilidade pessoal quando fazem parte de um grupo ou multidão, frequentemente levando a comportamentos que não teriam sozinhos.","pt_PT":"Um processo no qual indivíduos perdem a autoconsciência e a responsabilidade pessoal quando fazem parte de um grupo ou multidão, frequentemente levando a comportamentos que não teriam sozinhos."}},
  { id: 'dc-psychology-0026', deck_id: 'deck-psychology', front: 'Prejudice', back: 'A preconceived opinion, often negative, about a person based on their membership in a social group; differs from discrimination (behavior) and stereotyping (cognitive).', sort_order: 26 , front_translations: {"es":"Preconceito","de":"Vorurteil","fr":"Préjugé","tr":"Önyargı","nl":"Vooroordeel","ru":"Предрассудок","zh":"偏见","pt_BR":"Preconceito","pt_PT":"Preconceito"}, back_translations: {"es":"Una opinião preconcebida, frecuentemente negativa, sobre una persona con base en su pertença a un grupo social; difere de la discriminación (comportamiento) y de los estereótipos (cognitivo).","de":"Eine vorgefasste Meinung, oft negativ, über eine Person aufgrund ihrer Zugehörigkeit zu einer sozialen Gruppe; unterscheidet sich von Diskriminierung (Verhalten) und Stereotypisierung (kognitiv).","fr":"Une opinion préconçue, souvent négative, sur une personne en raison de son appartenance à un groupe social ; différente de la discrimination (comportement) et des stéréotypes (cognitif).","tr":"Bir kişi hakkında, sosyal bir gruba üyeliğine dayanarak oluşturulan, çoğunlukla olumsuz önceden edinilmiş bir görüş; ayrımcılıktan (davranış) ve kalıp yargıdan (bilişsel) farklıdır.","nl":"Een vooropgezette mening, vaak negatief, over een persoon op basis van diens lidmaatschap van een sociale groep; verschilt van discriminatie (gedrag) en stereotypering (cognitief).","ru":"Предвзятое мнение, зачастую негативное, о человеке на основании его принадлежности к социальной группе; отличается от дискриминации (поведение) и стереотипизации (когнитивное).","zh":"基于某人所属社会群体而对其形成的先入为主的观念，往往带有负面色彩；有别于歧视（行为）和刻板印象（认知）。","pt_BR":"Uma opinião preconcebida, frequentemente negativa, sobre uma pessoa com base em sua pertença a um grupo social; difere da discriminação (comportamento) e dos estereótipos (cognitivo).","pt_PT":"Uma opinião preconcebida, frequentemente negativa, sobre uma pessoa com base na sua pertença a um grupo social; difere da discriminação (comportamento) e dos estereótipos (cognitivo)."}},
  { id: 'dc-psychology-0027', deck_id: 'deck-psychology', front: 'In-Group vs. Out-Group Bias', back: 'The tendency to favor members of one\'s own group (in-group) over those outside it (out-group); contributes to prejudice, discrimination, and intergroup conflict.', sort_order: 27 , front_translations: {"es":"Viés de endogrupo vs. exogrupo","de":"Eigengruppen- vs. Fremdgruppen-Bias","fr":"Biais endogroupe vs. exogroupe","tr":"İç Grup ile Dış Grup Yanlılığı","nl":"In-groep vs. uit-groepbias","ru":"Предвзятость в пользу своей группы vs. чужой группы","zh":"内群体与外群体偏见","pt_BR":"Viés de endogrupo vs. exogrupo","pt_PT":"Viés de endogrupo vs. exogrupo"}, back_translations: {"es":"La tendencia de favorecer membros del propio grupo (endogrupo) en detrimento de los de fuera (exogrupo); contribuye para preconceitos, discriminación y conflitos intergrupais.","de":"Die Tendenz, Mitglieder der eigenen Gruppe (Eigengruppe) gegenüber Außenstehenden (Fremdgruppe) zu bevorzugen; trägt zu Vorurteilen, Diskriminierung und Intergruppenkonflikt bei.","fr":"La tendance à favoriser les membres de son propre groupe (endogroupe) par rapport à ceux qui en sont extérieurs (exogroupe) ; contribue aux préjugés, à la discrimination et aux conflits intergroupes.","tr":"Kendi grubunun (iç grup) üyelerini dışarıdakilerin (dış grup) önünde tutma eğilimi; önyargıya, ayrımcılığa ve gruplar arası çatışmaya katkıda bulunur.","nl":"De neiging om leden van de eigen groep (in-groep) te begunstigen boven die buiten de groep (uit-groep); draagt bij aan vooroordelen, discriminatie en intergroepsconflicten.","ru":"Склонность отдавать предпочтение членам своей группы (ингруппы) перед теми, кто в неё не входит (аутгруппа); способствует предрассудкам, дискриминации и межгрупповым конфликтам.","zh":"倾向于偏袒自己所在群体（内群体）的成员，而非群体之外的人（外群体）；助长偏见、歧视和群体间冲突。","pt_BR":"A tendência de favorecer membros do próprio grupo (endogrupo) em detrimento dos de fora (exogrupo); contribui para preconceitos, discriminação e conflitos intergrupais.","pt_PT":"A tendência de favorecer membros do próprio grupo (endogrupo) em detrimento dos de fora (exogrupo); contribui para preconceitos, discriminação e conflitos intergrupais."}},
  { id: 'dc-psychology-0028', deck_id: 'deck-psychology', front: 'Piaget\'s Sensorimotor Stage', back: 'Birth to ~2 years: infants learn through sensory experiences and motor actions. A key achievement is object permanence — understanding that objects continue to exist even when hidden.', sort_order: 28 , front_translations: {"es":"Estágio sensório-motor de Piaget","de":"Piagets sensomotorische Phase","fr":"Stade sensori-moteur de Piaget","tr":"Piaget'nin Duyusal-Motor Dönemi","nl":"Piagets sensomotorische fase","ru":"Сенсомоторная стадия Пиаже","zh":"皮亚杰感知运动阶段","pt_BR":"Estágio sensório-motor de Piaget","pt_PT":"Estádio sensório-motor de Piaget"}, back_translations: {"es":"Do nascimento hasta ~2 anos: bebes aprendem por medio de experiencias sensoriais y acciones motoras. Una conquista fundamental es a permanencia del objeto — compreender que los objetos continuam a existir mismo cuando escondidos.","de":"Geburt bis ca. 2 Jahre: Säuglinge lernen durch sensorische Erfahrungen und motorische Handlungen. Eine wichtige Errungenschaft ist die Objektpermanenz – das Verständnis, dass Gegenstände weiter existieren, auch wenn sie verborgen sind.","fr":"De la naissance à ~2 ans : les nourrissons apprennent par l'expérience sensorielle et les actions motrices. Une réalisation clé est la permanence de l'objet — comprendre que les objets continuent d'exister même lorsqu'ils sont cachés.","tr":"Doğumdan ~2 yaşa kadar: bebekler duyusal deneyimler ve motor eylemler aracılığıyla öğrenir. Önemli bir kazanım, nesnelerin gizlendiğinde bile var olmaya devam ettiğini anlamak olan nesne kalıcılığıdır.","nl":"Geboorte tot ~2 jaar: baby's leren door zintuiglijke ervaringen en motorische handelingen. Een belangrijke prestatie is objectpermanentie — het besef dat objecten blijven bestaan ook als ze verborgen zijn.","ru":"От рождения до ~2 лет: младенцы познают мир через сенсорный опыт и двигательные действия. Ключевым достижением является константность объекта — понимание того, что предметы продолжают существовать, даже когда скрыты от глаз.","zh":"从出生到约2岁：婴儿通过感官体验和运动动作来学习。一项关键成就是客体永久性——理解物体即使被隐藏也依然存在。","pt_BR":"Do nascimento até ~2 anos: bebês aprendem por meio de experiências sensoriais e ações motoras. Uma conquista fundamental é a permanência do objeto — compreender que os objetos continuam a existir mesmo quando escondidos.","pt_PT":"Do nascimento até ~2 anos: os bebés aprendem através de experiências sensoriais e ações motoras. Uma conquista fundamental é a permanência do objeto — compreender que os objetos continuam a existir mesmo quando estão escondidos."}},
  { id: 'dc-psychology-0029', deck_id: 'deck-psychology', front: 'Piaget\'s Preoperational Stage', back: 'Ages 2–7: children develop language and symbolic thinking but are egocentric (unable to take others\' perspectives) and lack conservation (understanding that quantity stays the same despite shape changes).', sort_order: 29 , front_translations: {"es":"Estágio pré-operacional de Piaget","de":"Piagets präoperationale Phase","fr":"Stade préopératoire de Piaget","tr":"Piaget'nin İşlem Öncesi Dönemi","nl":"Piagets preoperationele fase","ru":"Дооперациональная стадия Пиаже","zh":"皮亚杰前运算阶段","pt_BR":"Estágio pré-operacional de Piaget","pt_PT":"Estádio pré-operatório de Piaget"}, back_translations: {"es":"Idades 2–7: las niños desenvolvem a linguaje y el pensamiento simbólico, pero son egocentricas (incapazes de assumir a perspectiva de los outros) y carecem de conservación (compreensão de que a cantidad permanece a misma apesar de las cambios de forma).","de":"2–7 Jahre: Kinder entwickeln Sprache und symbolisches Denken, sind aber egozentrisch (können die Perspektive anderer nicht einnehmen) und mangelt es an Invarianzverständnis (Verständnis, dass Mengen trotz Formveränderungen gleich bleiben).","fr":"De 2 à 7 ans : les enfants développent le langage et la pensée symbolique, mais sont égocentriques (incapables de prendre la perspective des autres) et manquent de conservation (compréhension que la quantité reste la même malgré les changements de forme).","tr":"2–7 yaş: çocuklar dil ve sembolik düşünce geliştirirler, ancak benmerkezcidir (başkalarının bakış açısını alamazlar) ve koruma kavramından (şekil değişikliklerine rağmen miktarın aynı kaldığı anlayışı) yoksundurlar.","nl":"Leeftijd 2–7: kinderen ontwikkelen taal en symbolisch denken, maar zijn egocentrisch (kunnen het perspectief van anderen niet innemen) en missen behoud (het begrijpen dat hoeveelheid gelijk blijft ondanks vormveranderingen).","ru":"Возраст 2–7 лет: дети развивают речь и символическое мышление, но остаются эгоцентричными (не способны встать на точку зрения другого) и лишены понятия сохранения (понимания того, что количество не меняется при изменении формы).","zh":"2至7岁：儿童发展出语言和符号思维，但具有自我中心性（无法站在他人角度看问题），也缺乏守恒概念（无法理解外形改变后数量保持不变）。","pt_BR":"Idades 2–7: as crianças desenvolvem a linguagem e o pensamento simbólico, mas são egocêntricas (incapazes de assumir a perspectiva dos outros) e carecem de conservação (compreensão de que a quantidade permanece a mesma apesar das mudanças de forma).","pt_PT":"Idades 2–7: as crianças desenvolvem a linguagem e o pensamento simbólico, mas são egocêntricas (incapazes de assumir a perspetiva dos outros) e carecem de conservação (compreensão de que a quantidade permanece a mesma apesar das mudanças de forma)."}},
  { id: 'dc-psychology-0030', deck_id: 'deck-psychology', front: 'Piaget\'s Concrete Operational Stage', back: 'Ages 7–11: children develop logical thinking about concrete objects, understand conservation, and can classify objects; still struggle with abstract hypothetical thinking.', sort_order: 30 , front_translations: {"es":"Estágio operacional concreto de Piaget","de":"Piagets konkret-operationale Phase","fr":"Stade des opérations concrètes de Piaget","tr":"Piaget'nin Somut İşlemler Dönemi","nl":"Piagets concreet-operationele fase","ru":"Стадия конкретных операций Пиаже","zh":"皮亚杰具体运算阶段","pt_BR":"Estágio operacional concreto de Piaget","pt_PT":"Estádio das operações concretas de Piaget"}, back_translations: {"es":"Idades 7–11: las niños desenvolvem pensamiento lógico sobre objetos concretos, compreendem a conservación y conseguem classificar objetos; aún tienen dificuldades con el pensamiento hipotético abstrato.","de":"7–11 Jahre: Kinder entwickeln logisches Denken über konkrete Objekte, verstehen Invarianz und können Objekte klassifizieren; haben noch Schwierigkeiten mit abstraktem hypothetischem Denken.","fr":"De 7 à 11 ans : les enfants développent une pensée logique sur les objets concrets, comprennent la conservation et peuvent classer les objets ; ont encore du mal avec la pensée abstraite et hypothétique.","tr":"7–11 yaş: çocuklar somut nesneler hakkında mantıksal düşünce geliştirir, korumayı anlar ve nesneleri sınıflandırabilir; soyut hipotetik düşüncede hâlâ zorlanırlar.","nl":"Leeftijd 7–11: kinderen ontwikkelen logisch denken over concrete objecten, begrijpen behoud en kunnen objecten classificeren; hebben nog moeite met abstract hypothetisch denken.","ru":"Возраст 7–11 лет: дети развивают логическое мышление применительно к конкретным объектам, понимают сохранение и умеют классифицировать предметы; по-прежнему испытывают затруднения с абстрактным гипотетическим мышлением.","zh":"7至11岁：儿童发展出针对具体物体的逻辑思维，理解守恒概念并能对物体进行分类；但抽象假设性思维仍有困难。","pt_BR":"Idades 7–11: as crianças desenvolvem pensamento lógico sobre objetos concretos, compreendem a conservação e conseguem classificar objetos; ainda têm dificuldades com o pensamento hipotético abstrato.","pt_PT":"Idades 7–11: as crianças desenvolvem o pensamento lógico sobre objetos concretos, compreendem a conservação e conseguem classificar objetos; ainda têm dificuldades com o pensamento hipotético-abstrato."}},
  { id: 'dc-psychology-0031', deck_id: 'deck-psychology', front: 'Piaget\'s Formal Operational Stage', back: 'Ages 12+: adolescents develop the ability for abstract, hypothetical-deductive reasoning, considering multiple possibilities and thinking scientifically.', sort_order: 31 , front_translations: {"es":"Estágio operacional formal de Piaget","de":"Piagets formal-operationale Phase","fr":"Stade des opérations formelles de Piaget","tr":"Piaget'nin Soyut İşlemler Dönemi","nl":"Piagets formeel-operationele fase","ru":"Стадия формальных операций Пиаже","zh":"皮亚杰形式运算阶段","pt_BR":"Estágio operacional formal de Piaget","pt_PT":"Estádio das operações formais de Piaget"}, back_translations: {"es":"La partir de los 12 anos: los adolescentes desenvolvem a capacidad de raciocínio abstrato y hipotético-dedutivo, considerando múltiplas posibilidades y pensando de forma científica.","de":"Ab 12 Jahren: Jugendliche entwickeln die Fähigkeit zum abstrakten, hypothetisch-deduktiven Denken, können mehrere Möglichkeiten in Betracht ziehen und wissenschaftlich denken.","fr":"À partir de 12 ans : les adolescents développent la capacité de raisonnement abstrait et hypothético-déductif, envisagent plusieurs possibilités et pensent de manière scientifique.","tr":"12 yaş ve üzeri: ergenler soyut, hipotetik-tümdengelimli akıl yürütme yeteneği geliştirir; birden fazla olasılığı değerlendirerek bilimsel düşünebilirler.","nl":"Leeftijd 12+: adolescenten ontwikkelen het vermogen voor abstract, hypothetisch-deductief redeneren, overwegen meerdere mogelijkheden en denken wetenschappelijk.","ru":"С 12 лет: подростки развивают способность к абстрактному, гипотетико-дедуктивному мышлению, рассматривают множество возможностей и мыслят научно.","zh":"12岁及以上：青少年发展出抽象的、假设-演绎推理能力，能够考虑多种可能性并进行科学思考。","pt_BR":"A partir dos 12 anos: os adolescentes desenvolvem a capacidade de raciocínio abstrato e hipotético-dedutivo, considerando múltiplas possibilidades e pensando de forma científica.","pt_PT":"A partir dos 12 anos: os adolescentes desenvolvem a capacidade de raciocínio abstrato e hipotético-dedutivo, considerando múltiplas possibilidades e pensando de forma científica."}},
  { id: 'dc-psychology-0032', deck_id: 'deck-psychology', front: 'Object Permanence', back: 'The understanding that objects continue to exist even when they cannot be seen or touched; develops around 8 months in Piaget\'s sensorimotor stage.', sort_order: 32 , front_translations: {"es":"Permanencia del objeto","de":"Objektpermanenz","fr":"Permanence de l'objet","tr":"Nesne Kalıcılığı","nl":"Objectpermanentie","ru":"Константность объекта","zh":"客体永久性","pt_BR":"Permanência do objeto","pt_PT":"Permanência do objeto"}, back_translations: {"es":"La compreensão de que los objetos continuam a existir mismo cuando no pueden ser vistos o tocados; se desarrolla por volta de los 8 meses en el etapa sensório-motor de Piaget.","de":"Das Verständnis, dass Objekte weiter existieren, auch wenn sie nicht gesehen oder berührt werden können; entwickelt sich nach Piaget im Alter von etwa 8 Monaten in der sensomotorischen Phase.","fr":"La compréhension que les objets continuent d'exister même quand on ne peut pas les voir ou les toucher ; se développe vers 8 mois selon le stade sensori-moteur de Piaget.","tr":"Nesnelerin görülemeyen veya dokunulamayan durumlarda bile var olmaya devam ettiğinin anlaşılması; Piaget'nin duyusal-motor döneminde yaklaşık 8. ayda gelişir.","nl":"Het besef dat objecten blijven bestaan ook als ze niet te zien of aan te raken zijn; ontwikkelt zich rond de leeftijd van 8 maanden in Piagets sensomotorische fase.","ru":"Понимание того, что предметы продолжают существовать, даже когда их нельзя увидеть или потрогать; формируется примерно в 8 месяцев в рамках сенсомоторной стадии по Пиаже.","zh":"理解物体即使看不见或摸不到也依然存在；根据皮亚杰的感知运动阶段，约在8个月时发展形成。","pt_BR":"A compreensão de que os objetos continuam a existir mesmo quando não podem ser vistos ou tocados; desenvolve-se por volta dos 8 meses no estágio sensório-motor de Piaget.","pt_PT":"A compreensão de que os objetos continuam a existir mesmo quando não podem ser vistos ou tocados; desenvolve-se por volta dos 8 meses no estádio sensório-motor de Piaget."}},
  { id: 'dc-psychology-0033', deck_id: 'deck-psychology', front: 'Conservation (Piaget)', back: 'The understanding that quantity, mass, or volume remains the same despite changes in appearance; develops in the concrete operational stage (~age 7).', sort_order: 33 , front_translations: {"es":"Conservación (Piaget)","de":"Invarianz (Piaget)","fr":"Conservation (Piaget)","tr":"Koruma (Piaget)","nl":"Behoud (Piaget)","ru":"Сохранение (Пиаже)","zh":"守恒（皮亚杰）","pt_BR":"Conservação (Piaget)","pt_PT":"Conservação (Piaget)"}, back_translations: {"es":"La compreensão de que cantidad, masa o volumen permanece el mismo apesar de las cambios de aparencia; se desarrolla en el etapa operacional concreto (~7 anos).","de":"Das Verständnis, dass Menge, Masse oder Volumen trotz Veränderungen im Aussehen gleich bleibt; entwickelt sich in der konkret-operationalen Phase (~7 Jahre).","fr":"La compréhension que la quantité, la masse ou le volume reste le même malgré les changements d'apparence ; se développe dans le stade des opérations concrètes (~7 ans).","tr":"Miktar, kütle veya hacmin görünümdeki değişikliklere rağmen aynı kalmasının anlaşılması; somut işlemler döneminde (~7 yaş) gelişir.","nl":"Het besef dat hoeveelheid, massa of volume gelijk blijft ondanks veranderingen in uiterlijk; ontwikkelt zich in de concreet-operationele fase (~7 jaar).","ru":"Понимание того, что количество, масса или объём остаются неизменными несмотря на изменения внешнего вида; формируется на стадии конкретных операций (~7 лет).","zh":"理解数量、质量或体积在外观改变后依然保持不变；在具体运算阶段（约7岁）发展形成。","pt_BR":"A compreensão de que quantidade, massa ou volume permanece o mesmo apesar das mudanças de aparência; desenvolve-se no estágio operacional concreto (~7 anos).","pt_PT":"A compreensão de que quantidade, massa ou volume permanece o mesmo apesar das mudanças de aparência; desenvolve-se no estádio operacional concreto (~7 anos)."}},
  { id: 'dc-psychology-0034', deck_id: 'deck-psychology', front: 'Attachment Theory (Bowlby)', back: 'John Bowlby\'s theory that infants have an innate need to form close emotional bonds with caregivers; early attachment quality profoundly influences social and emotional development.', sort_order: 34 , front_translations: {"es":"Teoria del apego (Bowlby)","de":"Bindungstheorie (Bowlby)","fr":"Théorie de l'attachement (Bowlby)","tr":"Bağlanma Teorisi (Bowlby)","nl":"Gehechtheidstheorie (Bowlby)","ru":"Теория привязанности (Боулби)","zh":"依恋理论（鲍尔比）","pt_BR":"Teoria do apego (Bowlby)","pt_PT":"Teoria da vinculação (Bowlby)"}, back_translations: {"es":"La teoría de John Bowlby de que los bebes tienen una necesidad inata de formar laços emocionais estreitos con los cuidadores; a calidad del apego precoce influencia profundamente el desarrollo social y emocional.","de":"John Bowlbys Theorie, dass Säuglinge ein angeborenes Bedürfnis haben, enge emotionale Bindungen zu Bezugspersonen zu entwickeln; die frühe Bindungsqualität beeinflusst die soziale und emotionale Entwicklung tiefgreifend.","fr":"La théorie de John Bowlby selon laquelle les nourrissons ont un besoin inné de former des liens émotionnels étroits avec leurs soignants ; la qualité des premières attachements influence profondément le développement social et émotionnel.","tr":"John Bowlby'nin, bebeklerin bakıcılarıyla yakın duygusal bağlar kurma konusunda doğuştan gelen bir ihtiyaçları olduğuna dair teorisi; erken bağlanma kalitesi sosyal ve duygusal gelişimi derinden etkiler.","nl":"John Bowlby's theorie dat baby's een aangeboren behoefte hebben om hechte emotionele banden te vormen met verzorgers; de vroege gehechtheidskwaliteit beïnvloedt de sociale en emotionele ontwikkeling ingrijpend.","ru":"Теория Джона Боулби о том, что у младенцев есть врождённая потребность формировать тесные эмоциональные связи с опекунами; качество ранней привязанности оказывает глубокое влияние на социальное и эмоциональное развитие.","zh":"约翰·鲍尔比的理论认为婴儿具有与照料者建立亲密情感纽带的天生需求；早期依恋质量对社会和情感发展有深远影响。","pt_BR":"A teoria de John Bowlby de que os bebês têm uma necessidade inata de formar laços emocionais estreitos com os cuidadores; a qualidade do apego precoce influencia profundamente o desenvolvimento social e emocional.","pt_PT":"A teoria de John Bowlby de que os bebés têm uma necessidade inata de formar laços emocionais estreitos com os cuidadores; a qualidade da vinculação precoce influencia profundamente o desenvolvimento social e emocional."}},
  { id: 'dc-psychology-0035', deck_id: 'deck-psychology', front: 'Secure Attachment', back: 'An attachment style (Mary Ainsworth) where infants feel comfortable with caregivers as a safe base; they explore freely and are distressed by but recover well from separation.', sort_order: 35 , front_translations: {"es":"Apego seguro","de":"Sichere Bindung","fr":"Attachement sécure","tr":"Güvenli Bağlanma","nl":"Veilige gehechtheid","ru":"Надёжная привязанность","zh":"安全型依恋","pt_BR":"Apego seguro","pt_PT":"Vinculação segura"}, back_translations: {"es":"Un estilo de apego (Mary Ainsworth) en que los bebes se sentem confortables con los cuidadores como base segura; exploram livremente y ficam angustiados con a separación, pero se recuperam bem.","de":"Ein Bindungsstil (Mary Ainsworth), bei dem Säuglinge die Bezugsperson als sichere Basis empfinden; sie erkunden frei und sind bei Trennung beunruhigt, erholen sich aber gut.","fr":"Un style d'attachement (Mary Ainsworth) dans lequel les nourrissons se sentent à l'aise avec les soignants comme base de sécurité ; ils explorent librement et sont perturbés par la séparation mais s'en remettent bien.","tr":"Bebeklerin bakıcıları ile güvenli bir üs olarak rahat hissettiği bir bağlanma stili (Mary Ainsworth); özgürce keşfederler ve ayrılığa üzülürler, ancak iyi bir şekilde toparlanırlar.","nl":"Een gehechtheidsstijl (Mary Ainsworth) waarbij baby's de verzorger als veilige basis ervaren; ze verkennen vrijelijk en zijn bij scheiding ontdaan, maar herstellen goed.","ru":"Стиль привязанности (Мэри Эйнсворт), при котором младенцы чувствуют себя комфортно, используя опекуна как надёжную базу; они свободно исследуют окружение и расстраиваются при разлуке, но быстро успокаиваются.","zh":"一种依恋风格（玛丽·安斯沃思），婴儿将照料者视为安全基地；他们自由探索，分离时感到痛苦，但能很好地恢复。","pt_BR":"Um estilo de apego (Mary Ainsworth) em que os bebês se sentem confortáveis com os cuidadores como base segura; exploram livremente e ficam angustiados com a separação, mas se recuperam bem.","pt_PT":"Um estilo de vinculação (Mary Ainsworth) em que os bebés se sentem confortáveis com os cuidadores como base segura; exploram livremente e ficam angustiados com a separação, mas recuperam bem."}},
  { id: 'dc-psychology-0036', deck_id: 'deck-psychology', front: 'Insecure Attachment Styles', back: 'Ainsworth identified anxious-ambivalent (clingy, not easily soothed), avoidant (emotionally detached from caregiver), and disorganized (fearful, inconsistent) insecure patterns.', sort_order: 36 , front_translations: {"es":"Estilos de apego inseguro","de":"Unsichere Bindungsstile","fr":"Styles d'attachement insécures","tr":"Güvensiz Bağlanma Stilleri","nl":"Onveilige gehechtheidsstijlen","ru":"Ненадёжные стили привязанности","zh":"不安全型依恋风格","pt_BR":"Estilos de apego inseguro","pt_PT":"Estilos de vinculação insegura"}, back_translations: {"es":"Ainsworth identificou padrões inseguros: ansioso-ambivalente (dependente, no se acalma fácilmente), evitativo (emocionalmente distante del cuidador) y desorganizado (medroso, inconsistente).","de":"Ainsworth identifizierte ängstlich-ambivalente (anhänglich, schwer zu beruhigen), vermeidende (emotional distanziert zum Bezugsperson) und desorganisierte (ängstlich, inkonsistent) unsichere Muster.","fr":"Ainsworth a identifié les patterns insécures : anxieux-ambivalent (accroché, pas facilement apaisé), évitant (détaché émotionnellement du soignant) et désorganisé (craintif, incohérent).","tr":"Ainsworth, kaygılı-kararsız (yapışkan, kolayca sakinleştirilemeyen), kaçınan (bakıcıdan duygusal olarak uzak) ve dezorganize (korkulu, tutarsız) güvensiz kalıpları tanımladı.","nl":"Ainsworth identificeerde angstig-ambivalent (klamend, niet gemakkelijk te sussen), vermijdend (emotioneel afstandelijk van verzorger) en gedesorganiseerd (angstig, inconsistent) onveilige patronen.","ru":"Эйнсворт выделила тревожно-амбивалентный (навязчивый, с трудом успокаивается), избегающий (эмоционально дистанцированный от опекуна) и дезорганизованный (боязливый, непоследовательный) ненадёжные паттерны.","zh":"安斯沃思识别出焦虑-矛盾型（依恋性强、不易安抚）、回避型（与照料者情感疏离）和混乱型（恐惧、行为不一致）三种不安全依恋模式。","pt_BR":"Ainsworth identificou padrões inseguros: ansioso-ambivalente (dependente, não se acalma facilmente), evitativo (emocionalmente distante do cuidador) e desorganizado (medroso, inconsistente).","pt_PT":"Ainsworth identificou padrões inseguros: ansioso-ambivalente (dependente, não se acalma facilmente), evitante (emocionalmente distante do cuidador) e desorganizado (medroso, inconsistente)."}},
  { id: 'dc-psychology-0037', deck_id: 'deck-psychology', front: 'Erikson\'s Stage 1: Trust vs. Mistrust', back: 'Birth to 18 months. Infants develop a sense of trust if caregivers provide reliable, consistent care; otherwise they develop mistrust of the world. Virtue: hope.', sort_order: 37 , front_translations: {"es":"Estágio 1 de Erikson: confiança vs. desconfiança","de":"Eriksons Phase 1: Urvertrauen vs. Urmisstrauen","fr":"Stade 1 d'Erikson : confiance vs. méfiance","tr":"Erikson'un 1. Aşaması: Güven - Güvensizlik","nl":"Eriksons fase 1: basisvertrouwen vs. wantrouwen","ru":"Стадия 1 по Эриксону: базовое доверие vs. недоверие","zh":"埃里克森第1阶段：信任 vs. 不信任","pt_BR":"Estágio 1 de Erikson: confiança vs. desconfiança","pt_PT":"Estádio 1 de Erikson: confiança vs. desconfiança"}, back_translations: {"es":"Do nascimento a los 18 meses. Los bebes desenvolvem confiança se los cuidadores oferecem cuidados confiables y consistentes; caso contrário, desenvolvem desconfiança en relación con el mundo. Virtude: esperança.","de":"Geburt bis 18 Monate. Säuglinge entwickeln Vertrauen, wenn Bezugspersonen zuverlässige, beständige Fürsorge bieten; andernfalls entwickeln sie Misstrauen gegenüber der Welt. Tugend: Hoffnung.","fr":"De la naissance à 18 mois. Les nourrissons développent un sentiment de confiance si les soignants fournissent des soins fiables et cohérents ; sinon, ils développent de la méfiance envers le monde. Vertu : espoir.","tr":"Doğumdan 18 aya kadar. Bakıcılar güvenilir, tutarlı bakım sağlarsa bebekler güven duygusu geliştirir; aksi hâlde dünyaya karşı güvensizlik geliştirir. Erdem: umut.","nl":"Geboorte tot 18 maanden. Zuigelingen ontwikkelen een gevoel van vertrouwen als verzorgers betrouwbare, consistente zorg bieden; anders ontwikkelen ze wantrouwen ten opzichte van de wereld. Deugd: hoop.","ru":"От рождения до 18 месяцев. Если опекуны обеспечивают надёжный и последовательный уход, у младенцев формируется базовое доверие; в противном случае — недоверие к миру. Добродетель: надежда.","zh":"从出生到18个月。若照料者提供可靠、一致的照料，婴儿发展出信任感；否则对世界产生不信任。美德：希望。","pt_BR":"Do nascimento aos 18 meses. Os bebês desenvolvem confiança se os cuidadores oferecem cuidados confiáveis e consistentes; caso contrário, desenvolvem desconfiança em relação ao mundo. Virtude: esperança.","pt_PT":"Do nascimento aos 18 meses. Os bebés desenvolvem confiança se os cuidadores oferecem cuidados fiáveis e consistentes; caso contrário, desenvolvem desconfiança em relação ao mundo. Virtude: esperança."}},
  { id: 'dc-psychology-0038', deck_id: 'deck-psychology', front: 'Erikson\'s Stage 5: Identity vs. Role Confusion', back: 'Adolescence (12–18 years). Teenagers explore and develop a sense of personal identity; failure results in role confusion and uncertainty about one\'s place in society. Virtue: fidelity.', sort_order: 38 , front_translations: {"es":"Estágio 5 de Erikson: identidad vs. confusão de papéis","de":"Eriksons Phase 5: Identität vs. Rollenkonfusion","fr":"Stade 5 d'Erikson : identité vs. confusion des rôles","tr":"Erikson'un 5. Aşaması: Kimlik - Rol Karmaşası","nl":"Eriksons fase 5: identiteit vs. rolverwarring","ru":"Стадия 5 по Эриксону: идентичность vs. ролевая спутанность","zh":"埃里克森第5阶段：同一性 vs. 角色混乱","pt_BR":"Estágio 5 de Erikson: identidade vs. confusão de papéis","pt_PT":"Estádio 5 de Erikson: identidade vs. confusão de papéis"}, back_translations: {"es":"Adolescencia (12–18 anos). Los adolescentes exploram y desenvolvem un senso de identidad pessoal; el fracasso resulta en confusão de papéis y incerteza sobre el lugar de cada un en la sociedad. Virtude: fidelidad.","de":"Adoleszenz (12–18 Jahre). Teenager erkunden und entwickeln ein Gefühl der persönlichen Identität; Scheitern führt zu Rollenkonfusion und Unsicherheit über den eigenen Platz in der Gesellschaft. Tugend: Treue.","fr":"Adolescence (12–18 ans). Les adolescents explorent et développent un sens de l'identité personnelle ; l'échec entraîne une confusion des rôles et une incertitude sur sa place dans la société. Vertu : fidélité.","tr":"Ergenlik (12–18 yaş). Gençler kişisel kimlik duygusu keşfeder ve geliştirir; başarısızlık, rol karmaşasına ve bireyin toplumdaki yerini bulmadaki belirsizliğe yol açar. Erdem: sadakat.","nl":"Adolescentie (12–18 jaar). Tieners verkennen en ontwikkelen een gevoel van persoonlijke identiteit; mislukking resulteert in rolverwarring en onzekerheid over de eigen plek in de maatschappij. Deugd: trouw.","ru":"Подростковый возраст (12–18 лет). Подростки исследуют и развивают чувство личностной идентичности; неудача приводит к ролевой спутанности и неопределённости относительно своего места в обществе. Добродетель: верность.","zh":"青春期（12至18岁）。青少年探索并发展自我同一性；失败会导致角色混乱和对自身社会定位的不确定。美德：忠诚。","pt_BR":"Adolescência (12–18 anos). Os adolescentes exploram e desenvolvem um senso de identidade pessoal; o fracasso resulta em confusão de papéis e incerteza sobre o lugar de cada um na sociedade. Virtude: fidelidade.","pt_PT":"Adolescência (12–18 anos). Os adolescentes exploram e desenvolvem um sentido de identidade pessoal; o fracasso resulta em confusão de papéis e incerteza sobre o lugar de cada um na sociedade. Virtude: fidelidade."}},
  { id: 'dc-psychology-0039', deck_id: 'deck-psychology', front: 'Erikson\'s Stage 8: Integrity vs. Despair', back: 'Late adulthood (65+). Older adults reflect on their lives; those with a sense of fulfillment achieve ego integrity, while those with regret experience despair. Virtue: wisdom.', sort_order: 39 , front_translations: {"es":"Estágio 8 de Erikson: integridad vs. desespero","de":"Eriksons Phase 8: Integrität vs. Verzweiflung","fr":"Stade 8 d'Erikson : intégrité vs. désespoir","tr":"Erikson'un 8. Aşaması: Bütünlük - Umutsuzluk","nl":"Eriksons fase 8: integriteit vs. wanhoop","ru":"Стадия 8 по Эриксону: целостность эго vs. отчаяние","zh":"埃里克森第8阶段：自我整合 vs. 绝望","pt_BR":"Estágio 8 de Erikson: integridade vs. desespero","pt_PT":"Estádio 8 de Erikson: integridade vs. desespero"}, back_translations: {"es":"Idad adulta tardia (65+). Los idosos refletem sobre sus vidas; aqueles con senso de realización alcançam a integridad del ego, mientras los que tienen arrependimentos experimentam desespero. Virtude: sabedoria.","de":"Spätes Erwachsenenalter (65+). Ältere Erwachsene reflektieren ihr Leben; diejenigen mit einem Gefühl der Erfüllung erlangen Ich-Integrität, während diejenigen mit Reue Verzweiflung erfahren. Tugend: Weisheit.","fr":"Fin de l'âge adulte (65+). Les personnes âgées réfléchissent sur leur vie ; celles qui ont un sentiment d'accomplissement atteignent l'intégrité du moi, tandis que celles qui ont des regrets éprouvent du désespoir. Vertu : sagesse.","tr":"Geç yetişkinlik (65+). Yaşlı yetişkinler yaşamlarını değerlendirir; doyum duygusu olan benlik bütünlüğüne ulaşırken, pişmanlık duyanlar umutsuzluk yaşar. Erdem: bilgelik.","nl":"Latere volwassenheid (65+). Oudere volwassenen reflecteren op hun leven; degenen met een gevoel van vervulling bereiken ego-integriteit, terwijl degenen met spijt wanhoop ervaren. Deugd: wijsheid.","ru":"Поздняя взрослость (65+). Пожилые люди оглядываются на прожитую жизнь; те, кто чувствует удовлетворённость, достигают целостности эго, тогда как испытывающие сожаление переживают отчаяние. Добродетель: мудрость.","zh":"晚年成年期（65岁及以上）。老年人回顾自己的生活；感到充实者获得自我整合，而心存遗憾者则陷入绝望。美德：智慧。","pt_BR":"Idade adulta tardia (65+). Os idosos refletem sobre suas vidas; aqueles com senso de realização alcançam a integridade do ego, enquanto os que têm arrependimentos experimentam desespero. Virtude: sabedoria.","pt_PT":"Idade adulta tardia (65+). Os idosos refletem sobre as suas vidas; os que têm um sentido de realização alcançam a integridade do ego, enquanto os que têm arrependimentos experienciam desespero. Virtude: sabedoria."}},
  { id: 'dc-psychology-0040', deck_id: 'deck-psychology', front: 'Vygotsky\'s Zone of Proximal Development (ZPD)', back: 'The range of tasks a learner can perform with guidance but not yet independently; learning occurs most effectively within this zone with appropriate scaffolding from teachers or peers.', sort_order: 40 , front_translations: {"es":"Zona de Desenvolvimento Proximal de Vygotsky (ZDP)","de":"Wygotskis Zone der nächsten Entwicklung (ZNE)","fr":"Zone proximale de développement de Vygotski (ZPD)","tr":"Vygotsky'nin Yakın Gelişim Alanı (ZPD)","nl":"Vygotsky's zone van naaste ontwikkeling (ZNO)","ru":"Зона ближайшего развития Выготского (ЗБР)","zh":"维果茨基最近发展区（ZPD）","pt_BR":"Zona de Desenvolvimento Proximal de Vygotsky (ZDP)","pt_PT":"Zona de Desenvolvimento Proximal de Vygotsky (ZDP)"}, back_translations: {"es":"El conjunto de tarefas que un aprendiz consegue realizar con orientación, pero aún no de forma independente; a aprendizaje ocurre de forma más eficaz dentro dessa zona con scaffolding adequado de professores o colegas.","de":"Der Bereich von Aufgaben, die ein Lernender mit Führung, aber noch nicht selbständig ausführen kann; Lernen erfolgt am effektivsten innerhalb dieser Zone mit angemessener Unterstützung durch Lehrer oder Gleichaltrige.","fr":"L'ensemble des tâches qu'un apprenant peut effectuer avec des conseils mais pas encore de manière autonome ; l'apprentissage se produit le plus efficacement dans cette zone avec un étayage approprié de la part des enseignants ou des pairs.","tr":"Bir öğrenicinin rehberlik ile gerçekleştirebileceği ancak henüz bağımsız olarak yapamayacağı görev aralığı; öğrenme, öğretmenler veya akranlardan uygun iskele desteğiyle bu bölge içinde en etkili şekilde gerçekleşir.","nl":"Het bereik van taken dat een leerling met begeleiding maar nog niet zelfstandig kan uitvoeren; leren vindt het meest effectief plaats binnen deze zone met passende ondersteuning van leraren of leeftijdsgenoten.","ru":"Диапазон задач, которые учащийся может выполнять с помощью наставника, но ещё не самостоятельно; обучение наиболее эффективно происходит внутри этой зоны при соответствующей поддержке (скаффолдинге) со стороны учителей или сверстников.","zh":"学习者在指导下能够完成但尚不能独立完成的任务范围；在教师或同伴适当支架支持下，学习在该区域内最为有效。","pt_BR":"O conjunto de tarefas que um aprendiz consegue realizar com orientação, mas ainda não de forma independente; a aprendizagem ocorre de forma mais eficaz dentro dessa zona com scaffolding adequado de professores ou colegas.","pt_PT":"O conjunto de tarefas que um aprendente consegue realizar com orientação, mas ainda não de forma independente; a aprendizagem ocorre de forma mais eficaz dentro dessa zona com scaffolding adequado de professores ou pares."}},
  { id: 'dc-psychology-0041', deck_id: 'deck-psychology', front: 'Scaffolding (Vygotsky)', back: 'Temporary support provided by a more knowledgeable person to help a learner perform tasks within their ZPD; support is gradually withdrawn as the learner becomes more independent.', sort_order: 41 , front_translations: {"es":"Scaffolding (Vygotsky)","de":"Scaffolding (Wygotski)","fr":"Étayage (Vygotski)","tr":"İskele (Vygotsky)","nl":"Scaffolding (Vygotsky)","ru":"Скаффолдинг (Выготский)","zh":"脚手架（维果茨基）","pt_BR":"Scaffolding (Vygotsky)","pt_PT":"Scaffolding (Vygotsky)"}, back_translations: {"es":"Suporte temporário fornecido por una persona más experiente para ajudar el aprendiz a realizar tarefas dentro de su ZDP; el suporte es retirado gradualmente a la medida que el aprendiz se torna más independente.","de":"Vorübergehende Unterstützung durch eine sachkundigere Person, um einem Lernenden zu helfen, Aufgaben in seiner ZNE zu erfüllen; die Unterstützung wird schrittweise zurückgezogen, während der Lernende selbstständiger wird.","fr":"Soutien temporaire fourni par une personne plus compétente pour aider un apprenant à accomplir des tâches dans sa ZPD ; le soutien est progressivement retiré à mesure que l'apprenant devient plus autonome.","tr":"Bir öğrenicinin ZPD'sindeki görevleri yerine getirmesine yardımcı olmak için daha bilgili bir kişi tarafından sağlanan geçici destek; öğrenci daha bağımsız hâle geldikçe destek kademeli olarak geri çekilir.","nl":"Tijdelijke ondersteuning van een meer ervaren persoon om een leerling te helpen taken binnen zijn ZNO uit te voeren; de ondersteuning wordt geleidelijk verminderd naarmate de leerling zelfstandiger wordt.","ru":"Временная поддержка, оказываемая более компетентным человеком, чтобы помочь учащемуся выполнять задачи в рамках его ЗБР; поддержка постепенно убирается по мере того, как учащийся становится более самостоятельным.","zh":"由知识更丰富的人提供的临时支持，帮助学习者完成其最近发展区内的任务；随着学习者逐渐独立，支持逐步撤除。","pt_BR":"Suporte temporário fornecido por uma pessoa mais experiente para ajudar o aprendiz a realizar tarefas dentro de sua ZDP; o suporte é retirado gradualmente à medida que o aprendiz se torna mais independente.","pt_PT":"Suporte temporário fornecido por uma pessoa mais experiente para ajudar o aprendente a realizar tarefas dentro da sua ZDP; o suporte é retirado gradualmente à medida que o aprendente se torna mais independente."}},
  { id: 'dc-psychology-0042', deck_id: 'deck-psychology', front: 'Maslow\'s Hierarchy of Needs', back: 'A motivational theory arranged in a pyramid: physiological (food, water) → safety → love/belonging → esteem → self-actualization. Lower needs must be met before higher needs motivate behavior.', sort_order: 42 , front_translations: {"es":"Hierarquia de necesidades de Maslow","de":"Maslows Bedürfnishierarchie","fr":"Hiérarchie des besoins de Maslow","tr":"Maslow'un İhtiyaçlar Hiyerarşisi","nl":"Maslows behoeftenhiërarchie","ru":"Пирамида потребностей Маслоу","zh":"马斯洛需求层次理论","pt_BR":"Hierarquia de necessidades de Maslow","pt_PT":"Hierarquia de necessidades de Maslow"}, back_translations: {"es":"Una teoría motivacional disposta en piramide: fisiológico (comida, agua) → seguridad → amor/pertencimento → estima → autorrealización. As necesidades inferiores devem ser atendidas antes que las superiores motivem el comportamiento.","de":"Eine Motivationstheorie in einer Pyramide: physiologisch (Nahrung, Wasser) → Sicherheit → Zugehörigkeit/Liebe → Wertschätzung → Selbstverwirklichung. Niedrigere Bedürfnisse müssen befriedigt sein, bevor höhere Bedürfnisse das Verhalten motivieren.","fr":"Une théorie de la motivation organisée en pyramide : physiologique (nourriture, eau) → sécurité → amour/appartenance → estime → actualisation de soi. Les besoins inférieurs doivent être satisfaits avant que les besoins supérieurs motivent le comportement.","tr":"Bir piramit içinde düzenlenmiş motivasyon teorisi: fizyolojik (yiyecek, su) → güvenlik → sevgi/aidiyet → saygınlık → kendini gerçekleştirme. Alt ihtiyaçlar karşılanmadan üst ihtiyaçlar davranışı motive edemez.","nl":"Een motivatietheorie in een piramide: fysiologisch (voedsel, water) → veiligheid → liefde/verbondenheid → waardering → zelfactualisatie. Lagere behoeften moeten worden vervuld voordat hogere behoeften het gedrag motiveren.","ru":"Мотивационная теория в форме пирамиды: физиологические (еда, вода) → безопасность → любовь/принадлежность → уважение → самоактуализация. Низшие потребности должны быть удовлетворены прежде, чем высшие начнут мотивировать поведение.","zh":"以金字塔形式排列的动机理论：生理需求（食物、水）→安全→爱与归属→尊重→自我实现。低层次需求须先得到满足，高层次需求才能驱动行为。","pt_BR":"Uma teoria motivacional disposta em pirâmide: fisiológico (comida, água) → segurança → amor/pertencimento → estima → autorrealização. As necessidades inferiores devem ser atendidas antes que as superiores motivem o comportamento.","pt_PT":"Uma teoria motivacional disposta em pirâmide: fisiológico (comida, água) → segurança → amor/pertença → estima → autorrealização. As necessidades inferiores devem ser satisfeitas antes que as superiores motivem o comportamento."}},
  { id: 'dc-psychology-0043', deck_id: 'deck-psychology', front: 'Self-Actualization', back: 'The highest level in Maslow\'s hierarchy; the drive to fulfill one\'s full potential, creativity, and authenticity. Only achieved when lower-level needs are substantially satisfied.', sort_order: 43 , front_translations: {"es":"Autorrealización","de":"Selbstverwirklichung","fr":"Actualisation de soi","tr":"Kendini Gerçekleştirme","nl":"Zelfactualisatie","ru":"Самоактуализация","zh":"自我实现","pt_BR":"Autorrealização","pt_PT":"Autorrealização"}, back_translations: {"es":"El nivel más alto en la hierarquia de Maslow; el impulso para realizar el pleno potencial, criatividad y autenticidad. Só es alcançado cuando las necesidades de nivel inferior están substancialmente satisfeitas.","de":"Die höchste Stufe in Maslows Hierarchie; der Antrieb, das eigene volle Potenzial, Kreativität und Authentizität zu entfalten. Wird nur erreicht, wenn Bedürfnisse der unteren Ebenen weitgehend befriedigt sind.","fr":"Le niveau le plus élevé dans la hiérarchie de Maslow ; le désir d'accomplir son plein potentiel, sa créativité et son authenticité. N'est atteint que lorsque les besoins de niveau inférieur sont substantiellement satisfaits.","tr":"Maslow'un hiyerarşisindeki en yüksek düzey; kişinin tam potansiyelini, yaratıcılığını ve özgünlüğünü gerçekleştirme dürtüsü. Yalnızca alt düzey ihtiyaçlar büyük ölçüde karşılandığında ulaşılır.","nl":"Het hoogste niveau in Maslows hiërarchie; de drive om het eigen volledige potentieel, creativiteit en authenticiteit te vervullen. Alleen bereikt wanneer behoeften van lagere niveaus grotendeels zijn vervuld.","ru":"Высший уровень в пирамиде Маслоу; стремление реализовать свой полный потенциал, творческие способности и аутентичность. Достигается лишь при условии существенного удовлетворения потребностей низших уровней.","zh":"马斯洛层次中的最高层级；实现个人全部潜能、创造力和真实自我的驱动力。只有在较低层次需求得到基本满足后才能实现。","pt_BR":"O nível mais alto na hierarquia de Maslow; o impulso para realizar o pleno potencial, criatividade e autenticidade. Só é alcançado quando as necessidades de nível inferior estão substancialmente satisfeitas.","pt_PT":"O nível mais alto na hierarquia de Maslow; o impulso para realizar o pleno potencial, criatividade e autenticidade. Só é alcançado quando as necessidades de nível inferior estão substancialmente satisfeitas."}},
  { id: 'dc-psychology-0044', deck_id: 'deck-psychology', front: 'Intrinsic vs. Extrinsic Motivation', back: 'Intrinsic motivation comes from within (interest, enjoyment); extrinsic motivation comes from external rewards or consequences. Over-reliance on extrinsic rewards can undermine intrinsic motivation (overjustification effect).', sort_order: 44 , front_translations: {"es":"Motivación intrínseca vs. extrínseca","de":"Intrinsische vs. extrinsische Motivation","fr":"Motivation intrinsèque vs. extrinsèque","tr":"İçsel ve Dışsal Motivasyon","nl":"Intrinsieke vs. extrinsieke motivatie","ru":"Внутренняя vs. внешняя мотивация","zh":"内在动机 vs. 外在动机","pt_BR":"Motivação intrínseca vs. extrínseca","pt_PT":"Motivação intrínseca vs. extrínseca"}, back_translations: {"es":"La motivación intrínseca vem de dentro (interesse, prazer); a motivación extrínseca vem de recompensas o consecuencias externas. El excessivo uso de recompensas extrínsecas puede minar a motivación intrínseca (efecto de superjustificativa).","de":"Intrinsische Motivation entsteht von innen (Interesse, Freude); extrinsische Motivation kommt von äußeren Belohnungen oder Konsequenzen. Übermäßige Abhängigkeit von extrinsischen Belohnungen kann intrinsische Motivation untergraben (Überjustifikationseffekt).","fr":"La motivation intrinsèque vient de l'intérieur (intérêt, plaisir) ; la motivation extrinsèque provient de récompenses ou de conséquences externes. Une dépendance excessive aux récompenses extrinsèques peut saper la motivation intrinsèque (effet de surjustification).","tr":"İçsel motivasyon içeriden gelir (ilgi, zevk); dışsal motivasyon dışarıdan gelen ödül veya sonuçlardan kaynaklanır. Dışsal ödüllere aşırı güvenmek içsel motivasyonu zayıflatabilir (aşırı gerekçelendirme etkisi).","nl":"Intrinsieke motivatie komt van binnenuit (interesse, plezier); extrinsieke motivatie komt van externe beloningen of gevolgen. Overmatige afhankelijkheid van extrinsieke beloningen kan intrinsieke motivatie ondermijnen (overjustificatie-effect).","ru":"Внутренняя мотивация исходит изнутри (интерес, удовольствие); внешняя мотивация обусловлена внешними наградами или последствиями. Чрезмерная зависимость от внешних наград может подрывать внутреннюю мотивацию (эффект сверхобоснования).","zh":"内在动机来自内部（兴趣、乐趣）；外在动机来自外部奖励或后果。过度依赖外在奖励可能会削弱内在动机（过度辩护效应）。","pt_BR":"A motivação intrínseca vem de dentro (interesse, prazer); a motivação extrínseca vem de recompensas ou consequências externas. O excessivo uso de recompensas extrínsecas pode minar a motivação intrínseca (efeito de superjustificativa).","pt_PT":"A motivação intrínseca vem de dentro (interesse, prazer); a motivação extrínseca vem de recompensas ou consequências externas. A dependência excessiva de recompensas extrínsecas pode minar a motivação intrínseca (efeito de sobrejustificação)."}},
  { id: 'dc-psychology-0045', deck_id: 'deck-psychology', front: 'Self-Determination Theory (SDT)', back: 'Deci and Ryan\'s theory that psychological well-being requires three innate needs: autonomy (sense of choice), competence (feeling effective), and relatedness (connection with others).', sort_order: 45 , front_translations: {"es":"Teoria de la Autodeterminación (TAD)","de":"Selbstbestimmungstheorie (SBT)","fr":"Théorie de l'autodétermination (TAD)","tr":"Öz-Belirleme Teorisi (SDT)","nl":"Zelfbeschikkingstheorie (SDT)","ru":"Теория самодетерминации (ТСД)","zh":"自我决定理论（SDT）","pt_BR":"Teoria da Autodeterminação (TAD)","pt_PT":"Teoria da Autodeterminação (TAD)"}, back_translations: {"es":"La teoría de Deci y Ryan de que el bem-estar psicológico requiere tres necesidades inatas: autonomia (senso de escolha), competencia (sentir-se eficaz) y relacionamento (conexión con los outros).","de":"Deci und Ryans Theorie, dass psychisches Wohlbefinden drei angeborene Bedürfnisse erfordert: Autonomie (Gefühl der Wahlfreiheit), Kompetenz (Gefühl der Wirksamkeit) und Verbundenheit (Verbindung mit anderen).","fr":"La théorie de Deci et Ryan selon laquelle le bien-être psychologique requiert trois besoins innés : l'autonomie (sentiment de choix), la compétence (sentiment d'efficacité) et l'appartenance (connexion avec les autres).","tr":"Deci ve Ryan'ın psikolojik iyilik halinin üç doğuştan gelen ihtiyacı gerektirdiğini öne sürdüğü teorisi: özerklik (seçim duygusu), yeterlik (etkili hissetme) ve ilişkililik (başkalarıyla bağlantı).","nl":"De theorie van Deci en Ryan dat psychologisch welzijn drie aangeboren behoeften vereist: autonomie (gevoel van keuze), competentie (gevoel van effectiviteit) en verbondenheid (verbinding met anderen).","ru":"Теория Деси и Райана о том, что психологическое благополучие требует удовлетворения трёх врождённых потребностей: автономии (ощущение выбора), компетентности (ощущение эффективности) и связанности (связь с другими).","zh":"德西和瑞安的理论认为心理健康需要三种天生需求：自主性（选择感）、胜任感（有效感）和关联性（与他人的联系）。","pt_BR":"A teoria de Deci e Ryan de que o bem-estar psicológico requer três necessidades inatas: autonomia (senso de escolha), competência (sentir-se eficaz) e relacionamento (conexão com os outros).","pt_PT":"A teoria de Deci e Ryan de que o bem-estar psicológico requer três necessidades inatas: autonomia (sentido de escolha), competência (sentir-se eficaz) e relacionamento (ligação com os outros)."}},
  { id: 'dc-psychology-0046', deck_id: 'deck-psychology', front: 'Sigmund Freud\'s Psychoanalytic Theory', back: 'Freud proposed that behavior is driven by unconscious conflicts, primarily between the id (primitive drives), ego (rational mediator), and superego (moral conscience).', sort_order: 46 , front_translations: {"es":"Teoria psicanalítica de Sigmund Freud","de":"Sigmund Freuds Psychoanalytische Theorie","fr":"Théorie psychanalytique de Sigmund Freud","tr":"Sigmund Freud'un Psikanalitik Teorisi","nl":"Sigmund Freuds psychoanalytische theorie","ru":"Психоаналитическая теория Зигмунда Фрейда","zh":"西格蒙德·弗洛伊德的精神分析理论","pt_BR":"Teoria psicanalítica de Sigmund Freud","pt_PT":"Teoria psicanalítica de Sigmund Freud"}, back_translations: {"es":"Freud propos que el comportamiento es movido por conflitos inconscientes, principalmente entre el id (impulsos primitivos), el ego (mediador racional) y el superego (conciencia moral).","de":"Freud schlug vor, dass Verhalten durch unbewusste Konflikte angetrieben wird, hauptsächlich zwischen dem Es (primitive Triebe), dem Ich (rationaler Vermittler) und dem Über-Ich (moralisches Gewissen).","fr":"Freud a proposé que le comportement est guidé par des conflits inconscients, principalement entre le ça (pulsions primitives), le moi (médiateur rationnel) et le surmoi (conscience morale).","tr":"Freud, davranışın bilinçdışı çatışmalar, özellikle id (ilkel dürtüler), ego (rasyonel arabulucu) ve süperego (ahlaki vicdan) arasındaki çatışmalar tarafından yönlendirildiğini öne sürdü.","nl":"Freud stelde dat gedrag wordt aangedreven door onbewuste conflicten, voornamelijk tussen het id (primitieve driften), het ego (rationele bemiddelaar) en het superego (moreel geweten).","ru":"Фрейд утверждал, что поведение определяется бессознательными конфликтами, прежде всего между ид (примитивные влечения), эго (рациональный посредник) и суперэго (моральная совесть).","zh":"弗洛伊德提出行为受无意识冲突驱动，主要发生在本我（原始冲动）、自我（理性调节者）和超我（道德良知）之间。","pt_BR":"Freud propôs que o comportamento é movido por conflitos inconscientes, principalmente entre o id (impulsos primitivos), o ego (mediador racional) e o superego (consciência moral).","pt_PT":"Freud propôs que o comportamento é movido por conflitos inconscientes, principalmente entre o id (impulsos primitivos), o ego (mediador racional) e o superego (consciência moral)."}},
  { id: 'dc-psychology-0047', deck_id: 'deck-psychology', front: 'Id, Ego, and Superego', back: 'Freud\'s structural model: the id operates on the pleasure principle (immediate gratification); the ego on the reality principle (rational planning); the superego internalizes moral standards.', sort_order: 47 , front_translations: {"es":"Id, ego y superego","de":"Es, Ich und Über-Ich","fr":"Ça, moi et surmoi","tr":"İd, Ego ve Süperego","nl":"Id, ego en superego","ru":"Ид, эго и суперэго","zh":"本我、自我与超我","pt_BR":"Id, ego e superego","pt_PT":"Id, ego e superego"}, back_translations: {"es":"El modelo estrutural de Freud: el id opera por el principio del prazer (gratificación imediata); el ego por el principio de la realidad (planejamento racional); el superego internaliza padrões morais.","de":"Freuds Strukturmodell: Das Es arbeitet nach dem Lustprinzip (sofortige Befriedigung); das Ich nach dem Realitätsprinzip (rationale Planung); das Über-Ich verinnerlicht moralische Standards.","fr":"Le modèle structurel de Freud : le ça fonctionne selon le principe de plaisir (satisfaction immédiate) ; le moi selon le principe de réalité (planification rationnelle) ; le surmoi intériorise les normes morales.","tr":"Freud'un yapısal modeli: id haz ilkesine göre işler (anlık doyum); ego gerçeklik ilkesine göre (rasyonel planlama); süperego ahlaki standartları içselleştirir.","nl":"Freuds structuurmodel: het id werkt op het lustprincipe (onmiddellijke bevrediging); het ego op het realiteitsprincipe (rationeel plannen); het superego verinnelijkt morele normen.","ru":"Структурная модель Фрейда: ид руководствуется принципом удовольствия (немедленное удовлетворение); эго — принципом реальности (рациональное планирование); суперэго интернализирует моральные нормы.","zh":"弗洛伊德的结构模型：本我遵循快乐原则（即时满足）；自我遵循现实原则（理性计划）；超我内化道德标准。","pt_BR":"O modelo estrutural de Freud: o id opera pelo princípio do prazer (gratificação imediata); o ego pelo princípio da realidade (planejamento racional); o superego internaliza padrões morais.","pt_PT":"O modelo estrutural de Freud: o id opera pelo princípio do prazer (gratificação imediata); o ego pelo princípio da realidade (planeamento racional); o superego internaliza normas morais."}},
  { id: 'dc-psychology-0048', deck_id: 'deck-psychology', front: 'Defense Mechanisms (Freud)', back: 'Unconscious strategies used by the ego to protect against anxiety from unacceptable thoughts. Examples: repression, denial, projection, rationalization, displacement, and sublimation.', sort_order: 48 , front_translations: {"es":"Mecanismos de defesa (Freud)","de":"Abwehrmechanismen (Freud)","fr":"Mécanismes de défense (Freud)","tr":"Savunma Mekanizmaları (Freud)","nl":"Afweermechanismen (Freud)","ru":"Защитные механизмы (Фрейд)","zh":"防御机制（弗洛伊德）","pt_BR":"Mecanismos de defesa (Freud)","pt_PT":"Mecanismos de defesa (Freud)"}, back_translations: {"es":"Estratégias inconscientes usadas por el ego para se proteger de la ansiedad gerada por pensamientos inaceitables. Exemplos: represión, negación, projeción, racionalización, deslocamento y sublimación.","de":"Unbewusste Strategien des Ichs zum Schutz vor Angst durch inakzeptable Gedanken. Beispiele: Verdrängung, Verleugnung, Projektion, Rationalisierung, Verschiebung und Sublimierung.","fr":"Stratégies inconscientes utilisées par le moi pour se protéger contre l'anxiété liée à des pensées inacceptables. Exemples : le refoulement, le déni, la projection, la rationalisation, le déplacement et la sublimation.","tr":"Egonun kabul edilemez düşüncelerden kaynaklanan kaygıya karşı korunmak için kullandığı bilinçdışı stratejiler. Örnekler: bastırma, inkâr, yansıtma, rasyonalizasyon, yer değiştirme ve yüceltme.","nl":"Onbewuste strategieën van het ego om angst van onaanvaardbare gedachten te beschermen. Voorbeelden: verdringing, ontkenning, projectie, rationalisatie, verplaatsing en sublimatie.","ru":"Бессознательные стратегии, используемые эго для защиты от тревоги, вызванной неприемлемыми мыслями. Примеры: вытеснение, отрицание, проекция, рационализация, смещение и сублимация.","zh":"自我为防御不可接受的想法所引发的焦虑而采用的无意识策略。例如：压抑、否认、投射、合理化、置换和升华。","pt_BR":"Estratégias inconscientes usadas pelo ego para se proteger da ansiedade gerada por pensamentos inaceitáveis. Exemplos: repressão, negação, projeção, racionalização, deslocamento e sublimação.","pt_PT":"Estratégias inconscientes utilizadas pelo ego para se proteger da ansiedade gerada por pensamentos inaceitáveis. Exemplos: repressão, negação, projeção, racionalização, deslocamento e sublimação."}},
  { id: 'dc-psychology-0049', deck_id: 'deck-psychology', front: 'Repression', back: 'A defense mechanism in which anxiety-provoking thoughts or memories are pushed out of conscious awareness into the unconscious; the cornerstone of Freudian theory.', sort_order: 49 , front_translations: {"es":"Represión","de":"Verdrängung","fr":"Refoulement","tr":"Bastırma","nl":"Verdringing","ru":"Вытеснение","zh":"压抑","pt_BR":"Repressão","pt_PT":"Repressão"}, back_translations: {"es":"Un mecanismo de defesa por el qual pensamientos o memorias geradoras de ansiedad son expulsos de la conciencia para el inconsciente; a pedra angular de la teoría freudiana.","de":"Ein Abwehrmechanismus, bei dem angstauslösende Gedanken oder Erinnerungen aus dem Bewusstsein ins Unbewusste verdrängt werden; der Eckpfeiler der Freudschen Theorie.","fr":"Un mécanisme de défense par lequel des pensées ou des souvenirs générateurs d'anxiété sont exclus de la conscience pour être relégués dans l'inconscient ; la pierre angulaire de la théorie freudienne.","tr":"Kaygıya yol açan düşünce veya anıların bilinçli farkındalıktan bilinçdışına itildiği bir savunma mekanizması; Freud teorisinin köşe taşı.","nl":"Een afweermechanisme waarbij angstwekkende gedachten of herinneringen uit het bewustzijn worden verdrongen naar het onbewuste; de hoeksteen van de Freudiaanse theorie.","ru":"Защитный механизм, при котором вызывающие тревогу мысли или воспоминания вытесняются из сознания в бессознательное; краеугольный камень фрейдовской теории.","zh":"一种防御机制，将引发焦虑的思想或记忆从意识中压入无意识；是弗洛伊德理论的基石。","pt_BR":"Um mecanismo de defesa pelo qual pensamentos ou memórias geradoras de ansiedade são expulsos da consciência para o inconsciente; a pedra angular da teoria freudiana.","pt_PT":"Um mecanismo de defesa pelo qual pensamentos ou memórias geradores de ansiedade são afastados da consciência para o inconsciente; a pedra angular da teoria freudiana."}},
  { id: 'dc-psychology-0050', deck_id: 'deck-psychology', front: 'Projection', back: 'A defense mechanism in which one attributes unacceptable thoughts or feelings to others; e.g., an angry person accuses others of being hostile.', sort_order: 50 , front_translations: {"es":"Projeción","de":"Projektion","fr":"Projection","tr":"Yansıtma (Projeksiyon)","nl":"Projectie","ru":"Проекция","zh":"投射","pt_BR":"Projeção","pt_PT":"Projeção"}, back_translations: {"es":"Un mecanismo de defesa por el qual se atribui a outros pensamientos o sentimientos inaceitables; p. ex., una persona raivosa acusa los outros de serem hostis.","de":"Ein Abwehrmechanismus, bei dem inakzeptable Gedanken oder Gefühle anderen zugeschrieben werden; z. B. wirft eine wütende Person anderen Feindseligkeit vor.","fr":"Un mécanisme de défense par lequel on attribue à autrui des pensées ou des sentiments inacceptables ; p. ex., une personne en colère accuse les autres d'être hostiles.","tr":"Kabul edilemez düşünce veya duyguların başkalarına atfedildiği bir savunma mekanizması; örneğin öfkeli bir kişi başkalarını düşmanca olmakla suçlar.","nl":"Een afweermechanisme waarbij men onaanvaardbare gedachten of gevoelens aan anderen toeschrijft; bijv. een boos persoon beschuldigt anderen van vijandigheid.","ru":"Защитный механизм, при котором неприемлемые мысли или чувства приписываются другим; например, злой человек обвиняет других в враждебности.","zh":"一种防御机制，将不可接受的思想或感受归咎于他人；例如，愤怒的人指责他人具有敌意。","pt_BR":"Um mecanismo de defesa pelo qual se atribui a outros pensamentos ou sentimentos inaceitáveis; p. ex., uma pessoa raivosa acusa os outros de serem hostis.","pt_PT":"Um mecanismo de defesa pelo qual se atribui a outros pensamentos ou sentimentos inaceitáveis; p. ex., uma pessoa furiosa acusa os outros de serem hostis."}},
  { id: 'dc-psychology-0051', deck_id: 'deck-psychology', front: 'Freud\'s Psychosexual Stages', back: 'Freud proposed five stages of development: oral, anal, phallic (Oedipus/Electra complex), latency, and genital. Unresolved conflicts at any stage create fixations affecting adult personality.', sort_order: 51 , front_translations: {"es":"Estágios Psicossexuais de Freud","de":"Freuds psychosexuelle Phasen","fr":"Les stades psychosexuels de Freud","tr":"Freud'un Psikoseksüel Evreleri","nl":"Freuds psychoseksuele stadia","ru":"Психосексуальные стадии Фрейда","zh":"弗洛伊德的心理性欲发展阶段","pt_BR":"Estágios Psicossexuais de Freud","pt_PT":"Fases Psicossexuais de Freud"}, back_translations: {"es":"Freud propos cinco etapas de desarrollo: oral, anal, fálico (complexo de Édipo/Electra), latencia y genital. Conflitos no resolvidos en cualquier etapa crean fixaciones que afectan a personalidad adulta.","de":"Freud beschrieb fünf Entwicklungsphasen: oral, anal, phallisch (Ödipus-/Elektrakomplex), Latenz und genital. Ungelöste Konflikte in einer Phase führen zu Fixierungen, die die Persönlichkeit im Erwachsenenalter beeinflussen.","fr":"Freud a proposé cinq stades de développement : oral, anal, phallique (complexe d'Œdipe/Électre), de latence et génital. Des conflits non résolus à n'importe quel stade créent des fixations affectant la personnalité adulte.","tr":"Freud beş gelişim evresi önerdi: oral, anal, fallik (Oedipus/Elektra kompleksi), gizillik ve genital. Herhangi bir evredeki çözümsüz çatışmalar, yetişkin kişiliğini etkileyen saplanmalara yol açar.","nl":"Freud stelde vijf ontwikkelingsfasen voor: oraal, anaal, fallisch (Oedipus-/Elektracomplex), latentie en genitaal. Onopgeloste conflicten in een fase veroorzaken fixaties die de volwassen persoonlijkheid beïnvloeden.","ru":"Фрейд предложил пять стадий развития: оральная, анальная, фаллическая (комплекс Эдипа/Электры), латентная и генитальная. Неразрешённые конфликты на любой стадии создают фиксации, влияющие на личность взрослого.","zh":"弗洛伊德提出了五个发展阶段：口腔期、肛门期、阳具期（俄狄浦斯/厄勒克特拉情结）、潜伏期和生殖期。任何阶段未解决的冲突都会产生影响成人人格的固着。","pt_BR":"Freud propôs cinco estágios de desenvolvimento: oral, anal, fálico (complexo de Édipo/Electra), latência e genital. Conflitos não resolvidos em qualquer estágio criam fixações que afetam a personalidade adulta.","pt_PT":"Freud propôs cinco fases de desenvolvimento: oral, anal, fálica (complexo de Édipo/Electra), latência e genital. Conflitos não resolvidos em qualquer fase criam fixações que afetam a personalidade adulta."}},
  { id: 'dc-psychology-0052', deck_id: 'deck-psychology', front: 'Carl Jung\'s Analytical Psychology', back: 'Jung proposed the collective unconscious containing archetypes (universal symbols). He introduced the concepts of introversion/extroversion, the shadow, anima/animus, and the persona.', sort_order: 52 , front_translations: {"es":"Psicologia Analítica de Carl Jung","de":"Carl Jungs Analytische Psychologie","fr":"La psychologie analytique de Carl Jung","tr":"Carl Jung'un Analitik Psikolojisi","nl":"Carl Jungs analytische psychologie","ru":"Аналитическая психология Карла Юнга","zh":"卡尔·荣格的分析心理学","pt_BR":"Psicologia Analítica de Carl Jung","pt_PT":"Psicologia Analítica de Carl Jung"}, back_translations: {"es":"Jung propos el inconsciente coletivo conteniendo arquétipos (símbolos universais). Ele introduziu los conceptos de introversão/extroversão, a sombra, anima/animus y a persona.","de":"Jung postulierte das kollektive Unbewusste mit Archetypen (universelle Symbole). Er führte die Konzepte Introversion/Extroversion, den Schatten, Anima/Animus und die Persona ein.","fr":"Jung a proposé l'inconscient collectif contenant des archétypes (symboles universels). Il a introduit les concepts d'introversion/extraversion, l'ombre, l'anima/animus et le persona.","tr":"Jung, arketipler (evrensel semboller) içeren kolektif bilinçdışını önerdi. İçe dönüklük/dışa dönüklük, gölge, anima/animus ve persona kavramlarını tanıttı.","nl":"Jung stelde het collectief onbewuste voor, dat archetypen (universele symbolen) bevat. Hij introduceerde de concepten introversie/extroversie, de schaduw, anima/animus en de persona.","ru":"Юнг предложил концепцию коллективного бессознательного, содержащего архетипы (универсальные символы). Он ввёл понятия интроверсии/экстраверсии, тени, анимы/анимуса и персоны.","zh":"荣格提出了包含原型（普遍象征）的集体无意识。他引入了内向/外向、阴影、阿尼玛/阿尼姆斯和人格面具的概念。","pt_BR":"Jung propôs o inconsciente coletivo contendo arquétipos (símbolos universais). Ele introduziu os conceitos de introversão/extroversão, a sombra, anima/animus e a persona.","pt_PT":"Jung propôs o inconsciente coletivo contendo arquétipos (símbolos universais). Introduziu os conceitos de introversão/extroversão, a sombra, anima/animus e a persona."}},
  { id: 'dc-psychology-0053', deck_id: 'deck-psychology', front: 'Introversion and Extroversion (Jung)', back: 'Introversion refers to a preference for solitary activities and inner reflection; extroversion to a preference for social interaction and external stimulation. Most people fall on a continuum.', sort_order: 53 , front_translations: {"es":"Introversão y Extroversão (Jung)","de":"Introversion und Extroversion (Jung)","fr":"Introversion et extraversion (Jung)","tr":"İçe Dönüklük ve Dışa Dönüklük (Jung)","nl":"Introversie en extroversie (Jung)","ru":"Интроверсия и экстраверсия (Юнг)","zh":"内向与外向（荣格）","pt_BR":"Introversão e Extroversão (Jung)","pt_PT":"Introversão e Extroversão (Jung)"}, back_translations: {"es":"Introversão se refiere a la preferencia por atividades solitárias y reflexão interior; extroversão a la preferencia por interacción social y estimulación externa. La maioria de las personas se situa en un continuum.","de":"Introversion bezeichnet eine Präferenz für Einzelaktivitäten und innere Reflexion; Extroversion eine Vorliebe für soziale Interaktion und äußere Stimulation. Die meisten Menschen liegen auf einem Kontinuum.","fr":"L'introversion désigne une préférence pour les activités solitaires et la réflexion intérieure ; l'extraversion pour l'interaction sociale et la stimulation externe. La plupart des gens se situent sur un continuum.","tr":"İçe dönüklük, yalnız aktiviteleri ve iç yansımayı tercih etmeyi ifade eder; dışa dönüklük ise sosyal etkileşimi ve dışsal uyarımı tercih etmeyi. Çoğu insan bir süreklilik üzerinde yer alır.","nl":"Introversie verwijst naar een voorkeur voor solitaire activiteiten en innerlijke reflectie; extroversie naar een voorkeur voor sociale interactie en externe stimulatie. De meeste mensen bevinden zich op een continuüm.","ru":"Интроверсия означает предпочтение одиночных занятий и внутренней рефлексии; экстраверсия — предпочтение социального взаимодействия и внешней стимуляции. Большинство людей находятся на континууме.","zh":"内向指偏好独自活动和内部反思；外向指偏好社交互动和外部刺激。大多数人处于这一连续谱上的某个位置。","pt_BR":"Introversão refere-se à preferência por atividades solitárias e reflexão interior; extroversão à preferência por interação social e estimulação externa. A maioria das pessoas se situa em um continuum.","pt_PT":"A introversão refere-se à preferência por atividades solitárias e reflexão interior; a extroversão à preferência por interação social e estimulação externa. A maioria das pessoas situa-se num continuum."}},
  { id: 'dc-psychology-0054', deck_id: 'deck-psychology', front: 'Big Five Personality Traits (OCEAN)', back: 'The five-factor model: Openness, Conscientiousness, Extroversion, Agreeableness, Neuroticism. These dimensions represent the most validated framework of human personality.', sort_order: 54 , front_translations: {"es":"Los Cinco Grandes Traços de Personalidad (OCEAN)","de":"Fünf große Persönlichkeitseigenschaften (OCEAN)","fr":"Les cinq grands traits de personnalité (OCEAN)","tr":"Beş Büyük Kişilik Özelliği (OCEAN)","nl":"De Grote Vijf persoonlijkheidseigenschappen (OCEAN)","ru":"Большая пятёрка черт личности (OCEAN)","zh":"五大人格特质（OCEAN）","pt_BR":"Os Cinco Grandes Traços de Personalidade (OCEAN)","pt_PT":"Os Cinco Grandes Traços de Personalidade (OCEAN)"}, back_translations: {"es":"El modelo de los cinco fatores: Abertura, Conscienciosidad, Extroversão, Amabilidad, Neuroticismo. Essas dimensões representan el framework más validado de la personalidad humana.","de":"Das Fünf-Faktoren-Modell: Offenheit, Gewissenhaftigkeit, Extraversion, Verträglichkeit, Neurotizismus. Diese Dimensionen repräsentieren den am besten validierten Rahmen der menschlichen Persönlichkeit.","fr":"Le modèle à cinq facteurs : Ouverture, Conscienciosité, Extraversion, Agréabilité, Névrosisme. Ces dimensions représentent le cadre le plus validé de la personnalité humaine.","tr":"Beş faktör modeli: Açıklık, Sorumluluk, Dışa Dönüklük, Uyumluluk, Nevrotiklik. Bu boyutlar, insan kişiliğinin en geçerli çerçevesini temsil eder.","nl":"Het vijf-factorenmodel: Openheid, Consciëntieusheid, Extraversie, Vriendelijkheid, Neuroticisme. Deze dimensies vormen het meest gevalideerde kader van de menselijke persoonlijkheid.","ru":"Пятифакторная модель: открытость, добросовестность, экстраверсия, доброжелательность, нейротизм. Эти измерения представляют наиболее валидизированную концепцию личности человека.","zh":"五因素模型：开放性、尽责性、外向性、宜人性、神经质。这些维度代表了人类人格最经过验证的框架。","pt_BR":"O modelo dos cinco fatores: Abertura, Conscienciosidade, Extroversão, Amabilidade, Neuroticismo. Essas dimensões representam o framework mais validado da personalidade humana.","pt_PT":"O modelo dos cinco fatores: Abertura à experiência, Conscienciosidade, Extroversão, Amabilidade, Neuroticismo. Estas dimensões representam o modelo mais validado da personalidade humana."}},
  { id: 'dc-psychology-0055', deck_id: 'deck-psychology', front: 'Openness to Experience (Big Five)', back: 'Reflects curiosity, creativity, and receptivity to new ideas and experiences. High scorers tend to be imaginative and intellectually curious; low scorers prefer routine and convention.', sort_order: 55 , front_translations: {"es":"Abertura a la Experiencia (Big Five)","de":"Offenheit für Erfahrungen (Große Fünf)","fr":"Ouverture à l'expérience (Big Five)","tr":"Deneyime Açıklık (Beş Büyük)","nl":"Openheid voor ervaringen (Grote Vijf)","ru":"Открытость опыту (Большая пятёрка)","zh":"对经验的开放性（五大人格）","pt_BR":"Abertura à Experiência (Big Five)","pt_PT":"Abertura à Experiência (Big Five)"}, back_translations: {"es":"Reflete curiosidad, criatividad y receptividad a nuevas ideias y experiencias. Quem pontua alto tende a ser imaginativo y intelectualmente curioso; quem pontua bajo prefere a rotina y a convención.","de":"Spiegelt Neugier, Kreativität und Aufnahmebereitschaft für neue Ideen und Erfahrungen wider. Hochgradig Ausgeprägte neigen dazu, fantasievoll und intellektuell neugierig zu sein; niedrig Ausgeprägte bevorzugen Routine und Konvention.","fr":"Reflète la curiosité, la créativité et la réceptivité aux nouvelles idées et expériences. Les personnes avec un score élevé ont tendance à être imaginatives et curieuses intellectuellement ; celles avec un score faible préfèrent la routine et la convention.","tr":"Merak, yaratıcılık ve yeni fikir ve deneyimlere açıklığı yansıtır. Yüksek puanlılar hayal gücü kuvvetli ve entelektüel açıdan meraklı olma eğilimindedir; düşük puanlılar rutin ve alışılageldik olanı tercih eder.","nl":"Weerspiegelt nieuwsgierigheid, creativiteit en ontvankelijkheid voor nieuwe ideeën en ervaringen. Hoogscorers zijn doorgaans fantasierijk en intellectueel nieuwsgierig; laagscorers geven de voorkeur aan routine en conventie.","ru":"Отражает любопытство, творческое мышление и восприимчивость к новым идеям и опыту. Люди с высокими показателями склонны быть воображаемыми и интеллектуально любопытными; с низкими — предпочитают рутину и традиции.","zh":"反映好奇心、创造力以及对新想法和新经验的接受能力。高分者倾向于富有想象力和求知欲；低分者偏好常规和传统。","pt_BR":"Reflete curiosidade, criatividade e receptividade a novas ideias e experiências. Quem pontua alto tende a ser imaginativo e intelectualmente curioso; quem pontua baixo prefere a rotina e a convenção.","pt_PT":"Reflete curiosidade, criatividade e recetividade a novas ideias e experiências. Quem pontua alto tende a ser imaginativo e intelectualmente curioso; quem pontua baixo prefere a rotina e a convenção."}},
  { id: 'dc-psychology-0056', deck_id: 'deck-psychology', front: 'Conscientiousness (Big Five)', back: 'Reflects self-discipline, organization, and goal-directedness. The strongest personality predictor of academic and job performance; high scorers are reliable and achievement-oriented.', sort_order: 56 , front_translations: {"es":"Conscienciosidad (Big Five)","de":"Gewissenhaftigkeit (Große Fünf)","fr":"Conscienciosité (Big Five)","tr":"Sorumluluk (Beş Büyük)","nl":"Consciëntieusheid (Grote Vijf)","ru":"Добросовестность (Большая пятёрка)","zh":"尽责性（五大人格）","pt_BR":"Conscienciosidade (Big Five)","pt_PT":"Conscienciosidade (Big Five)"}, back_translations: {"es":"Reflete autodisciplina, organización y orientación para objetivos. El mayor preditor de personalidad para rendimiento academico y profissional; quem pontua alto es confiable y orientado para realizaciones.","de":"Spiegelt Selbstdisziplin, Organisation und Zielorientierung wider. Der stärkste Persönlichkeitsprediktor für schulische und berufliche Leistung; Hochgradig Ausgeprägte sind zuverlässig und leistungsorientiert.","fr":"Reflète la maîtrise de soi, l'organisation et l'orientation vers les objectifs. Le meilleur prédicteur de personnalité pour les performances académiques et professionnelles ; les personnes avec un score élevé sont fiables et orientées vers la réussite.","tr":"Öz disiplin, organizasyon ve hedefe yönelimliliği yansıtır. Akademik ve iş performansının en güçlü kişilik yordayıcısı; yüksek puanlılar güvenilir ve başarı odaklıdır.","nl":"Weerspiegelt zelfdiscipline, organisatie en doelgerichtheid. De sterkste persoonlijkheidsvoorspeller van academische en werkprestaties; hoogscorers zijn betrouwbaar en prestatiegericht.","ru":"Отражает самодисциплину, организованность и целеустремлённость. Наиболее сильный предиктор академической и профессиональной успеваемости среди черт личности; люди с высокими показателями надёжны и ориентированы на достижения.","zh":"反映自律性、组织能力和目标导向性。是学业和工作绩效最强的人格预测因子；高分者可靠、有成就动机。","pt_BR":"Reflete autodisciplina, organização e orientação para objetivos. O maior preditor de personalidade para desempenho acadêmico e profissional; quem pontua alto é confiável e orientado para realizações.","pt_PT":"Reflete autodisciplina, organização e orientação para objetivos. O preditor de personalidade mais forte do desempenho académico e profissional; quem pontua alto é fiável e orientado para as realizações."}},
  { id: 'dc-psychology-0057', deck_id: 'deck-psychology', front: 'Neuroticism (Big Five)', back: 'Reflects emotional instability, anxiety, and tendency to experience negative emotions. High neuroticism is associated with vulnerability to stress and mental health disorders.', sort_order: 57 , front_translations: {"es":"Neuroticismo (Big Five)","de":"Neurotizismus (Große Fünf)","fr":"Névrosisme (Big Five)","tr":"Nevrotiklik (Beş Büyük)","nl":"Neuroticisme (Grote Vijf)","ru":"Нейротизм (Большая пятёрка)","zh":"神经质（五大人格）","pt_BR":"Neuroticismo (Big Five)","pt_PT":"Neuroticismo (Big Five)"}, back_translations: {"es":"Reflete instabilidad emocional, ansiedad y tendencia a experienciar emociones negativas. Alto neuroticismo está associado a la vulnerabilidad al estresse y a trastornos de salud mental.","de":"Spiegelt emotionale Instabilität, Angst und die Tendenz wider, negative Emotionen zu erleben. Hoher Neurotizismus ist mit Anfälligkeit für Stress und psychische Erkrankungen verbunden.","fr":"Reflète l'instabilité émotionnelle, l'anxiété et la tendance à éprouver des émotions négatives. Un névrosisme élevé est associé à la vulnérabilité au stress et aux troubles de santé mentale.","tr":"Duygusal dengesizliği, kaygıyı ve olumsuz duygular yaşama eğilimini yansıtır. Yüksek nevrotiklik, strese ve ruh sağlığı bozukluklarına karşı kırılganlıkla ilişkilidir.","nl":"Weerspiegelt emotionele instabiliteit, angst en de neiging om negatieve emoties te ervaren. Hoog neuroticisme is geassocieerd met kwetsbaarheid voor stress en psychische stoornissen.","ru":"Отражает эмоциональную нестабильность, тревожность и склонность к переживанию негативных эмоций. Высокий нейротизм связан с уязвимостью к стрессу и психическим расстройствам.","zh":"反映情绪不稳定性、焦虑以及体验负面情绪的倾向。高神经质与对压力和心理健康障碍的易感性相关。","pt_BR":"Reflete instabilidade emocional, ansiedade e tendência a experienciar emoções negativas. Alto neuroticismo está associado à vulnerabilidade ao estresse e a transtornos de saúde mental.","pt_PT":"Reflete instabilidade emocional, ansiedade e tendência a experienciar emoções negativas. Alto neuroticismo está associado à vulnerabilidade ao stress e a perturbações de saúde mental."}},
  { id: 'dc-psychology-0058', deck_id: 'deck-psychology', front: 'Agreeableness (Big Five)', back: 'Reflects cooperativeness, trust, and kindness toward others. High scorers are empathetic and prosocial; low scorers can be competitive and skeptical.', sort_order: 58 , front_translations: {"es":"Amabilidad (Big Five)","de":"Verträglichkeit (Große Fünf)","fr":"Agréabilité (Big Five)","tr":"Uyumluluk (Beş Büyük)","nl":"Vriendelijkheid (Grote Vijf)","ru":"Доброжелательность (Большая пятёрка)","zh":"宜人性（五大人格）","pt_BR":"Amabilidade (Big Five)","pt_PT":"Amabilidade (Big Five)"}, back_translations: {"es":"Reflete cooperatividad, confiança y gentileza para con los outros. Quem pontua alto es empático y pró-social; quem pontua bajo puede ser competitivo y cético.","de":"Spiegelt Kooperationsbereitschaft, Vertrauen und Freundlichkeit gegenüber anderen wider. Hochgradig Ausgeprägte sind einfühlsam und prosozial; niedrig Ausgeprägte können wettbewerbsorientiert und skeptisch sein.","fr":"Reflète la coopération, la confiance et la gentillesse envers les autres. Les personnes avec un score élevé sont empathiques et prosociales ; celles avec un score faible peuvent être compétitives et sceptiques.","tr":"Diğerlerine yönelik işbirliği, güven ve nezaketi yansıtır. Yüksek puanlılar empatik ve prososyaldir; düşük puanlılar rekabetçi ve şüpheci olabilir.","nl":"Weerspiegelt coöperativiteit, vertrouwen en vriendelijkheid tegenover anderen. Hoogscorers zijn empathisch en prosociaal; laagscorers kunnen competitief en sceptisch zijn.","ru":"Отражает склонность к сотрудничеству, доверие и доброжелательность по отношению к другим. Люди с высокими показателями эмпатичны и просоциальны; с низкими — могут быть конкурентными и скептичными.","zh":"反映对他人的合作性、信任和友善。高分者富有同理心和亲社会性；低分者可能具有竞争性和怀疑态度。","pt_BR":"Reflete cooperatividade, confiança e gentileza para com os outros. Quem pontua alto é empático e pró-social; quem pontua baixo pode ser competitivo e cético.","pt_PT":"Reflete cooperatividade, confiança e gentileza para com os outros. Quem pontua alto é empático e pró-social; quem pontua baixo pode ser competitivo e cético."}},
  { id: 'dc-psychology-0059', deck_id: 'deck-psychology', front: 'Major Depressive Disorder (MDD)', back: 'Characterized by persistent low mood, loss of interest in activities, fatigue, feelings of worthlessness, and cognitive impairment lasting at least two weeks; a leading cause of disability worldwide.', sort_order: 59 , front_translations: {"es":"Transtorno Depressivo Maior (TDM)","de":"Schwere depressive Störung (MDD)","fr":"Trouble dépressif majeur (TDM)","tr":"Majör Depresif Bozukluk (MDB)","nl":"Zware depressieve stoornis (MDD)","ru":"Большое депрессивное расстройство (БДР)","zh":"重性抑郁障碍（MDD）","pt_BR":"Transtorno Depressivo Maior (TDM)","pt_PT":"Perturbação Depressiva Major (PDM)"}, back_translations: {"es":"Caracterizado por humor persistentemente bajo, perda de interesse en las atividades, fadiga, sentimientos de inutilidad y comprometimento cognitivo con duración mínima de de los semanas; una de las principales causas de incapacidad en el mundo.","de":"Gekennzeichnet durch anhaltende Niedergeschlagenheit, Interessenverlust, Erschöpfung, Gefühle der Wertlosigkeit und kognitive Beeinträchtigungen, die mindestens zwei Wochen andauern; weltweit eine der häufigsten Ursachen für Behinderung.","fr":"Caractérisé par une humeur basse persistante, une perte d'intérêt pour les activités, de la fatigue, des sentiments d'inutilité et des troubles cognitifs durant au moins deux semaines ; l'une des principales causes d'incapacité dans le monde.","tr":"En az iki hafta süren kalıcı düşük ruh hali, aktivitelere ilgi kaybı, yorgunluk, değersizlik hisleri ve bilişsel bozulma ile karakterizedir; dünya genelinde önde gelen bir engellilik nedenidir.","nl":"Gekenmerkt door aanhoudend somber stemming, verlies van interesse in activiteiten, vermoeidheid, gevoelens van waardeloosheid en cognitieve stoornissen die minimaal twee weken aanhouden; een van de belangrijkste oorzaken van invaliditeit wereldwijd.","ru":"Характеризуется стойко подавленным настроением, утратой интереса к деятельности, усталостью, чувством никчёмности и когнитивными нарушениями, длящимися не менее двух недель; ведущая причина инвалидности в мире.","zh":"以持续性情绪低落、对活动失去兴趣、疲劳、无价值感以及认知损害为特征，持续至少两周；是全球残疾的主要原因之一。","pt_BR":"Caracterizado por humor persistentemente baixo, perda de interesse nas atividades, fadiga, sentimentos de inutilidade e comprometimento cognitivo com duração mínima de duas semanas; uma das principais causas de incapacidade no mundo.","pt_PT":"Caracterizado por humor persistentemente baixo, perda de interesse nas atividades, fadiga, sentimentos de inutilidade e comprometimento cognitivo com duração mínima de duas semanas; uma das principais causas de incapacidade no mundo."}},
  { id: 'dc-psychology-0060', deck_id: 'deck-psychology', front: 'Bipolar Disorder', back: 'Characterized by cycles of depressive episodes and manic episodes (elevated mood, increased energy, reduced need for sleep, impulsive behavior). Bipolar I involves full mania; Bipolar II involves hypomania.', sort_order: 60 , front_translations: {"es":"Transtorno Bipolar","de":"Bipolare Störung","fr":"Trouble bipolaire","tr":"Bipolar Bozukluk","nl":"Bipolaire stoornis","ru":"Биполярное расстройство","zh":"双相情感障碍","pt_BR":"Transtorno Bipolar","pt_PT":"Perturbação Bipolar"}, back_translations: {"es":"Caracterizado por ciclos de episódios depressivos y episódios maníacos (humor elevado, aumento de energía, necesidad reduzida de sono, comportamiento impulsivo). El Bipolar I involucra mania plena; el Bipolar II involucra hipomania.","de":"Gekennzeichnet durch Zyklen aus depressiven Episoden und manischen Episoden (gehobene Stimmung, erhöhte Energie, vermindertes Schlafbedürfnis, impulsives Verhalten). Bipolar I beinhaltet vollständige Manie; Bipolar II Hypomanie.","fr":"Caractérisé par des cycles d'épisodes dépressifs et d'épisodes maniaques (humeur élevée, énergie accrue, besoin de sommeil réduit, comportement impulsif). Le trouble bipolaire I implique une manie complète ; le II implique une hypomanie.","tr":"Depresif epizodlar ve manik epizodlar (yüksek ruh hali, artmış enerji, azalmış uyku ihtiyacı, dürtüsel davranış) döngüleri ile karakterizedir. Bipolar I tam maniyi içerir; Bipolar II hipomaniyi içerir.","nl":"Gekenmerkt door cycli van depressieve episoden en manische episoden (verhoogde stemming, meer energie, verminderde slaapbehoefte, impulsief gedrag). Bipolair I omvat volledige manie; bipolair II omvat hypomanie.","ru":"Характеризуется чередованием депрессивных и маниакальных эпизодов (приподнятое настроение, повышенная энергия, сниженная потребность во сне, импульсивное поведение). Биполярное расстройство I включает полную манию; II — гипоманию.","zh":"以抑郁发作和躁狂发作（情绪高涨、精力增加、睡眠需求减少、冲动行为）的循环为特征。双相I型涉及完全躁狂；双相II型涉及轻躁狂。","pt_BR":"Caracterizado por ciclos de episódios depressivos e episódios maníacos (humor elevado, aumento de energia, necessidade reduzida de sono, comportamento impulsivo). O Bipolar I envolve mania plena; o Bipolar II envolve hipomania.","pt_PT":"Caracterizado por ciclos de episódios depressivos e episódios maníacos (humor elevado, aumento de energia, necessidade reduzida de sono, comportamento impulsivo). O Bipolar I envolve mania plena; o Bipolar II envolve hipomania."}},
  { id: 'dc-psychology-0061', deck_id: 'deck-psychology', front: 'Generalized Anxiety Disorder (GAD)', back: 'Characterized by excessive, difficult-to-control worry about multiple domains of life, accompanied by physical symptoms like muscle tension and sleep disturbance, lasting at least six months.', sort_order: 61 , front_translations: {"es":"Transtorno de Ansiedad Generalizada (TAG)","de":"Generalisierte Angststörung (GAS)","fr":"Trouble anxieux généralisé (TAG)","tr":"Yaygın Anksiyete Bozukluğu (YAB)","nl":"Gegeneraliseerde angststoornis (GAS)","ru":"Генерализованное тревожное расстройство (ГТР)","zh":"广泛性焦虑障碍（GAD）","pt_BR":"Transtorno de Ansiedade Generalizada (TAG)","pt_PT":"Perturbação de Ansiedade Generalizada (PAG)"}, back_translations: {"es":"Caracterizado por preocupación excessiva y difícil de controlar sobre múltiplos domínios de la vida, acompanhada de síntomas físicos como tensão muscular y distúrbios del sono, con duración mínima de seis meses.","de":"Gekennzeichnet durch übermäßige, schwer kontrollierbare Sorgen über mehrere Lebensbereiche, begleitet von körperlichen Symptomen wie Muskelverspannungen und Schlafstörungen, die mindestens sechs Monate andauern.","fr":"Caractérisé par une inquiétude excessive et difficile à contrôler concernant de multiples domaines de la vie, accompagnée de symptômes physiques tels que des tensions musculaires et des troubles du sommeil, durant au moins six mois.","tr":"Kas gerginliği ve uyku bozukluğu gibi fiziksel semptomlarla birlikte, birden fazla yaşam alanı hakkında en az altı ay süren aşırı, kontrol edilmesi güç kaygı ile karakterizedir.","nl":"Gekenmerkt door overmatige, moeilijk te beheersen bezorgdheid over meerdere levensgebieden, vergezeld van lichamelijke symptomen zoals spierspanning en slaapproblemen, gedurende minstens zes maanden.","ru":"Характеризуется чрезмерным, трудно поддающимся контролю беспокойством по многим сферам жизни, сопровождаемым физическими симптомами, такими как мышечное напряжение и нарушения сна, длящимися не менее шести месяцев.","zh":"以对生活多个领域的过度、难以控制的担忧为特征，伴有肌肉紧张和睡眠障碍等躯体症状，持续至少六个月。","pt_BR":"Caracterizado por preocupação excessiva e difícil de controlar sobre múltiplos domínios da vida, acompanhada de sintomas físicos como tensão muscular e distúrbios do sono, com duração mínima de seis meses.","pt_PT":"Caracterizado por preocupação excessiva e difícil de controlar sobre múltiplos domínios da vida, acompanhada de sintomas físicos como tensão muscular e perturbações do sono, com duração mínima de seis meses."}},
  { id: 'dc-psychology-0062', deck_id: 'deck-psychology', front: 'Panic Disorder', back: 'Characterized by recurrent unexpected panic attacks (intense fear with physical symptoms: racing heart, shortness of breath, dizziness) and persistent concern about future attacks.', sort_order: 62 , front_translations: {"es":"Transtorno del Panico","de":"Panikstörung","fr":"Trouble panique","tr":"Panik Bozukluğu","nl":"Paniekstoornis","ru":"Паническое расстройство","zh":"惊恐障碍","pt_BR":"Transtorno do Pânico","pt_PT":"Perturbação de Pânico"}, back_translations: {"es":"Caracterizado por ataques de panico recorrentes y inesperados (medo intenso con síntomas físicos: corazón acelerado, falta de aire, tontura) y preocupación persistente con futuros ataques.","de":"Gekennzeichnet durch wiederkehrende unerwartete Panikattacken (intensive Angst mit körperlichen Symptomen: Herzrasen, Kurzatmigkeit, Schwindel) und anhaltende Besorgnis über zukünftige Attacken.","fr":"Caractérisé par des attaques de panique récurrentes et inattendues (peur intense avec symptômes physiques : cœur qui bat vite, essoufflement, vertiges) et une inquiétude persistante concernant de futures attaques.","tr":"Yineleyen beklenmedik panik atakları (yoğun korku ve fiziksel semptomlar: çarpıntı, nefes darlığı, baş dönmesi) ve gelecekteki ataklara ilişkin kalıcı kaygı ile karakterizedir.","nl":"Gekenmerkt door terugkerende onverwachte paniekaanvallen (intense angst met lichamelijke symptomen: bonkend hart, kortademigheid, duizeligheid) en aanhoudende bezorgdheid over toekomstige aanvallen.","ru":"Характеризуется повторяющимися неожиданными паническими атаками (интенсивный страх с физическими симптомами: учащённое сердцебиение, одышка, головокружение) и устойчивой тревогой по поводу будущих атак.","zh":"以反复发生的意外惊恐发作（强烈恐惧伴躯体症状：心跳加速、气短、头晕）以及对未来发作的持续担忧为特征。","pt_BR":"Caracterizado por ataques de pânico recorrentes e inesperados (medo intenso com sintomas físicos: coração acelerado, falta de ar, tontura) e preocupação persistente com futuros ataques.","pt_PT":"Caracterizado por ataques de pânico recorrentes e inesperados (medo intenso com sintomas físicos: coração acelerado, falta de ar, tonturas) e preocupação persistente com futuros ataques."}},
  { id: 'dc-psychology-0063', deck_id: 'deck-psychology', front: 'Social Anxiety Disorder', back: 'Intense fear of social situations due to worry about being embarrassed or negatively evaluated by others; it can significantly impair daily functioning.', sort_order: 63 , front_translations: {"es":"Transtorno de Ansiedad Social","de":"Soziale Angststörung","fr":"Trouble anxieux social","tr":"Sosyal Anksiyete Bozukluğu","nl":"Sociale angststoornis","ru":"Социальное тревожное расстройство","zh":"社交焦虑障碍","pt_BR":"Transtorno de Ansiedade Social","pt_PT":"Perturbação de Ansiedade Social"}, back_translations: {"es":"Medo intenso de situaciones sociais debido a la preocupación con a posibilidad de ser embaraçado o avaliado negativamente por los outros; puede prejudicar significativamente el funcionamento diário.","de":"Intensive Angst vor sozialen Situationen aufgrund der Befürchtung, von anderen in Verlegenheit gebracht oder negativ bewertet zu werden; kann das tägliche Funktionieren erheblich beeinträchtigen.","fr":"Peur intense des situations sociales due à la crainte d'être embarrassé ou évalué négativement par les autres ; peut nuire considérablement au fonctionnement quotidien.","tr":"Başkaları tarafından utandırılma veya olumsuz değerlendirilme kaygısı nedeniyle sosyal durumlardan duyulan yoğun korku; günlük işlevselliği önemli ölçüde bozabilir.","nl":"Intense angst voor sociale situaties vanwege zorgen over in verlegenheid worden gebracht of negatief beoordeeld worden door anderen; kan het dagelijks functioneren aanzienlijk belemmeren.","ru":"Интенсивный страх перед социальными ситуациями из-за боязни быть опозоренным или негативно оценённым другими; может существенно нарушать повседневное функционирование.","zh":"因担心在他人面前出丑或受到负面评价而对社交场合产生强烈恐惧；可显著损害日常功能。","pt_BR":"Medo intenso de situações sociais devido à preocupação com a possibilidade de ser embaraçado ou avaliado negativamente pelos outros; pode prejudicar significativamente o funcionamento diário.","pt_PT":"Medo intenso de situações sociais devido à preocupação com a possibilidade de ser embaraçado ou avaliado negativamente pelos outros; pode prejudicar significativamente o funcionamento diário."}},
  { id: 'dc-psychology-0064', deck_id: 'deck-psychology', front: 'Phobia', back: 'An intense, irrational fear of a specific object or situation (e.g., spiders, heights, flying) that leads to avoidance and significant distress; treated effectively with exposure therapy.', sort_order: 64 , front_translations: {"es":"Fobia","de":"Phobie","fr":"Phobie","tr":"Fobi","nl":"Fobie","ru":"Фобия","zh":"恐惧症","pt_BR":"Fobia","pt_PT":"Fobia"}, back_translations: {"es":"Medo intenso y irracional de un objeto o situación específica (ex.: aranhas, alturas, voar) que leva a la evitación y sofrimento significativo; tratada de forma eficaz con terapia de exposición.","de":"Eine intensive, irrationale Angst vor einem bestimmten Objekt oder einer Situation (z. B. Spinnen, Höhen, Fliegen), die zu Vermeidung und erheblichem Leidensdruck führt; wirksam mit Expositionstherapie behandelbar.","fr":"Une peur intense et irrationnelle d'un objet ou d'une situation spécifique (ex. araignées, hauteurs, avion) qui conduit à l'évitement et à une détresse significative ; traitée efficacement par la thérapie d'exposition.","tr":"Kaçınmaya ve önemli sıkıntıya yol açan belirli bir nesne veya duruma (örn. örümcekler, yükseklikler, uçmak) karşı yoğun, irrasyonel korku; maruz bırakma terapisiyle etkili biçimde tedavi edilir.","nl":"Een intense, irrationele angst voor een specifiek object of situatie (bijv. spinnen, hoogten, vliegen) die leidt tot vermijding en aanzienlijk lijden; effectief behandeld met exposure-therapie.","ru":"Интенсивный, иррациональный страх перед определённым объектом или ситуацией (например, пауки, высота, полёты), приводящий к избеганию и значительному дистрессу; эффективно лечится экспозиционной терапией.","zh":"对特定物体或情境（如蜘蛛、高处、飞行）的强烈、非理性恐惧，导致回避和显著痛苦；暴露疗法治疗效果显著。","pt_BR":"Medo intenso e irracional de um objeto ou situação específica (ex.: aranhas, alturas, voar) que leva à evitação e sofrimento significativo; tratada de forma eficaz com terapia de exposição.","pt_PT":"Medo intenso e irracional de um objeto ou situação específica (ex.: aranhas, alturas, voar) que leva à evitação e sofrimento significativo; tratada de forma eficaz com terapia de exposição."}},
  { id: 'dc-psychology-0065', deck_id: 'deck-psychology', front: 'Post-Traumatic Stress Disorder (PTSD)', back: 'Develops after exposure to a traumatic event; characterized by intrusive memories (flashbacks), avoidance of trauma reminders, negative cognitions, and hyperarousal lasting more than one month.', sort_order: 65 , front_translations: {"es":"Transtorno de Estresse Pós-Traumático (TEPT)","de":"Posttraumatische Belastungsstörung (PTBS)","fr":"Trouble de stress post-traumatique (TSPT)","tr":"Travma Sonrası Stres Bozukluğu (TSSB)","nl":"Posttraumatische stressstoornis (PTSS)","ru":"Посттравматическое стрессовое расстройство (ПТСР)","zh":"创伤后应激障碍（PTSD）","pt_BR":"Transtorno de Estresse Pós-Traumático (TEPT)","pt_PT":"Perturbação de Stress Pós-Traumático (PSPT)"}, back_translations: {"es":"Se desarrolla após a exposición a un evento traumático; caracterizado por memorias intrusivas (flashbacks), evitación de lembretes del trauma, cogniciones negativas y hiperexcitación con duración superior a un mes.","de":"Entwickelt sich nach der Exposition gegenüber einem traumatischen Ereignis; gekennzeichnet durch aufdringliche Erinnerungen (Flashbacks), Vermeidung von Trauma-Auslösern, negative Kognitionen und Hyperarousal, das länger als einen Monat andauert.","fr":"Se développe après l'exposition à un événement traumatique ; caractérisé par des souvenirs intrusifs (flashbacks), l'évitement des rappels du trauma, des cognitions négatives et une hypervigilance durant plus d'un mois.","tr":"Travmatik bir olaya maruz kaldıktan sonra gelişir; bir aydan uzun süren saldırgan anılar (geri dönüşler), travma hatırlatıcılarından kaçınma, olumsuz bilişler ve aşırı uyarılma ile karakterizedir.","nl":"Ontwikkelt zich na blootstelling aan een traumatische gebeurtenis; gekenmerkt door opdringerige herinneringen (flashbacks), vermijding van trauma-herinneringen, negatieve cognities en hyperarousal die langer dan een maand aanhouden.","ru":"Развивается после воздействия травматического события; характеризуется навязчивыми воспоминаниями (флэшбэки), избеганием напоминаний о травме, негативными когнициями и гипервозбудимостью, длящимися более одного месяца.","zh":"在经历创伤事件后发展而来；以侵入性记忆（闪回）、回避创伤相关线索、负性认知和超警觉状态为特征，持续超过一个月。","pt_BR":"Desenvolve-se após a exposição a um evento traumático; caracterizado por memórias intrusivas (flashbacks), evitação de lembretes do trauma, cognições negativas e hiperexcitação com duração superior a um mês.","pt_PT":"Desenvolve-se após a exposição a um evento traumático; caracterizado por memórias intrusivas (flashbacks), evitação de recordações do trauma, cognições negativas e hiperexcitação com duração superior a um mês."}},
  { id: 'dc-psychology-0066', deck_id: 'deck-psychology', front: 'Obsessive-Compulsive Disorder (OCD)', back: 'Characterized by intrusive obsessive thoughts that cause distress and compulsive repetitive behaviors performed to reduce anxiety; the compulsions provide temporary relief but maintain the cycle.', sort_order: 66 , front_translations: {"es":"Transtorno Obsessivo-Compulsivo (TOC)","de":"Zwangsstörung (OCD)","fr":"Trouble obsessionnel-compulsif (TOC)","tr":"Obsesif-Kompulsif Bozukluk (OKB)","nl":"Obsessief-compulsieve stoornis (OCS)","ru":"Обсессивно-компульсивное расстройство (ОКР)","zh":"强迫症（OCD）","pt_BR":"Transtorno Obsessivo-Compulsivo (TOC)","pt_PT":"Perturbação Obsessivo-Compulsiva (POC)"}, back_translations: {"es":"Caracterizado por pensamientos obsessivos intrusivos que causan sofrimento y comportamientos compulsivos repetitivos realizados para reduzir a ansiedad; las compulsões proporcionam alívio temporário, pero mantem el ciclo.","de":"Gekennzeichnet durch aufdringliche Zwangsgedanken, die Leidensdruck verursachen, und zwanghafte Wiederholungshandlungen zur Angstreduktion; die Zwangshandlungen bieten vorübergehende Erleichterung, erhalten aber den Kreislauf aufrecht.","fr":"Caractérisé par des pensées obsessionnelles intrusives qui causent de la détresse et des comportements compulsifs répétitifs effectués pour réduire l'anxiété ; les compulsions apportent un soulagement temporaire mais maintiennent le cycle.","tr":"Sıkıntıya neden olan saldırgan obsesif düşünceler ve anksiyeteyi azaltmak için gerçekleştirilen kompulsif tekrarlayan davranışlarla karakterizedir; kompulsiyonlar geçici bir rahatlama sağlar ancak döngüyü sürdürür.","nl":"Gekenmerkt door opdringerige obsessieve gedachten die leed veroorzaken en compulsief repetitief gedrag uitgevoerd om angst te verminderen; de compulsies bieden tijdelijke verlichting maar houden de cyclus in stand.","ru":"Характеризуется навязчивыми обсессивными мыслями, вызывающими дистресс, и компульсивными повторяющимися действиями, направленными на снижение тревоги; компульсии дают временное облегчение, но поддерживают цикл.","zh":"以引发痛苦的侵入性强迫观念和为减少焦虑而执行的强迫性重复行为为特征；强迫行为提供短暂缓解，但维持了恶性循环。","pt_BR":"Caracterizado por pensamentos obsessivos intrusivos que causam sofrimento e comportamentos compulsivos repetitivos realizados para reduzir a ansiedade; as compulsões proporcionam alívio temporário, mas mantêm o ciclo.","pt_PT":"Caracterizado por pensamentos obsessivos intrusivos que causam sofrimento e comportamentos compulsivos repetitivos realizados para reduzir a ansiedade; as compulsões proporcionam alívio temporário, mas mantêm o ciclo."}},
  { id: 'dc-psychology-0067', deck_id: 'deck-psychology', front: 'Schizophrenia', back: 'A severe psychotic disorder characterized by positive symptoms (hallucinations, delusions, disorganized thinking) and negative symptoms (flat affect, avolition, social withdrawal).', sort_order: 67 , front_translations: {"es":"Esquizofrenia","de":"Schizophrenie","fr":"Schizophrénie","tr":"Şizofreni","nl":"Schizofrenie","ru":"Шизофрения","zh":"精神分裂症","pt_BR":"Esquizofrenia","pt_PT":"Esquizofrenia"}, back_translations: {"es":"Un trastorno psicótico grave caracterizado por síntomas positivos (alucinaciones, delírios, pensamiento desorganizado) y síntomas negativos (afeto embotado, avolia, retraimento social).","de":"Eine schwere psychotische Störung, die durch positive Symptome (Halluzinationen, Wahnvorstellungen, desorganisiertes Denken) und negative Symptome (flacher Affekt, Antriebslosigkeit, sozialer Rückzug) gekennzeichnet ist.","fr":"Un trouble psychotique grave caractérisé par des symptômes positifs (hallucinations, délires, pensée désorganisée) et des symptômes négatifs (affect plat, avolition, retrait social).","tr":"Pozitif semptomlar (halüsinasyonlar, sanrılar, dezorganize düşünce) ve negatif semptomlar (düzleşmiş duygulanım, avolisyon, sosyal çekilme) ile karakterize ağır bir psikotik bozukluk.","nl":"Een ernstige psychotische stoornis gekenmerkt door positieve symptomen (hallucinaties, wanen, gedesorganiseerd denken) en negatieve symptomen (afgevlakt affect, avolitie, sociale terugtrekking).","ru":"Тяжёлое психотическое расстройство, характеризующееся позитивными симптомами (галлюцинации, бред, дезорганизованное мышление) и негативными симптомами (уплощённый аффект, абулия, социальная изоляция).","zh":"一种严重的精神病性障碍，以阳性症状（幻觉、妄想、思维紊乱）和阴性症状（情感平淡、意志缺乏、社交退缩）为特征。","pt_BR":"Um transtorno psicótico grave caracterizado por sintomas positivos (alucinações, delírios, pensamento desorganizado) e sintomas negativos (afeto embotado, avolia, retraimento social).","pt_PT":"Uma perturbação psicótica grave caracterizada por sintomas positivos (alucinações, delírios, pensamento desorganizado) e sintomas negativos (afeto embotado, avolia, retraimento social)."}},
  { id: 'dc-psychology-0068', deck_id: 'deck-psychology', front: 'Hallucination', back: 'A perception experienced in the absence of an external stimulus; most common in schizophrenia. Auditory hallucinations (hearing voices) are the most prevalent type.', sort_order: 68 , front_translations: {"es":"Alucinación","de":"Halluzination","fr":"Hallucination","tr":"Hallüsinasyon","nl":"Hallucinatie","ru":"Галлюцинация","zh":"幻觉","pt_BR":"Alucinação","pt_PT":"Alucinação"}, back_translations: {"es":"Una percepción vivenciada en la ausencia de un estímulo externo; más comum en la esquizofrenia. As alucinaciones auditivas (ouvir vozes) son el tipo más prevalente.","de":"Eine Wahrnehmung, die ohne externen Stimulus erlebt wird; am häufigsten bei Schizophrenie. Auditive Halluzinationen (Stimmen hören) sind die am weitesten verbreitete Form.","fr":"Une perception vécue en l'absence d'un stimulus externe ; la plus courante dans la schizophrénie. Les hallucinations auditives (entendre des voix) sont le type le plus répandu.","tr":"Harici bir uyaran olmaksızın yaşanan bir algı; en yaygın olarak şizofrenide görülür. İşitsel halüsinasyonlar (sesler duymak) en yaygın türdür.","nl":"Een waarneming die wordt ervaren zonder een externe stimulus; het meest voorkomend bij schizofrenie. Auditieve hallucinaties (stemmen horen) zijn het meest voorkomende type.","ru":"Восприятие, переживаемое в отсутствие внешнего стимула; наиболее характерно для шизофрении. Слуховые галлюцинации (слышание голосов) являются наиболее распространённым типом.","zh":"在没有外部刺激的情况下体验到的知觉；在精神分裂症中最为常见。听幻觉（听到声音）是最普遍的类型。","pt_BR":"Uma percepção vivenciada na ausência de um estímulo externo; mais comum na esquizofrenia. As alucinações auditivas (ouvir vozes) são o tipo mais prevalente.","pt_PT":"Uma perceção vivenciada na ausência de um estímulo externo; mais comum na esquizofrenia. As alucinações auditivas (ouvir vozes) são o tipo mais prevalente."}},
  { id: 'dc-psychology-0069', deck_id: 'deck-psychology', front: 'Delusion', back: 'A fixed false belief held with strong conviction despite evidence to the contrary; common in schizophrenia. Types include persecutory, grandiose, and referential delusions.', sort_order: 69 , front_translations: {"es":"Delírio","de":"Wahn","fr":"Délire","tr":"Sanrı","nl":"Waan","ru":"Бред","zh":"妄想","pt_BR":"Delírio","pt_PT":"Delírio"}, back_translations: {"es":"Una creencia falsa y fixa mantida con fuerte convicción apesar de evidencias en contrário; comum en la esquizofrenia. Los tipos incluyen delírios persecutórios, grandiosos y referenciais.","de":"Ein fester falscher Glaube, der trotz gegenteiliger Beweise mit starker Überzeugung aufrechterhalten wird; häufig bei Schizophrenie. Zu den Typen gehören Verfolgungs-, Größen- und Beziehungswahn.","fr":"Une fausse croyance fixe maintenue avec une forte conviction malgré les preuves contraires ; courante dans la schizophrénie. Les types comprennent les délires de persécution, de grandeur et de référence.","tr":"Aksini gösteren kanıtlara rağmen güçlü bir inanç ile sürdürülen sabit, yanlış inanç; şizofrenide yaygındır. Türleri arasında persekütör, grandiyöz ve referans sanrıları yer alır.","nl":"Een vaste valse overtuiging die met sterke overtuiging wordt volgehouden ondanks tegenstrijdig bewijs; veelvoorkomend bij schizofrenie. Typen zijn vervolgingswanen, grootheidsidealen en betrekkingswanen.","ru":"Стойкое ложное убеждение, удерживаемое с сильной убеждённостью вопреки свидетельствам обратного; характерно для шизофрении. Типы включают персекуторный, величия и референторный бред.","zh":"尽管有相反证据，仍坚信的固定错误信念；在精神分裂症中很常见。类型包括被害妄想、夸大妄想和关系妄想。","pt_BR":"Uma crença falsa e fixa mantida com forte convicção apesar de evidências em contrário; comum na esquizofrenia. Os tipos incluem delírios persecutórios, grandiosos e referenciais.","pt_PT":"Uma crença falsa e fixa mantida com forte convicção apesar de evidências em contrário; comum na esquizofrenia. Os tipos incluem delírios persecutórios, grandiosos e referenciais."}},
  { id: 'dc-psychology-0070', deck_id: 'deck-psychology', front: 'Autism Spectrum Disorder (ASD)', back: 'A neurodevelopmental disorder characterized by difficulties in social communication, restricted interests, and repetitive behaviors; it exists on a spectrum from mild to severe.', sort_order: 70 , front_translations: {"es":"Transtorno del Espectro Autista (TEA)","de":"Autismus-Spektrum-Störung (ASS)","fr":"Trouble du spectre de l'autisme (TSA)","tr":"Otizm Spektrum Bozukluğu (OSB)","nl":"Autismespectrumstoornis (ASS)","ru":"Расстройство аутистического спектра (РАС)","zh":"自闭症谱系障碍（ASD）","pt_BR":"Transtorno do Espectro Autista (TEA)","pt_PT":"Perturbação do Espectro do Autismo (PEA)"}, back_translations: {"es":"Un trastorno del neurodesenvolvimento caracterizado por dificuldades en la comunicación social, interesses restritos y comportamientos repetitivos; existe en un espectro de ligero a grave.","de":"Eine neurologische Entwicklungsstörung, die durch Schwierigkeiten in der sozialen Kommunikation, eingeschränkte Interessen und repetitive Verhaltensweisen gekennzeichnet ist; sie besteht auf einem Spektrum von mild bis schwer.","fr":"Un trouble neurodéveloppemental caractérisé par des difficultés dans la communication sociale, des intérêts restreints et des comportements répétitifs ; il existe sur un spectre allant de léger à sévère.","tr":"Sosyal iletişimde güçlükler, kısıtlı ilgi alanları ve tekrarlayan davranışlarla karakterize nörogelişimsel bir bozukluk; hafiften ağıra uzanan bir spektrumda bulunur.","nl":"Een neurodevelopmentale stoornis gekenmerkt door moeilijkheden in sociale communicatie, beperkte interesses en repetitief gedrag; het bestaat op een spectrum van mild tot ernstig.","ru":"Нейродevelopmental расстройство, характеризующееся трудностями в социальном общении, ограниченными интересами и повторяющимся поведением; существует в виде спектра от лёгкой до тяжёлой степени.","zh":"一种神经发育障碍，以社交沟通困难、兴趣狭窄和重复行为为特征；存在从轻度到重度的谱系。","pt_BR":"Um transtorno do neurodesenvolvimento caracterizado por dificuldades na comunicação social, interesses restritos e comportamentos repetitivos; existe em um espectro de leve a grave.","pt_PT":"Uma perturbação do neurodesenvolvimento caracterizada por dificuldades na comunicação social, interesses restritos e comportamentos repetitivos; existe num espectro de ligeiro a grave."}},
  { id: 'dc-psychology-0071', deck_id: 'deck-psychology', front: 'Attention-Deficit/Hyperactivity Disorder (ADHD)', back: 'A neurodevelopmental disorder characterized by inattention, hyperactivity, and impulsivity that interferes with functioning; often persists into adulthood.', sort_order: 71 , front_translations: {"es":"Transtorno del Déficit de Atención con Hiperatividad (TDAH)","de":"Aufmerksamkeitsdefizit-Hyperaktivitätsstörung (ADHS)","fr":"Trouble déficit de l'attention avec hyperactivité (TDAH)","tr":"Dikkat Eksikliği/Hiperaktivite Bozukluğu (DEHB)","nl":"Aandachtstekortstoornis met hyperactiviteit (ADHD)","ru":"Синдром дефицита внимания и гиперактивности (СДВГ)","zh":"注意缺陷多动障碍（ADHD）","pt_BR":"Transtorno do Déficit de Atenção com Hiperatividade (TDAH)","pt_PT":"Perturbação de Hiperatividade e Défice de Atenção (PHDA)"}, back_translations: {"es":"Un trastorno del neurodesenvolvimento caracterizado por desatención, hiperatividad y impulsividad que interferem en el funcionamento; frecuentemente persiste en la vida adulta.","de":"Eine neurologische Entwicklungsstörung, die durch Unaufmerksamkeit, Hyperaktivität und Impulsivität gekennzeichnet ist, die das Funktionieren beeinträchtigen; hält oft bis ins Erwachsenenalter an.","fr":"Un trouble neurodéveloppemental caractérisé par l'inattention, l'hyperactivité et l'impulsivité qui interfèrent avec le fonctionnement ; persiste souvent à l'âge adulte.","tr":"İşlevselliği bozan dikkatsizlik, aşırı hareketlilik ve dürtüsellik ile karakterize nörogelişimsel bir bozukluk; genellikle yetişkinliğe kadar devam eder.","nl":"Een neurodevelopmentale stoornis gekenmerkt door onoplettendheid, hyperactiviteit en impulsiviteit die het functioneren belemmeren; blijft vaak voortbestaan tot in de volwassenheid.","ru":"Нейроразвивающее расстройство, характеризующееся невнимательностью, гиперактивностью и импульсивностью, нарушающими функционирование; нередко сохраняется во взрослом возрасте.","zh":"一种神经发育障碍，以影响功能的注意力不集中、多动和冲动为特征；通常持续到成年。","pt_BR":"Um transtorno do neurodesenvolvimento caracterizado por desatenção, hiperatividade e impulsividade que interferem no funcionamento; frequentemente persiste na vida adulta.","pt_PT":"Uma perturbação do neurodesenvolvimento caracterizada por desatenção, hiperatividade e impulsividade que interferem com o funcionamento; frequentemente persiste na vida adulta."}},
  { id: 'dc-psychology-0072', deck_id: 'deck-psychology', front: 'Borderline Personality Disorder (BPD)', back: 'A personality disorder marked by emotional instability, fear of abandonment, impulsive behavior, unstable relationships, and a distorted self-image.', sort_order: 72 , front_translations: {"es":"Transtorno de Personalidad Borderline (TPB)","de":"Borderline-Persönlichkeitsstörung (BPS)","fr":"Trouble de la personnalité borderline (TPB)","tr":"Sınır Kişilik Bozukluğu (SKB)","nl":"Borderline persoonlijkheidsstoornis (BPS)","ru":"Пограничное расстройство личности (ПРЛ)","zh":"边缘型人格障碍（BPD）","pt_BR":"Transtorno de Personalidade Borderline (TPB)","pt_PT":"Perturbação de Personalidade Borderline (PPB)"}, back_translations: {"es":"Un trastorno de personalidad marcado por instabilidad emocional, medo del abandono, comportamiento impulsivo, relacionamentos instables y una autoimaje distorcida.","de":"Eine Persönlichkeitsstörung, die durch emotionale Instabilität, Verlustangst, impulsives Verhalten, instabile Beziehungen und ein verzerrtes Selbstbild gekennzeichnet ist.","fr":"Un trouble de la personnalité marqué par l'instabilité émotionnelle, la peur de l'abandon, les comportements impulsifs, les relations instables et une image de soi déformée.","tr":"Duygusal dengesizlik, terk edilme korkusu, dürtüsel davranış, istikrarsız ilişkiler ve çarpıtılmış bir öz-imge ile belirgin kişilik bozukluğu.","nl":"Een persoonlijkheidsstoornis gekenmerkt door emotionele instabiliteit, angst voor verlating, impulsief gedrag, onstabiele relaties en een verstoord zelfbeeld.","ru":"Расстройство личности, отличающееся эмоциональной нестабильностью, страхом брошенности, импульсивным поведением, нестабильными отношениями и искажённым образом «я».","zh":"一种人格障碍，以情绪不稳定、害怕被抛弃、冲动行为、不稳定的人际关系和扭曲的自我形象为特征。","pt_BR":"Um transtorno de personalidade marcado por instabilidade emocional, medo do abandono, comportamento impulsivo, relacionamentos instáveis e uma autoimagem distorcida.","pt_PT":"Uma perturbação de personalidade marcada por instabilidade emocional, medo do abandono, comportamento impulsivo, relações instáveis e uma autoimagem distorcida."}},
  { id: 'dc-psychology-0073', deck_id: 'deck-psychology', front: 'Narcissistic Personality Disorder', back: 'A personality disorder characterized by grandiosity, need for admiration, and lack of empathy; despite an inflated self-image, narcissists often have fragile self-esteem.', sort_order: 73 , front_translations: {"es":"Transtorno de Personalidad Narcisista","de":"Narzisstische Persönlichkeitsstörung","fr":"Trouble de la personnalité narcissique","tr":"Narsistik Kişilik Bozukluğu","nl":"Narcistische persoonlijkheidsstoornis","ru":"Нарциссическое расстройство личности","zh":"自恋型人格障碍","pt_BR":"Transtorno de Personalidade Narcisista","pt_PT":"Perturbação de Personalidade Narcísica"}, back_translations: {"es":"Un trastorno de personalidad caracterizado por grandiosidad, necesidad de admiración y falta de empatia; apesar de una autoimaje inflada, narcisistas frecuentemente tienen autoestima frágil.","de":"Eine Persönlichkeitsstörung, die durch Grandiosität, Bewunderungsbedürfnis und mangelnde Empathie gekennzeichnet ist; trotz eines aufgeblähten Selbstbildes haben Narzissten oft ein fragiles Selbstwertgefühl.","fr":"Un trouble de la personnalité caractérisé par la grandiosité, le besoin d'admiration et le manque d'empathie ; malgré une image de soi exagérée, les narcissiques ont souvent une estime de soi fragile.","tr":"Grandiözite, hayranlık ihtiyacı ve empati eksikliği ile karakterize kişilik bozukluğu; şişirilmiş bir öz-imgeye rağmen narsistler genellikle kırılgan bir öz-saygıya sahiptir.","nl":"Een persoonlijkheidsstoornis gekenmerkt door grandiositeit, behoefte aan bewondering en gebrek aan empathie; ondanks een opgeblazen zelfbeeld hebben narcisten vaak een fragiel zelfgevoel.","ru":"Расстройство личности, характеризующееся грандиозностью, потребностью в восхищении и недостатком эмпатии; несмотря на завышенный образ «я», нарциссы нередко имеют хрупкую самооценку.","zh":"一种以自大、渴求赞美和缺乏共情为特征的人格障碍；尽管自我形象膨胀，自恋者往往有脆弱的自尊。","pt_BR":"Um transtorno de personalidade caracterizado por grandiosidade, necessidade de admiração e falta de empatia; apesar de uma autoimagem inflada, narcisistas frequentemente têm autoestima frágil.","pt_PT":"Uma perturbação de personalidade caracterizada por grandiosidade, necessidade de admiração e falta de empatia; apesar de uma autoimagem inflada, os narcisistas têm frequentemente uma autoestima frágil."}},
  { id: 'dc-psychology-0074', deck_id: 'deck-psychology', front: 'Cognitive-Behavioral Therapy (CBT)', back: 'A psychotherapy that identifies and modifies maladaptive thoughts (cognitive) and behaviors; highly evidence-based for depression, anxiety, and many other disorders.', sort_order: 74 , front_translations: {"es":"Terapia Cognitivo-Comportamental (TCC)","de":"Kognitive Verhaltenstherapie (KVT)","fr":"Thérapie cognitive et comportementale (TCC)","tr":"Bilişsel Davranışçı Terapi (BDT)","nl":"Cognitieve gedragstherapie (CGT)","ru":"Когнитивно-поведенческая терапия (КПТ)","zh":"认知行为疗法（CBT）","pt_BR":"Terapia Cognitivo-Comportamental (TCC)","pt_PT":"Terapia Cognitivo-Comportamental (TCC)"}, back_translations: {"es":"Una psicoterapia que identifica y modifica pensamientos (cognitivos) y comportamientos mal-adaptativos; altamente basada en evidencias para depresión, ansiedad y muchos outros trastornos.","de":"Eine Psychotherapie, die maladaptive Gedanken (kognitiv) und Verhaltensweisen identifiziert und modifiziert; stark evidenzbasiert für Depression, Angst und viele andere Störungen.","fr":"Une psychothérapie qui identifie et modifie les pensées inadaptées (cognitives) et les comportements ; très bien fondée sur des preuves pour la dépression, l'anxiété et de nombreux autres troubles.","tr":"Uyumsuz düşünceleri (bilişsel) ve davranışları tanımlayan ve değiştiren bir psikoterapi; depresyon, anksiyete ve diğer birçok bozukluk için yüksek kanıt temeline sahiptir.","nl":"Een psychotherapie die maladaptieve gedachten (cognitief) en gedragingen identificeert en wijzigt; sterk evidence-based voor depressie, angst en vele andere stoornissen.","ru":"Психотерапия, выявляющая и изменяющая дезадаптивные мысли (когнитивные) и поведение; имеет высокую доказательную базу при депрессии, тревоге и многих других расстройствах.","zh":"一种识别和修正适应不良的思维（认知）和行为的心理疗法；对抑郁症、焦虑症及许多其他障碍具有强大的循证支持。","pt_BR":"Uma psicoterapia que identifica e modifica pensamentos (cognitivos) e comportamentos mal-adaptativos; altamente baseada em evidências para depressão, ansiedade e muitos outros transtornos.","pt_PT":"Uma psicoterapia que identifica e modifica pensamentos (cognitivos) e comportamentos mal-adaptativos; altamente baseada em evidências para depressão, ansiedade e muitas outras perturbações."}},
  { id: 'dc-psychology-0075', deck_id: 'deck-psychology', front: 'Exposure Therapy', back: 'A behavioral technique that systematically exposes patients to feared stimuli (in vivo or imaginal) to reduce avoidance and extinguish fear responses; first-line treatment for phobias and PTSD.', sort_order: 75 , front_translations: {"es":"Terapia de Exposición","de":"Expositionstherapie","fr":"Thérapie par exposition","tr":"Maruz Bırakma Terapisi","nl":"Exposure-therapie","ru":"Экспозиционная терапия","zh":"暴露疗法","pt_BR":"Terapia de Exposição","pt_PT":"Terapia de Exposição"}, back_translations: {"es":"Una técnica comportamental que expõe sistematicamente los pacientes a estímulos temidos (in vivo o imaginário) para reduzir a evitación y extinguir las respuestas de medo; tratamiento de primera línea para fobias y TEPT.","de":"Eine Verhaltenstechnik, die Patienten systematisch gefürchteten Reizen aussetzt (in vivo oder imaginär), um Vermeidung abzubauen und Angstreaktionen zu löschen; Erstlinienbehandlung für Phobien und PTBS.","fr":"Une technique comportementale qui expose systématiquement les patients à des stimuli redoutés (in vivo ou imaginaires) pour réduire l'évitement et éteindre les réponses de peur ; traitement de première intention pour les phobies et le TSPT.","tr":"Kaçınmayı azaltmak ve korku tepkilerini söndürmek için hastaları sistematik olarak korkulan uyaranlara (in vivo veya hayali) maruz bırakan davranışsal bir teknik; fobiler ve TSSB için birinci basamak tedavidir.","nl":"Een gedragstechniek die patiënten systematisch blootstelt aan gevreesde stimuli (in vivo of in verbeelding) om vermijding te verminderen en angstreacties te doven; eerstelijnsbehandeling voor fobieën en PTSS.","ru":"Поведенческая техника, систематически подвергающая пациентов воздействию пугающих стимулов (in vivo или воображаемых) для снижения избегания и угасания страха; терапия первой линии при фобиях и ПТСР.","zh":"一种行为技术，系统性地将患者暴露于所恐惧的刺激（现实或想象）中，以减少回避并消退恐惧反应；是治疗恐惧症和PTSD的一线疗法。","pt_BR":"Uma técnica comportamental que expõe sistematicamente os pacientes a estímulos temidos (in vivo ou imaginário) para reduzir a evitação e extinguir as respostas de medo; tratamento de primeira linha para fobias e TEPT.","pt_PT":"Uma técnica comportamental que expõe sistematicamente os pacientes a estímulos temidos (in vivo ou imaginário) para reduzir a evitação e extinguir as respostas de medo; tratamento de primeira linha para fobias e PSPT."}},
  { id: 'dc-psychology-0076', deck_id: 'deck-psychology', front: 'Systematic Desensitization', back: 'A behavior therapy developed by Wolpe combining relaxation training with gradual exposure to a hierarchy of anxiety-provoking stimuli; used to treat phobias and anxiety disorders.', sort_order: 76 , front_translations: {"es":"Dessensibilización Sistemática","de":"Systematische Desensibilisierung","fr":"Désensibilisation systématique","tr":"Sistematik Duyarsızlaştırma","nl":"Systematische desensitisatie","ru":"Систематическая десенсибилизация","zh":"系统脱敏法","pt_BR":"Dessensibilização Sistemática","pt_PT":"Dessensibilização Sistemática"}, back_translations: {"es":"Una terapia comportamental desarrollada por Wolpe que combina treinamento de relaxamento con exposición gradual a una hierarquia de estímulos provocadores de ansiedad; usada para tratar fobias y trastornos de ansiedad.","de":"Eine von Wolpe entwickelte Verhaltenstherapie, die Entspannungstraining mit schrittweiser Exposition gegenüber einer Hierarchie angstauslösender Reize kombiniert; zur Behandlung von Phobien und Angststörungen eingesetzt.","fr":"Une thérapie comportementale développée par Wolpe combinant l'entraînement à la relaxation avec une exposition progressive à une hiérarchie de stimuli anxiogènes ; utilisée pour traiter les phobies et les troubles anxieux.","tr":"Wolpe tarafından geliştirilen, gevşeme eğitimini anksiyete uyandıran uyaranların hiyerarşisine kademeli maruz bırakmayla birleştiren bir davranış terapisi; fobiler ve anksiyete bozukluklarını tedavi etmek için kullanılır.","nl":"Een gedragstherapie ontwikkeld door Wolpe die ontspanningstraining combineert met geleidelijke blootstelling aan een hiërarchie van angstopwekkende stimuli; gebruikt voor de behandeling van fobieën en angststoornissen.","ru":"Поведенческая терапия, разработанная Вольпе, сочетающая тренировку релаксации с постепенным воздействием иерархии тревожных стимулов; применяется для лечения фобий и тревожных расстройств.","zh":"由沃尔普开发的一种行为疗法，将放松训练与逐步暴露于焦虑诱发刺激的层级相结合；用于治疗恐惧症和焦虑障碍。","pt_BR":"Uma terapia comportamental desenvolvida por Wolpe que combina treinamento de relaxamento com exposição gradual a uma hierarquia de estímulos provocadores de ansiedade; usada para tratar fobias e transtornos de ansiedade.","pt_PT":"Uma terapia comportamental desenvolvida por Wolpe que combina treino de relaxamento com exposição gradual a uma hierarquia de estímulos provocadores de ansiedade; usada para tratar fobias e perturbações de ansiedade."}},
  { id: 'dc-psychology-0077', deck_id: 'deck-psychology', front: 'Dialectical Behavior Therapy (DBT)', back: 'An evidence-based therapy combining CBT with mindfulness and acceptance strategies; developed by Marsha Linehan, it is the primary treatment for Borderline Personality Disorder.', sort_order: 77 , front_translations: {"es":"Terapia Comportamental Dialética (TCD)","de":"Dialektisch-Behaviorale Therapie (DBT)","fr":"Thérapie comportementale dialectique (TCD)","tr":"Diyalektik Davranış Terapisi (DDT)","nl":"Dialectische gedragstherapie (DGT)","ru":"Диалектическая поведенческая терапия (ДПТ)","zh":"辩证行为疗法（DBT）","pt_BR":"Terapia Comportamental Dialética (TCD)","pt_PT":"Terapia Comportamental Dialética (TCD)"}, back_translations: {"es":"Una terapia basada en evidencias que combina TCC con estrategias de mindfulness y aceitación; desarrollada por Marsha Linehan, es el tratamiento primário para el Transtorno de Personalidad Borderline.","de":"Eine evidenzbasierte Therapie, die KVT mit Achtsamkeits- und Akzeptanzstrategien kombiniert; von Marsha Linehan entwickelt, ist sie die primäre Behandlung der Borderline-Persönlichkeitsstörung.","fr":"Une thérapie fondée sur les preuves combinant la TCC avec des stratégies de pleine conscience et d'acceptation ; développée par Marsha Linehan, c'est le traitement principal du trouble de la personnalité borderline.","tr":"KDT'yi farkındalık ve kabul stratejileriyle birleştiren kanıta dayalı bir terapi; Marsha Linehan tarafından geliştirilmiş olup Sınırda Kişilik Bozukluğu için birincil tedavidir.","nl":"Een evidence-based therapie die CGT combineert met mindfulness- en acceptatiestrategieën; ontwikkeld door Marsha Linehan, is het de primaire behandeling voor borderline-persoonlijkheidsstoornis.","ru":"Доказательная терапия, сочетающая КПТ со стратегиями осознанности и принятия; разработана Маршей Линехан и является основным методом лечения пограничного расстройства личности.","zh":"一种循证疗法，将认知行为疗法与正念和接纳策略相结合；由玛莎·林纳翰开发，是边缘型人格障碍的主要治疗方法。","pt_BR":"Uma terapia baseada em evidências que combina TCC com estratégias de mindfulness e aceitação; desenvolvida por Marsha Linehan, é o tratamento primário para o Transtorno de Personalidade Borderline.","pt_PT":"Uma terapia baseada em evidências que combina TCC com estratégias de mindfulness e aceitação; desenvolvida por Marsha Linehan, é o tratamento primário para a Perturbação de Personalidade Borderline."}},
  { id: 'dc-psychology-0078', deck_id: 'deck-psychology', front: 'Neurotransmitter', back: 'A chemical messenger released by neurons into the synapse to transmit signals to adjacent neurons or cells; examples include dopamine, serotonin, GABA, glutamate, and acetylcholine.', sort_order: 78 , front_translations: {"es":"Neurotransmissor","de":"Neurotransmitter","fr":"Neurotransmetteur","tr":"Nörotransmiter","nl":"Neurotransmitter","ru":"Нейромедиатор","zh":"神经递质","pt_BR":"Neurotransmissor","pt_PT":"Neurotransmissor"}, back_translations: {"es":"Un mensagero químico liberado por los neuronas en la sinapse para transmitir señales a neuronas o células adjacentes; ejemplos incluyen dopamina, serotonina, GABA, glutamato y acetilcolina.","de":"Ein chemischer Botenstoff, der von Neuronen in den Synapsenspalt freigesetzt wird, um Signale an benachbarte Neuronen oder Zellen zu übertragen; Beispiele sind Dopamin, Serotonin, GABA, Glutamat und Acetylcholin.","fr":"Un messager chimique libéré par les neurones dans la synapse pour transmettre des signaux aux neurones ou cellules adjacents ; les exemples incluent la dopamine, la sérotonine, le GABA, le glutamate et l'acétylcholine.","tr":"Nöronlar tarafından sinaptik aralığa salınan ve komşu nöronlara veya hücrelere sinyal ileten kimyasal haberci; örnekleri dopamin, serotonin, GABA, glutamat ve asetilkolindir.","nl":"Een chemische boodschapper die door neuronen in de synaps wordt vrijgegeven om signalen door te geven aan aangrenzende neuronen of cellen; voorbeelden zijn dopamine, serotonine, GABA, glutamaat en acetylcholine.","ru":"Химический посредник, выделяемый нейронами в синапс для передачи сигналов соседним нейронам или клеткам; примеры включают дофамин, серотонин, ГАМК, глутамат и ацетилхолин.","zh":"由神经元释放到突触中以向相邻神经元或细胞传递信号的化学信使；例如多巴胺、血清素、GABA、谷氨酸和乙酰胆碱。","pt_BR":"Um mensageiro químico liberado pelos neurônios na sinapse para transmitir sinais a neurônios ou células adjacentes; exemplos incluem dopamina, serotonina, GABA, glutamato e acetilcolina.","pt_PT":"Um mensageiro químico libertado pelos neurónios na sinapse para transmitir sinais a neurónios ou células adjacentes; exemplos incluem dopamina, serotonina, GABA, glutamato e acetilcolina."}},
  { id: 'dc-psychology-0079', deck_id: 'deck-psychology', front: 'Dopamine', back: 'A neurotransmitter involved in the brain\'s reward and motivation system; implicated in pleasure, reinforcement learning, motor control, and in disorders like Parkinson\'s disease and schizophrenia.', sort_order: 79 , front_translations: {"es":"Dopamina","de":"Dopamin","fr":"Dopamine","tr":"Dopamin","nl":"Dopamine","ru":"Дофамин","zh":"多巴胺","pt_BR":"Dopamina","pt_PT":"Dopamina"}, back_translations: {"es":"Un neurotransmissor involucrado en el sistema de recompensa y motivación del cerebro; implicado en el prazer, aprendizaje por refuerzo, controle motor y en trastornos como a enfermedad de Parkinson y a esquizofrenia.","de":"Ein Neurotransmitter, der am Belohnungs- und Motivationssystem des Gehirns beteiligt ist; er spielt eine Rolle bei Vergnügen, Verstärkungslernen, Motorik und bei Störungen wie Parkinson und Schizophrenie.","fr":"Un neurotransmetteur impliqué dans le système de récompense et de motivation du cerveau ; il joue un rôle dans le plaisir, l'apprentissage par renforcement, le contrôle moteur et dans des troubles comme la maladie de Parkinson et la schizophrénie.","tr":"Beynin ödül ve motivasyon sisteminde yer alan bir nörotransmiter; haz, pekiştirmeli öğrenme, motor kontrol ve Parkinson hastalığı ile şizofreni gibi bozukluklarda rol oynar.","nl":"Een neurotransmitter betrokken bij het belonings- en motivatiesysteem van de hersenen; betrokken bij plezier, versterkend leren, motorische controle en bij aandoeningen zoals de ziekte van Parkinson en schizofrenie.","ru":"Нейромедиатор, участвующий в системе вознаграждения и мотивации мозга; связан с удовольствием, обучением с подкреплением, моторным контролем и такими расстройствами, как болезнь Паркинсона и шизофрения.","zh":"一种参与大脑奖赏和动机系统的神经递质；与愉悦感、强化学习、运动控制以及帕金森病和精神分裂症等疾病有关。","pt_BR":"Um neurotransmissor envolvido no sistema de recompensa e motivação do cérebro; implicado no prazer, aprendizagem por reforço, controle motor e em transtornos como a doença de Parkinson e a esquizofrenia.","pt_PT":"Um neurotransmissor envolvido no sistema de recompensa e motivação do cérebro; implicado no prazer, aprendizagem por reforço, controlo motor e em perturbações como a doença de Parkinson e a esquizofrenia."}},
  { id: 'dc-psychology-0080', deck_id: 'deck-psychology', front: 'Serotonin', back: 'A neurotransmitter regulating mood, sleep, appetite, and impulse control; low levels are associated with depression. SSRIs increase serotonin availability and are first-line antidepressants.', sort_order: 80 , front_translations: {"es":"Serotonina","de":"Serotonin","fr":"Sérotonine","tr":"Serotonin","nl":"Serotonine","ru":"Серотонин","zh":"血清素","pt_BR":"Serotonina","pt_PT":"Serotonina"}, back_translations: {"es":"Un neurotransmissor que regula humor, sono, apetite y controle de impulsos; niveles baixos están associados a la depresión. Los ISRSs aumentan a disponibilidad de serotonina y son antidepressivos de primera línea.","de":"Ein Neurotransmitter, der Stimmung, Schlaf, Appetit und Impulskontrolle reguliert; niedrige Spiegel werden mit Depression assoziiert. SSRIs erhöhen die Serotoninverfügbarkeit und sind Erstlinien-Antidepressiva.","fr":"Un neurotransmetteur régulant l'humeur, le sommeil, l'appétit et le contrôle des impulsions ; de faibles niveaux sont associés à la dépression. Les ISRS augmentent la disponibilité de la sérotonine et sont des antidépresseurs de première intention.","tr":"Duygudurum, uyku, iştah ve dürtü kontrolünü düzenleyen bir nörotransmiter; düşük seviyeleri depresyonla ilişkilidir. SSRI'lar serotonin kullanılabilirliğini artırır ve birinci basamak antidepresanlardır.","nl":"Een neurotransmitter die stemming, slaap, eetlust en impulscontrole reguleert; lage niveaus worden geassocieerd met depressie. SSRI's verhogen de beschikbaarheid van serotonine en zijn eerstelijns antidepressiva.","ru":"Нейромедиатор, регулирующий настроение, сон, аппетит и контроль импульсов; низкий уровень связан с депрессией. СИОЗС повышают доступность серотонина и являются антидепрессантами первой линии.","zh":"一种调节情绪、睡眠、食欲和冲动控制的神经递质；低水平与抑郁症相关。SSRIs增加血清素的可用性，是一线抗抑郁药。","pt_BR":"Um neurotransmissor que regula humor, sono, apetite e controle de impulsos; níveis baixos estão associados à depressão. Os ISRSs aumentam a disponibilidade de serotonina e são antidepressivos de primeira linha.","pt_PT":"Um neurotransmissor que regula o humor, o sono, o apetite e o controlo de impulsos; níveis baixos estão associados à depressão. Os ISRSs aumentam a disponibilidade de serotonina e são antidepressivos de primeira linha."}},
  { id: 'dc-psychology-0081', deck_id: 'deck-psychology', front: 'GABA (Gamma-Aminobutyric Acid)', back: 'The primary inhibitory neurotransmitter in the CNS; it reduces neuronal excitability. Benzodiazepines enhance GABA activity, producing calming and anti-anxiety effects.', sort_order: 81 , front_translations: {"es":"GABA (Ácido Gama-Aminobutírico)","de":"GABA (Gamma-Aminobuttersäure)","fr":"GABA (Acide gamma-aminobutyrique)","tr":"GABA (Gama-Aminobütirik Asit)","nl":"GABA (Gamma-aminoboterzuur)","ru":"ГАМК (гамма-аминомасляная кислота)","zh":"GABA（γ-氨基丁酸）","pt_BR":"GABA (Ácido Gama-Aminobutírico)","pt_PT":"GABA (Ácido Gama-Aminobutírico)"}, back_translations: {"es":"El principal neurotransmissor inibitório del SNC; reduce a excitabilidad neuronal. Los benzodiazepínicos aumentan a atividad del GABA, produciendo efectos calmantes y ansiolíticos.","de":"Der wichtigste inhibitorische Neurotransmitter im ZNS; er verringert die neuronale Erregbarkeit. Benzodiazepine verstärken die GABA-Aktivität und erzeugen beruhigende und angstlösende Wirkungen.","fr":"Le principal neurotransmetteur inhibiteur du SNC ; il réduit l'excitabilité neuronale. Les benzodiazépines renforcent l'activité du GABA, produisant des effets calmants et anxiolytiques.","tr":"MSS'deki başlıca inhibitör nörotransmiter; nöronal uyarılabilirliği azaltır. Benzodiazepinler GABA aktivitesini artırarak sakinleştirici ve anksiyete karşıtı etkiler üretir.","nl":"De belangrijkste inhiberende neurotransmitter in het CZS; het vermindert neuronale prikkelbaarheid. Benzodiazepinen versterken de GABA-activiteit en produceren kalmerende en angstverminderende effecten.","ru":"Основной тормозной нейромедиатор в ЦНС; снижает возбудимость нейронов. Бензодиазепины усиливают активность ГАМК, оказывая седативное и противотревожное действие.","zh":"中枢神经系统中主要的抑制性神经递质；它降低神经元兴奋性。苯二氮卓类药物增强GABA活性，产生镇静和抗焦虑效果。","pt_BR":"O principal neurotransmissor inibitório do SNC; reduz a excitabilidade neuronal. Os benzodiazepínicos aumentam a atividade do GABA, produzindo efeitos calmantes e ansiolíticos.","pt_PT":"O principal neurotransmissor inibitório do SNC; reduz a excitabilidade neuronal. As benzodiazepinas aumentam a atividade do GABA, produzindo efeitos calmantes e ansiolíticos."}},
  { id: 'dc-psychology-0082', deck_id: 'deck-psychology', front: 'Glutamate', back: 'The primary excitatory neurotransmitter in the CNS; essential for learning and memory (via long-term potentiation). Excessive glutamate activity is involved in excitotoxicity.', sort_order: 82 , front_translations: {"es":"Glutamato","de":"Glutamat","fr":"Glutamate","tr":"Glutamat","nl":"Glutamaat","ru":"Глутамат","zh":"谷氨酸","pt_BR":"Glutamato","pt_PT":"Glutamato"}, back_translations: {"es":"El principal neurotransmissor excitatório del SNC; esencial para aprendizaje y memoria (via potenciación de ancho prazo). La atividad excessiva de glutamato está involucrada en la excitotoxicidad.","de":"Der wichtigste exzitatorische Neurotransmitter im ZNS; essenziell für Lernen und Gedächtnis (über Langzeitpotenzierung). Übermäßige Glutamataktivität ist an Exzitotoxizität beteiligt.","fr":"Le principal neurotransmetteur excitateur du SNC ; essentiel pour l'apprentissage et la mémoire (via la potentialisation à long terme). Une activité excessive du glutamate est impliquée dans l'excitotoxicité.","tr":"MSS'deki başlıca uyarıcı nörotransmiter; öğrenme ve bellek için (uzun süreli potansiyasyon yoluyla) gereklidir. Aşırı glutamat aktivitesi eksitotoksisite ile ilişkilidir.","nl":"De belangrijkste excitatoire neurotransmitter in het CZS; essentieel voor leren en geheugen (via langetermijnpotentiëring). Overmatige glutamaatactiviteit is betrokken bij excitotoxiciteit.","ru":"Основной возбуждающий нейромедиатор в ЦНС; необходим для обучения и памяти (через долговременную потенциацию). Чрезмерная активность глутамата связана с эксайтотоксичностью.","zh":"中枢神经系统中主要的兴奋性神经递质；对学习和记忆（通过长时程增强）至关重要。过度的谷氨酸活性与兴奋性毒性有关。","pt_BR":"O principal neurotransmissor excitatório do SNC; essencial para aprendizagem e memória (via potenciação de longo prazo). A atividade excessiva de glutamato está envolvida na excitotoxicidade.","pt_PT":"O principal neurotransmissor excitatório do SNC; essencial para a aprendizagem e a memória (via potenciação de longo prazo). A atividade excessiva de glutamato está envolvida na excitotoxicidade."}},
  { id: 'dc-psychology-0083', deck_id: 'deck-psychology', front: 'Norepinephrine (Noradrenaline)', back: 'A neurotransmitter and hormone involved in the fight-or-flight response, attention, and arousal; plays a role in depression and anxiety, and is targeted by certain antidepressants.', sort_order: 83 , front_translations: {"es":"Norepinefrina (Noradrenalina)","de":"Noradrenalin (Norepinephrin)","fr":"Noradrénaline (Norépinéphrine)","tr":"Norepinefrin (Noradrenalin)","nl":"Noradrenaline (Norepinefrine)","ru":"Норадреналин (норэпинефрин)","zh":"去甲肾上腺素（Noradrenaline）","pt_BR":"Norepinefrina (Noradrenalina)","pt_PT":"Norepinefrina (Noradrenalina)"}, back_translations: {"es":"Un neurotransmissor y hormona involucrado en la respuesta de luta o fuga, atención y alerta; desempenha papel en la depresión y ansiedad y es alvo de certos antidepressivos.","de":"Ein Neurotransmitter und Hormon, das an der Kampf-oder-Flucht-Reaktion, Aufmerksamkeit und Erregung beteiligt ist; spielt eine Rolle bei Depression und Angst und wird von bestimmten Antidepressiva beeinflusst.","fr":"Un neurotransmetteur et une hormone impliqués dans la réponse de combat ou de fuite, l'attention et l'éveil ; joue un rôle dans la dépression et l'anxiété, et est ciblé par certains antidépresseurs.","tr":"Savaş ya da kaç tepkisi, dikkat ve uyarılmada rol oynayan bir nörotransmiter ve hormon; depresyon ve anksiyetede rol oynar ve bazı antidepresanlar tarafından hedef alınır.","nl":"Een neurotransmitter en hormoon betrokken bij de vecht-of-vluchtreactie, aandacht en arousal; speelt een rol bij depressie en angst en wordt beïnvloed door bepaalde antidepressiva.","ru":"Нейромедиатор и гормон, участвующий в реакции «бей или беги», внимании и возбуждении; играет роль в депрессии и тревоге и является мишенью некоторых антидепрессантов.","zh":"一种参与战斗或逃跑反应、注意力和唤醒的神经递质和激素；在抑郁和焦虑中起作用，是某些抗抑郁药的靶点。","pt_BR":"Um neurotransmissor e hormônio envolvido na resposta de luta ou fuga, atenção e alerta; desempenha papel na depressão e ansiedade e é alvo de certos antidepressivos.","pt_PT":"Um neurotransmissor e hormona envolvido na resposta de luta ou fuga, atenção e alerta; desempenha um papel na depressão e ansiedade e é alvo de certos antidepressivos."}},
  { id: 'dc-psychology-0084', deck_id: 'deck-psychology', front: 'Acetylcholine', back: 'The first neurotransmitter discovered; involved in muscle activation, memory, and attention. Deficiency in acetylcholine-producing neurons is associated with Alzheimer\'s disease.', sort_order: 84 , front_translations: {"es":"Acetilcolina","de":"Acetylcholin","fr":"Acétylcholine","tr":"Asetilkolin","nl":"Acetylcholine","ru":"Ацетилхолин","zh":"乙酰胆碱","pt_BR":"Acetilcolina","pt_PT":"Acetilcolina"}, back_translations: {"es":"El primero neurotransmissor descoberto; involucrado en la ativación muscular, memoria y atención. La deficiencia de neuronas produtores de acetilcolina está associada a la enfermedad de Alzheimer.","de":"Der erste entdeckte Neurotransmitter; beteiligt an Muskelaktivierung, Gedächtnis und Aufmerksamkeit. Ein Mangel an acetylcholinproduzierenden Neuronen wird mit der Alzheimer-Krankheit assoziiert.","fr":"Le premier neurotransmetteur découvert ; impliqué dans l'activation musculaire, la mémoire et l'attention. Le déficit des neurones produisant l'acétylcholine est associé à la maladie d'Alzheimer.","tr":"Keşfedilen ilk nörotransmiter; kas aktivasyonu, bellek ve dikkatte rol oynar. Asetilkolin üreten nöronlardaki eksiklik Alzheimer hastalığı ile ilişkilidir.","nl":"De eerste ontdekte neurotransmitter; betrokken bij spieractivering, geheugen en aandacht. Een tekort aan acetylcholine-producerende neuronen wordt geassocieerd met de ziekte van Alzheimer.","ru":"Первый открытый нейромедиатор; участвует в активации мышц, памяти и внимании. Дефицит нейронов, вырабатывающих ацетилхолин, связан с болезнью Альцгеймера.","zh":"第一个被发现的神经递质；参与肌肉激活、记忆和注意力。产生乙酰胆碱的神经元缺乏与阿尔茨海默病相关。","pt_BR":"O primeiro neurotransmissor descoberto; envolvido na ativação muscular, memória e atenção. A deficiência de neurônios produtores de acetilcolina está associada à doença de Alzheimer.","pt_PT":"O primeiro neurotransmissor descoberto; envolvido na ativação muscular, memória e atenção. A deficiência de neurónios produtores de acetilcolina está associada à doença de Alzheimer."}},
  { id: 'dc-psychology-0085', deck_id: 'deck-psychology', front: 'Synapse', back: 'The junction between two neurons where chemical communication occurs; neurotransmitters released from the presynaptic terminal cross the synaptic cleft to bind to receptors on the postsynaptic neuron.', sort_order: 85 , front_translations: {"es":"Sinapse","de":"Synapse","fr":"Synapse","tr":"Sinaps","nl":"Synaps","ru":"Синапс","zh":"突触","pt_BR":"Sinapse","pt_PT":"Sinapse"}, back_translations: {"es":"La junción entre de los neuronas donde ocurre a comunicación química; neurotransmissores liberados por el terminal pré-sináptico atravessam a fenda sináptica para se ligar a receptores en el neurona pós-sináptico.","de":"Die Verbindungsstelle zwischen zwei Neuronen, an der chemische Kommunikation stattfindet; Neurotransmitter, die vom präsynaptischen Terminal freigesetzt werden, überqueren den synaptischen Spalt und binden an Rezeptoren des postsynaptischen Neurons.","fr":"La jonction entre deux neurones où la communication chimique se produit ; les neurotransmetteurs libérés par le terminal présynaptique traversent la fente synaptique pour se lier aux récepteurs du neurone postsynaptique.","tr":"Kimyasal iletişimin gerçekleştiği iki nöron arasındaki bağlantı noktası; presinaptik terminalden salınan nörotransmiterler sinaptik aralığı geçerek postsinaptik nöronun reseptörlerine bağlanır.","nl":"De verbinding tussen twee neuronen waar chemische communicatie plaatsvindt; neurotransmitters die vrijkomen uit de presynaptische terminal kruisen de synaptische spleet om te binden aan receptoren op het postsynaptische neuron.","ru":"Соединение между двумя нейронами, где происходит химическая коммуникация; нейромедиаторы, высвобождаемые из пресинаптического окончания, пересекают синаптическую щель и связываются с рецепторами постсинаптического нейрона.","zh":"两个神经元之间进行化学通信的连接点；从突触前末端释放的神经递质穿过突触间隙，与突触后神经元上的受体结合。","pt_BR":"A junção entre dois neurônios onde ocorre a comunicação química; neurotransmissores liberados pelo terminal pré-sináptico atravessam a fenda sináptica para se ligar a receptores no neurônio pós-sináptico.","pt_PT":"A junção entre dois neurónios onde ocorre a comunicação química; neurotransmissores libertados pelo terminal pré-sináptico atravessam a fenda sináptica para se ligar a recetores no neurónio pós-sináptico."}},
  { id: 'dc-psychology-0086', deck_id: 'deck-psychology', front: 'Long-Term Potentiation (LTP)', back: 'A long-lasting increase in synaptic strength following repeated stimulation; believed to be the cellular basis of learning and memory formation in the hippocampus.', sort_order: 86 , front_translations: {"es":"Potenciación de Longo Prazo (LTP)","de":"Langzeitpotenzierung (LTP)","fr":"Potentialisation à long terme (PLT)","tr":"Uzun Süreli Potansiyasyon (LTP)","nl":"Langetermijnpotentiëring (LTP)","ru":"Долговременная потенциация (ДП)","zh":"长时程增强（LTP）","pt_BR":"Potenciação de Longo Prazo (LTP)","pt_PT":"Potenciação de Longo Prazo (LTP)"}, back_translations: {"es":"Un aumento duradouro en la fuerza sináptica após estimulación repetida; acredita-se ser a base celular de la aprendizaje y formación de memoria en el hipocampo.","de":"Eine langanhaltende Zunahme der synaptischen Stärke nach wiederholter Stimulation; gilt als die zelluläre Grundlage von Lernen und Gedächtnisbildung im Hippocampus.","fr":"Une augmentation durable de la force synaptique après une stimulation répétée ; considérée comme la base cellulaire de l'apprentissage et de la formation de la mémoire dans l'hippocampe.","tr":"Tekrarlanan uyarımın ardından sinaptik güçte uzun süreli bir artış; hipokampüste öğrenme ve bellek oluşumunun hücresel temeli olduğuna inanılmaktadır.","nl":"Een langdurige toename van synaptische sterkte na herhaalde stimulatie; wordt beschouwd als de cellulaire basis van leren en geheugenvorming in de hippocampus.","ru":"Длительное усиление синаптической передачи после повторной стимуляции; считается клеточной основой обучения и формирования памяти в гиппокампе.","zh":"反复刺激后突触强度的持久增加；被认为是海马体中学习和记忆形成的细胞基础。","pt_BR":"Um aumento duradouro na força sináptica após estimulação repetida; acredita-se ser a base celular da aprendizagem e formação de memória no hipocampo.","pt_PT":"Um aumento duradouro na força sináptica após estimulação repetida; acredita-se ser a base celular da aprendizagem e formação de memória no hipocampo."}},
  { id: 'dc-psychology-0087', deck_id: 'deck-psychology', front: 'Neuroplasticity', back: 'The brain\'s ability to reorganize itself by forming new neural connections throughout life; enables learning, memory, and recovery from brain injury.', sort_order: 87 , front_translations: {"es":"Neuroplasticidad","de":"Neuroplastizität","fr":"Neuroplasticité","tr":"Nöroplastisite","nl":"Neuroplasticiteit","ru":"Нейропластичность","zh":"神经可塑性","pt_BR":"Neuroplasticidade","pt_PT":"Neuroplasticidade"}, back_translations: {"es":"La capacidad del cerebro de se reorganizar formando nuevas conexiones neurais a lo ancho de la vida; possibilita a aprendizaje, a memoria y a recuperación de lesões cerebrais.","de":"Die Fähigkeit des Gehirns, sich durch die Bildung neuer neuronaler Verbindungen im Laufe des Lebens umzuorganisieren; ermöglicht Lernen, Gedächtnis und Erholung von Hirnverletzungen.","fr":"La capacité du cerveau à se réorganiser en formant de nouvelles connexions neuronales tout au long de la vie ; elle permet l'apprentissage, la mémoire et la récupération après une lésion cérébrale.","tr":"Beynin yaşam boyunca yeni sinirsel bağlantılar oluşturarak kendini yeniden organize etme yeteneği; öğrenme, bellek ve beyin hasarından iyileşmeyi mümkün kılar.","nl":"Het vermogen van de hersenen om zichzelf te reorganiseren door gedurende het hele leven nieuwe neurale verbindingen te vormen; maakt leren, geheugen en herstel van hersenletsel mogelijk.","ru":"Способность мозга перестраиваться путём формирования новых нейронных связей на протяжении всей жизни; обеспечивает обучение, память и восстановление после травм мозга.","zh":"大脑通过在一生中形成新的神经连接来重组自身的能力；使学习、记忆和脑损伤后的恢复成为可能。","pt_BR":"A capacidade do cérebro de se reorganizar formando novas conexões neurais ao longo da vida; possibilita a aprendizagem, a memória e a recuperação de lesões cerebrais.","pt_PT":"A capacidade do cérebro de se reorganizar formando novas conexões neurais ao longo da vida; possibilita a aprendizagem, a memória e a recuperação de lesões cerebrais."}},
  { id: 'dc-psychology-0088', deck_id: 'deck-psychology', front: 'Limbic System', back: 'A set of brain structures (including hippocampus, amygdala, and hypothalamus) involved in emotion, motivation, and memory; it connects the emotional brain to the rational cortex.', sort_order: 88 , front_translations: {"es":"Sistema Límbico","de":"Limbisches System","fr":"Système limbique","tr":"Limbik Sistem","nl":"Limbisch systeem","ru":"Лимбическая система","zh":"边缘系统","pt_BR":"Sistema Límbico","pt_PT":"Sistema Límbico"}, back_translations: {"es":"Un conjunto de estructuras cerebrais (incluyendo hipocampo, amígdala y hipotálamo) involucradas en la emoción, motivación y memoria; conecta el cerebro emocional al córtex racional.","de":"Eine Gruppe von Gehirnstrukturen (einschließlich Hippocampus, Amygdala und Hypothalamus), die an Emotion, Motivation und Gedächtnis beteiligt sind; sie verbindet das emotionale Gehirn mit dem rationalen Kortex.","fr":"Un ensemble de structures cérébrales (incluant l'hippocampe, l'amygdale et l'hypothalamus) impliquées dans l'émotion, la motivation et la mémoire ; il relie le cerveau émotionnel au cortex rationnel.","tr":"Duygu, motivasyon ve bellekte rol oynayan bir dizi beyin yapısı (hipokampüs, amigdala ve hipotalamus dahil); duygusal beyni rasyonel kortekse bağlar.","nl":"Een reeks hersenstructuren (waaronder hippocampus, amygdala en hypothalamus) betrokken bij emotie, motivatie en geheugen; het verbindt het emotionele brein met de rationele cortex.","ru":"Совокупность структур мозга (включая гиппокамп, миндалевидное тело и гипоталамус), участвующих в эмоциях, мотивации и памяти; соединяет эмоциональный мозг с рациональной корой.","zh":"一组参与情绪、动机和记忆的大脑结构（包括海马体、杏仁核和下丘脑）；它将情感脑与理性皮层连接起来。","pt_BR":"Um conjunto de estruturas cerebrais (incluindo hipocampo, amígdala e hipotálamo) envolvidas na emoção, motivação e memória; conecta o cérebro emocional ao córtex racional.","pt_PT":"Um conjunto de estruturas cerebrais (incluindo hipocampo, amígdala e hipotálamo) envolvidas na emoção, motivação e memória; liga o cérebro emocional ao córtex racional."}},
  { id: 'dc-psychology-0089', deck_id: 'deck-psychology', front: 'Prefrontal Cortex', back: 'The anterior portion of the frontal lobe responsible for executive functions: planning, decision-making, impulse control, working memory, and social behavior; fully matures by mid-20s.', sort_order: 89 , front_translations: {"es":"Córtex Pré-frontal","de":"Präfrontaler Kortex","fr":"Cortex préfrontal","tr":"Prefrontal Korteks","nl":"Prefrontale cortex","ru":"Префронтальная кора","zh":"前额叶皮层","pt_BR":"Córtex Pré-frontal","pt_PT":"Córtex Pré-frontal"}, back_translations: {"es":"La porción anterior del lobo frontal responsable por las funciones executivas: planejamento, tomada de decisão, controle de impulsos, memoria de trabajo y comportamiento social; amadurece completamente por volta de los 25 anos.","de":"Der vordere Teil des Frontallappens, verantwortlich für exekutive Funktionen: Planung, Entscheidungsfindung, Impulskontrolle, Arbeitsgedächtnis und Sozialverhalten; vollständig ausgereift bis Mitte 20.","fr":"La partie antérieure du lobe frontal responsable des fonctions exécutives : planification, prise de décision, contrôle des impulsions, mémoire de travail et comportement social ; pleinement mature vers le milieu de la vingtaine.","tr":"Yürütücü işlevlerden sorumlu frontal lobun ön kısmı: planlama, karar verme, dürtü kontrolü, çalışma belleği ve sosyal davranış; 20'li yaşların ortalarında tam olarak olgunlaşır.","nl":"Het voorste deel van de frontale kwab, verantwoordelijk voor executieve functies: planning, besluitvorming, impulscontrole, werkgeheugen en sociaal gedrag; volledig volgroeid rond het midden van de twintig.","ru":"Передняя часть лобной доли, отвечающая за исполнительные функции: планирование, принятие решений, контроль импульсов, рабочую память и социальное поведение; полностью созревает к середине третьего десятилетия жизни.","zh":"额叶的前部，负责执行功能：计划、决策、冲动控制、工作记忆和社会行为；在25岁左右完全成熟。","pt_BR":"A porção anterior do lobo frontal responsável pelas funções executivas: planejamento, tomada de decisão, controle de impulsos, memória de trabalho e comportamento social; amadurece completamente por volta dos 25 anos.","pt_PT":"A porção anterior do lobo frontal responsável pelas funções executivas: planeamento, tomada de decisão, controlo de impulsos, memória de trabalho e comportamento social; amadurece completamente por volta dos 25 anos."}},
  { id: 'dc-psychology-0090', deck_id: 'deck-psychology', front: 'Fight-or-Flight Response', back: 'The physiological reaction triggered by the amygdala to a perceived threat; adrenaline is released, increasing heart rate, blood pressure, and energy availability to prepare for action.', sort_order: 90 , front_translations: {"es":"Resposta de Luta o Fuga","de":"Kampf-oder-Flucht-Reaktion","fr":"Réponse de combat ou de fuite","tr":"Savaş ya da Kaç Tepkisi","nl":"Vecht-of-vluchtreactie","ru":"Реакция «бей или беги»","zh":"战斗或逃跑反应","pt_BR":"Resposta de Luta ou Fuga","pt_PT":"Resposta de Luta ou Fuga"}, back_translations: {"es":"La reacción fisiológica desencadeada por la amígdala ante de una ameaça percebida; a adrenalina es liberada, aumentando a frecuencia cardíaca, a presión arterial y a disponibilidad de energía para preparar para a acción.","de":"Die durch die Amygdala ausgelöste physiologische Reaktion auf eine wahrgenommene Bedrohung; Adrenalin wird freigesetzt, was Herzfrequenz, Blutdruck und Energieverfügbarkeit erhöht, um auf Handlung vorzubereiten.","fr":"La réaction physiologique déclenchée par l'amygdale face à une menace perçue ; l'adrénaline est libérée, augmentant la fréquence cardiaque, la pression artérielle et la disponibilité énergétique pour préparer à l'action.","tr":"Algılanan bir tehdide karşı amigdala tarafından tetiklenen fizyolojik tepki; adrenalin salınır, kalp hızı, kan basıncı ve enerji kullanılabilirliği artırılarak eyleme hazırlanılır.","nl":"De fysiologische reactie die door de amygdala wordt getriggerd bij een waargenomen bedreiging; adrenaline wordt vrijgegeven, waardoor hartslag, bloeddruk en energiebeschikbaarheid toenemen om voor te bereiden op actie.","ru":"Физиологическая реакция, запускаемая миндалевидным телом при воспринимаемой угрозе; выделяется адреналин, повышая частоту сердечных сокращений, артериальное давление и доступность энергии для подготовки к действию.","zh":"杏仁核在感知到威胁时触发的生理反应；释放肾上腺素，增加心率、血压和能量供应，为行动做准备。","pt_BR":"A reação fisiológica desencadeada pela amígdala diante de uma ameaça percebida; a adrenalina é liberada, aumentando a frequência cardíaca, a pressão arterial e a disponibilidade de energia para preparar para a ação.","pt_PT":"A reação fisiológica desencadeada pela amígdala perante uma ameaça percebida; a adrenalina é libertada, aumentando a frequência cardíaca, a pressão arterial e a disponibilidade de energia para preparar para a ação."}},
  { id: 'dc-psychology-0091', deck_id: 'deck-psychology', front: 'Cortisol', back: 'The primary stress hormone released by the adrenal cortex; it mobilizes energy and suppresses non-essential functions. Chronic cortisol elevation impairs memory, immunity, and mental health.', sort_order: 91 , front_translations: {"es":"Cortisol","de":"Cortisol","fr":"Cortisol","tr":"Kortizol","nl":"Cortisol","ru":"Кортизол","zh":"皮质醇","pt_BR":"Cortisol","pt_PT":"Cortisol"}, back_translations: {"es":"El principal hormona del estresse liberado por el córtex adrenal; mobiliza energía y suprime funciones no esenciales. La elevación crónica del cortisol prejudica a memoria, a imunidad y a salud mental.","de":"Das primäre Stresshormon, das von der Nebennierenrinde freigesetzt wird; es mobilisiert Energie und unterdrückt nicht-essentielle Funktionen. Chronisch erhöhtes Cortisol beeinträchtigt Gedächtnis, Immunität und psychische Gesundheit.","fr":"La principale hormone du stress libérée par le cortex surrénalien ; elle mobilise l'énergie et supprime les fonctions non essentielles. Une élévation chronique du cortisol altère la mémoire, l'immunité et la santé mentale.","tr":"Adrenal korteks tarafından salınan birincil stres hormonu; enerjiyi harekete geçirir ve zorunlu olmayan işlevleri baskılar. Kronik kortizol yüksekliği bellek, bağışıklık ve ruh sağlığını bozar.","nl":"Het primaire stresshormoon dat wordt vrijgegeven door de bijnierschors; het mobiliseert energie en onderdrukt niet-essentiële functies. Chronisch verhoogd cortisol schaadt geheugen, immuniteit en geestelijke gezondheid.","ru":"Основной гормон стресса, выделяемый корой надпочечников; мобилизует энергию и подавляет второстепенные функции. Хронически повышенный уровень кортизола ухудшает память, иммунитет и психическое здоровье.","zh":"由肾上腺皮质释放的主要应激激素；它调动能量并抑制非必要功能。慢性皮质醇升高会损害记忆、免疫力和心理健康。","pt_BR":"O principal hormônio do estresse liberado pelo córtex adrenal; mobiliza energia e suprime funções não essenciais. A elevação crônica do cortisol prejudica a memória, a imunidade e a saúde mental.","pt_PT":"A principal hormona do stress libertada pelo córtex suprarrenal; mobiliza energia e suprime funções não essenciais. A elevação crónica do cortisol prejudica a memória, a imunidade e a saúde mental."}},
  { id: 'dc-psychology-0092', deck_id: 'deck-psychology', front: 'Independent Variable (IV)', back: 'The variable that the experimenter manipulates or controls in an experiment; the presumed cause. Example: type of teaching method in an educational study.', sort_order: 92 , front_translations: {"es":"Variable Independente (VI)","de":"Unabhängige Variable (UV)","fr":"Variable indépendante (VI)","tr":"Bağımsız Değişken","nl":"Onafhankelijke variabele (OV)","ru":"Независимая переменная","zh":"自变量","pt_BR":"Variável Independente (VI)","pt_PT":"Variável Independente (VI)"}, back_translations: {"es":"La variable que el experimentador manipula o controla en un experimento; a causa presumida. Exemplo: tipo de método de ensino en un estudio educacional.","de":"Die Variable, die der Versuchsleiter in einem Experiment manipuliert oder kontrolliert; die vermutete Ursache. Beispiel: Art der Unterrichtsmethode in einer Bildungsstudie.","fr":"La variable que l'expérimentateur manipule ou contrôle dans une expérience ; la cause présumée. Exemple : le type de méthode d'enseignement dans une étude éducative.","tr":"Deneyde araştırmacının manipüle ettiği veya kontrol ettiği değişken; varsayılan neden. Örnek: bir eğitim çalışmasında öğretim yöntemi türü.","nl":"De variabele die de onderzoeker manipuleert of controleert in een experiment; de veronderstelde oorzaak. Voorbeeld: type onderwijsmethode in een onderwijsstudie.","ru":"Переменная, которую экспериментатор изменяет или контролирует в эксперименте; предполагаемая причина. Пример: тип метода обучения в образовательном исследовании.","zh":"实验者在实验中操纵或控制的变量；假定的原因。例如：教育研究中的教学方法类型。","pt_BR":"A variável que o experimentador manipula ou controla em um experimento; a causa presumida. Exemplo: tipo de método de ensino em um estudo educacional.","pt_PT":"A variável que o experimentador manipula ou controla numa experiência; a causa presumida. Exemplo: tipo de método de ensino num estudo educacional."}},
  { id: 'dc-psychology-0093', deck_id: 'deck-psychology', front: 'Dependent Variable (DV)', back: 'The variable measured in an experiment to assess the effect of the independent variable; the presumed effect. Example: test scores in a study on teaching methods.', sort_order: 93 , front_translations: {"es":"Variable Dependente (VD)","de":"Abhängige Variable (AV)","fr":"Variable dépendante (VD)","tr":"Bağımlı Değişken","nl":"Afhankelijke variabele (AV)","ru":"Зависимая переменная","zh":"因变量","pt_BR":"Variável Dependente (VD)","pt_PT":"Variável Dependente (VD)"}, back_translations: {"es":"La variable medida en un experimento para avaliar el efecto de la variable independente; el efecto presumido. Exemplo: notas en pruebas en un estudio sobre métodos de ensino.","de":"Die Variable, die in einem Experiment gemessen wird, um die Wirkung der unabhängigen Variablen zu beurteilen; der vermutete Effekt. Beispiel: Testergebnisse in einer Studie über Unterrichtsmethoden.","fr":"La variable mesurée dans une expérience pour évaluer l'effet de la variable indépendante ; l'effet présumé. Exemple : les résultats aux tests dans une étude sur les méthodes d'enseignement.","tr":"Bağımsız değişkenin etkisini değerlendirmek için deneyde ölçülen değişken; varsayılan etki. Örnek: öğretim yöntemleri üzerine bir çalışmada sınav puanları.","nl":"De variabele die in een experiment wordt gemeten om het effect van de onafhankelijke variabele te beoordelen; het veronderstelde effect. Voorbeeld: testscores in een studie over onderwijsmethoden.","ru":"Переменная, измеряемая в эксперименте для оценки влияния независимой переменной; предполагаемое следствие. Пример: результаты тестов в исследовании методов обучения.","zh":"在实验中测量的用于评估自变量效果的变量；假定的结果。例如：教学方法研究中的测试成绩。","pt_BR":"A variável medida em um experimento para avaliar o efeito da variável independente; o efeito presumido. Exemplo: notas em testes em um estudo sobre métodos de ensino.","pt_PT":"A variável medida numa experiência para avaliar o efeito da variável independente; o efeito presumido. Exemplo: resultados em testes num estudo sobre métodos de ensino."}},
  { id: 'dc-psychology-0094', deck_id: 'deck-psychology', front: 'Confounding Variable', back: 'An extraneous variable that co-varies with the independent variable and may be an alternative explanation for the results; controlled through random assignment or experimental design.', sort_order: 94 , front_translations: {"es":"Variable de Confusão","de":"Störvariable (Konfundierende Variable)","fr":"Variable confondante","tr":"Karıştırıcı Değişken","nl":"Confounding variabele","ru":"Смешивающая переменная (конфаунд)","zh":"混淆变量","pt_BR":"Variável de Confusão","pt_PT":"Variável de Confusão"}, back_translations: {"es":"Una variable estranha que covaria con a variable independente y puede ser una explicación alternativa para los resultados; controlada por medio de atribuición aleatória o delineamento experimental.","de":"Eine externe Variable, die mit der unabhängigen Variable kovariiert und eine alternative Erklärung für die Ergebnisse darstellen kann; durch Randomisierung oder Versuchsplanung kontrolliert.","fr":"Une variable extrinsèque qui covarie avec la variable indépendante et peut constituer une explication alternative des résultats ; contrôlée par l'assignation aléatoire ou le plan expérimental.","tr":"Bağımsız değişkenle birlikte değişen ve sonuçlar için alternatif bir açıklama olabilecek dışsal bir değişken; rastgele atama veya deneysel tasarım yoluyla kontrol edilir.","nl":"Een externe variabele die samenhangt met de onafhankelijke variabele en een alternatieve verklaring voor de resultaten kan zijn; gecontroleerd door willekeurige toewijzing of experimenteel ontwerp.","ru":"Посторонняя переменная, ковариирующая с независимой переменной и способная быть альтернативным объяснением результатов; контролируется рандомизацией или планом эксперимента.","zh":"一种与自变量共变的外部变量，可能是结果的替代解释；通过随机分配或实验设计加以控制。","pt_BR":"Uma variável estranha que covaria com a variável independente e pode ser uma explicação alternativa para os resultados; controlada por meio de atribuição aleatória ou delineamento experimental.","pt_PT":"Uma variável estranha que covaria com a variável independente e pode ser uma explicação alternativa para os resultados; controlada através de atribuição aleatória ou desenho experimental."}},
  { id: 'dc-psychology-0095', deck_id: 'deck-psychology', front: 'Placebo Effect', back: 'Improvement in a participant\'s condition due to their expectation of receiving an effective treatment, rather than the treatment itself; necessitates control groups in research.', sort_order: 95 , front_translations: {"es":"Efeito Placebo","de":"Placeboeffekt","fr":"Effet placebo","tr":"Plasebo Etkisi","nl":"Placebo-effect","ru":"Эффект плацебо","zh":"安慰剂效应","pt_BR":"Efeito Placebo","pt_PT":"Efeito Placebo"}, back_translations: {"es":"Melhora en la condición de un participante debido a la su expectativa de recibir un tratamiento eficaz, y no al tratamiento en si; torna necesarios los grupos de controle en la investigación.","de":"Verbesserung des Zustands eines Teilnehmers aufgrund seiner Erwartung, eine wirksame Behandlung zu erhalten, und nicht aufgrund der Behandlung selbst; macht Kontrollgruppen in der Forschung erforderlich.","fr":"Amélioration de l'état d'un participant due à son attente de recevoir un traitement efficace, plutôt qu'au traitement lui-même ; nécessite des groupes de contrôle dans la recherche.","tr":"Bir katılımcının durumundaki iyileşmenin tedavinin kendisinden değil, etkili bir tedavi alma beklentisinden kaynaklanması; araştırmada kontrol gruplarını zorunlu kılar.","nl":"Verbetering van de toestand van een deelnemer door de verwachting een effectieve behandeling te ontvangen, in plaats van door de behandeling zelf; maakt controlegroepen in onderzoek noodzakelijk.","ru":"Улучшение состояния участника вследствие ожидания эффективного лечения, а не самого лечения; обусловливает необходимость контрольных групп в исследованиях.","zh":"参与者因期望接受有效治疗而非治疗本身而出现的病情改善；使研究中的对照组成为必要。","pt_BR":"Melhora na condição de um participante devido à sua expectativa de receber um tratamento eficaz, e não ao tratamento em si; torna necessários os grupos de controle na pesquisa.","pt_PT":"Melhoria na condição de um participante devido à sua expectativa de receber um tratamento eficaz, e não ao tratamento em si; torna necessários os grupos de controlo na investigação."}},
  { id: 'dc-psychology-0096', deck_id: 'deck-psychology', front: 'Double-Blind Study', back: 'An experimental design in which neither participants nor researchers assessing outcomes know who received the treatment or placebo; minimizes expectation biases on both sides.', sort_order: 96 , front_translations: {"es":"Estudo Duplo-Cego","de":"Doppelblindstudie","fr":"Étude en double aveugle","tr":"Çift Kör Çalışma","nl":"Dubbelblind onderzoek","ru":"Двойное слепое исследование","zh":"双盲研究","pt_BR":"Estudo Duplo-Cego","pt_PT":"Estudo Duplamente Cego"}, back_translations: {"es":"Un delineamento experimental en el qual nem los participantes nem los pesquisadores que avaliam los resultados sabem quem recebeu el tratamiento o el placebo; minimiza vieses de expectativa de ambos los lados.","de":"Ein Versuchsdesign, bei dem weder die Teilnehmer noch die Forscher, die die Ergebnisse bewerten, wissen, wer die Behandlung oder das Placebo erhalten hat; minimiert Erwartungsverzerrungen auf beiden Seiten.","fr":"Un plan expérimental dans lequel ni les participants ni les chercheurs évaluant les résultats ne savent qui a reçu le traitement ou le placebo ; minimise les biais d'attente des deux côtés.","tr":"Ne katılımcıların ne de sonuçları değerlendiren araştırmacıların kimin tedavi veya plasebo aldığını bildiği bir deneysel tasarım; her iki taraftaki beklenti yanlılıklarını en aza indirir.","nl":"Een experimenteel ontwerp waarbij noch de deelnemers noch de onderzoekers die de resultaten beoordelen weten wie de behandeling of het placebo heeft ontvangen; minimaliseert verwachtingsbiassen aan beide zijden.","ru":"Экспериментальный план, при котором ни участники, ни исследователи, оценивающие результаты, не знают, кто получил лечение, а кто — плацебо; минимизирует эффекты ожиданий с обеих сторон.","zh":"一种实验设计，其中参与者和评估结果的研究人员都不知道谁接受了治疗或安慰剂；最大限度地减少双方的期望偏差。","pt_BR":"Um delineamento experimental no qual nem os participantes nem os pesquisadores que avaliam os resultados sabem quem recebeu o tratamento ou o placebo; minimiza vieses de expectativa de ambos os lados.","pt_PT":"Um desenho experimental no qual nem os participantes nem os investigadores que avaliam os resultados sabem quem recebeu o tratamento ou o placebo; minimiza vieses de expectativa de ambos os lados."}},
  { id: 'dc-psychology-0097', deck_id: 'deck-psychology', front: 'Random Assignment', back: 'Randomly placing participants into experimental or control groups to equalize individual differences; it is the key element ensuring internal validity and causal inference in experiments.', sort_order: 97 , front_translations: {"es":"Atribuición Aleatória","de":"Randomisierte Zuordnung","fr":"Assignation aléatoire","tr":"Rastgele Atama","nl":"Willekeurige toewijzing","ru":"Случайное распределение","zh":"随机分配","pt_BR":"Atribuição Aleatória","pt_PT":"Atribuição Aleatória"}, back_translations: {"es":"Colocar aleatoriamente los participantes en grupos experimentais o de controle para equalizar diferencias individuais; es el elemento-chave que garantiza a validad interna y a inferencia causal en experimentos.","de":"Zufällige Zuordnung von Teilnehmern zu Experimental- oder Kontrollgruppen, um individuelle Unterschiede auszugleichen; das Schlüsselelement zur Sicherstellung interner Validität und kausaler Schlussfolgerungen in Experimenten.","fr":"Placer aléatoirement les participants dans des groupes expérimentaux ou de contrôle pour égaliser les différences individuelles ; c'est l'élément clé garantissant la validité interne et l'inférence causale dans les expériences.","tr":"Bireysel farklılıkları eşitlemek için katılımcıları deney veya kontrol gruplarına rastgele yerleştirme; deneylerde iç geçerlilik ve nedensel çıkarım sağlayan temel unsurdur.","nl":"Het willekeurig plaatsen van deelnemers in experimentele of controlegroepen om individuele verschillen te egaliseren; het sleutelelement dat interne validiteit en causale inferentie in experimenten waarborgt.","ru":"Случайное распределение участников по экспериментальным или контрольным группам для уравнивания индивидуальных различий; ключевой элемент обеспечения внутренней валидности и причинно-следственных выводов в экспериментах.","zh":"将参与者随机分配到实验组或对照组以平衡个体差异；是确保实验内部效度和因果推断的关键要素。","pt_BR":"Colocar aleatoriamente os participantes em grupos experimentais ou de controle para equalizar diferenças individuais; é o elemento-chave que garante a validade interna e a inferência causal em experimentos.","pt_PT":"Colocar aleatoriamente os participantes em grupos experimentais ou de controlo para equalizar diferenças individuais; é o elemento-chave que garante a validade interna e a inferência causal em experiências."}},
  { id: 'dc-psychology-0098', deck_id: 'deck-psychology', front: 'Random Sampling', back: 'Selecting participants from a population such that every member has an equal chance of being chosen; it ensures the sample is representative and supports generalizability (external validity).', sort_order: 98 , front_translations: {"es":"Amostraje Aleatória","de":"Zufallsstichprobe","fr":"Échantillonnage aléatoire","tr":"Rastgele Örnekleme","nl":"Willekeurige steekproef","ru":"Случайная выборка","zh":"随机抽样","pt_BR":"Amostragem Aleatória","pt_PT":"Amostragem Aleatória"}, back_translations: {"es":"Selecionar participantes de una población de modo que cada membro tenha a misma chance de ser escolhido; garantiza que a amostra seja representativa y apoia a generalización (validad externa).","de":"Auswahl von Teilnehmern aus einer Population, sodass jedes Mitglied die gleiche Chance hat, ausgewählt zu werden; stellt sicher, dass die Stichprobe repräsentativ ist und unterstützt die Verallgemeinerbarkeit (externe Validität).","fr":"Sélectionner des participants d'une population de sorte que chaque membre ait une chance égale d'être choisi ; cela garantit que l'échantillon est représentatif et soutient la généralisabilité (validité externe).","tr":"Bir popülasyondan katılımcıları her üyenin seçilme şansının eşit olacağı şekilde seçme; örneklemin temsili olmasını sağlar ve genellenebilirliği (dış geçerlilik) destekler.","nl":"Het selecteren van deelnemers uit een populatie zodat elk lid een gelijke kans heeft om gekozen te worden; het zorgt ervoor dat de steekproef representatief is en ondersteunt generaliseerbaarheid (externe validiteit).","ru":"Отбор участников из популяции таким образом, чтобы каждый член имел равные шансы быть выбранным; обеспечивает репрезентативность выборки и поддерживает обобщаемость (внешнюю валидность).","zh":"从总体中选择参与者，使每个成员都有相等的被选中机会；确保样本具有代表性并支持可推广性（外部效度）。","pt_BR":"Selecionar participantes de uma população de modo que cada membro tenha a mesma chance de ser escolhido; garante que a amostra seja representativa e apoia a generalização (validade externa).","pt_PT":"Selecionar participantes de uma população de modo que cada membro tenha a mesma probabilidade de ser escolhido; garante que a amostra seja representativa e apoia a generalização (validade externa)."}},
  { id: 'dc-psychology-0099', deck_id: 'deck-psychology', front: 'Reliability (Research)', back: 'The consistency of a measurement; a reliable measure produces similar results under consistent conditions. Inter-rater, test-retest, and internal consistency are forms of reliability.', sort_order: 99 , front_translations: {"es":"Confiabilidad (Pesquisa)","de":"Reliabilität (Forschung)","fr":"Fiabilité (Recherche)","tr":"Güvenilirlik (Araştırma)","nl":"Betrouwbaarheid (Onderzoek)","ru":"Надёжность (в исследованиях)","zh":"信度（研究）","pt_BR":"Confiabilidade (Pesquisa)","pt_PT":"Fiabilidade (Investigação)"}, back_translations: {"es":"La consistencia de una medición; una medida confiable produce resultados semelhantes en condiciones consistentes. Confiabilidad entre avaliadores, prueba-reteste y consistencia interna son formas de confiabilidad.","de":"Die Konsistenz einer Messung; ein reliables Maß liefert unter gleichbleibenden Bedingungen ähnliche Ergebnisse. Interrater-Reliabilität, Test-Retest-Reliabilität und interne Konsistenz sind Formen der Reliabilität.","fr":"La cohérence d'une mesure ; une mesure fiable produit des résultats similaires dans des conditions constantes. La fidélité inter-juges, test-retest et la cohérence interne sont des formes de fiabilité.","tr":"Bir ölçümün tutarlılığı; güvenilir bir ölçüm tutarlı koşullar altında benzer sonuçlar üretir. Değerlendiriciler arası güvenilirlik, test-tekrar test güvenilirliği ve iç tutarlılık güvenilirlik biçimleridir.","nl":"De consistentie van een meting; een betrouwbare meting levert vergelijkbare resultaten op onder consistente omstandigheden. Inter-beoordelaarsbetrouwbaarheid, test-hertestbetrouwbaarheid en interne consistentie zijn vormen van betrouwbaarheid.","ru":"Согласованность измерения; надёжный инструмент даёт сходные результаты в одинаковых условиях. Межэкспертная надёжность, тест-ретестовая надёжность и внутренняя согласованность — формы надёжности.","zh":"测量的一致性；可靠的测量在一致条件下产生相似的结果。评分者间信度、重测信度和内部一致性是信度的形式。","pt_BR":"A consistência de uma medição; uma medida confiável produz resultados semelhantes em condições consistentes. Confiabilidade entre avaliadores, teste-reteste e consistência interna são formas de confiabilidade.","pt_PT":"A consistência de uma medição; uma medida fiável produz resultados semelhantes em condições consistentes. Fiabilidade entre avaliadores, teste-reteste e consistência interna são formas de fiabilidade."}},
  { id: 'dc-psychology-0100', deck_id: 'deck-psychology', front: 'Validity (Research)', back: 'The degree to which a test or study measures what it claims to measure. Internal validity concerns causal conclusions; external validity concerns generalizability.', sort_order: 100 , front_translations: {"es":"Validad (Pesquisa)","de":"Validität (Forschung)","fr":"Validité (Recherche)","tr":"Geçerlilik (Araştırma)","nl":"Validiteit (Onderzoek)","ru":"Валидность (Исследование)","zh":"效度（研究）","pt_BR":"Validade (Pesquisa)","pt_PT":"Validade (Investigação)"}, back_translations: {"es":"El grau en que un prueba o estudio mide el que afirma medir. La validad interna diz respeito a conclusões causais; a validad externa diz respeito a la generalización.","de":"Das Ausmaß, in dem ein Test oder eine Studie tatsächlich misst, was er/sie zu messen vorgibt. Interne Validität betrifft kausale Schlussfolgerungen; externe Validität betrifft die Verallgemeinerbarkeit.","fr":"Le degré auquel un test ou une étude mesure ce qu'il prétend mesurer. La validité interne concerne les conclusions causales ; la validité externe concerne la généralisabilité.","tr":"Bir testin veya çalışmanın ölçmeyi iddia ettiği şeyi gerçekten ne ölçüde ölçtüğü. İç geçerlilik nedensel sonuçlarla; dış geçerlilik genellenebilirlikle ilgilidir.","nl":"De mate waarin een test of onderzoek meet wat het beweert te meten. Interne validiteit betreft causale conclusies; externe validiteit betreft generaliseerbaarheid.","ru":"Степень, в которой тест или исследование измеряет то, что оно претендует измерять. Внутренняя валидность касается причинно-следственных выводов; внешняя валидность касается обобщаемости.","zh":"测试或研究实际测量其声称测量内容的程度。内部效度涉及因果结论；外部效度涉及可推广性。","pt_BR":"O grau em que um teste ou estudo mede o que afirma medir. A validade interna diz respeito a conclusões causais; a validade externa diz respeito à generalização.","pt_PT":"O grau em que um teste ou estudo mede o que afirma medir. A validade interna diz respeito a conclusões causais; a validade externa diz respeito à generalização."}},
  { id: 'dc-psychology-0101', deck_id: 'deck-psychology', front: 'Correlation vs. Causation', back: 'Correlation means two variables change together; causation means one variable directly causes changes in the other. Correlation does not imply causation; confounds may explain the relationship.', sort_order: 101 , front_translations: {"es":"Correlación vs. Causalidad","de":"Korrelation vs. Kausalität","fr":"Corrélation vs. Causalité","tr":"Korelasyon ve Nedensellik","nl":"Correlatie vs. Causaliteit","ru":"Корреляция и причинность","zh":"相关与因果","pt_BR":"Correlação vs. Causalidade","pt_PT":"Correlação vs. Causalidade"}, back_translations: {"es":"Correlación significa que de los variables mudam juntas; causalidad significa que una variable causa directamente cambios en la outra. Correlación no implica causalidad; variables confundidoras pueden explicar a relación.","de":"Korrelation bedeutet, dass zwei Variablen sich gemeinsam verändern; Kausalität bedeutet, dass eine Variable direkt Veränderungen in der anderen verursacht. Korrelation impliziert keine Kausalität; Störvariablen können die Beziehung erklären.","fr":"La corrélation signifie que deux variables changent ensemble ; la causalité signifie qu'une variable provoque directement des changements dans l'autre. La corrélation n'implique pas la causalité ; des variables confondantes peuvent expliquer la relation.","tr":"Korelasyon, iki değişkenin birlikte değiştiği anlamına gelir; nedensellik, bir değişkenin diğerinde doğrudan değişikliklere neden olduğu anlamına gelir. Korelasyon nedensellik anlamına gelmez; karıştırıcı değişkenler ilişkiyi açıklayabilir.","nl":"Correlatie betekent dat twee variabelen samen veranderen; causaliteit betekent dat de ene variabele direct veranderingen in de andere veroorzaakt. Correlatie impliceert geen causaliteit; confounders kunnen de relatie verklaren.","ru":"Корреляция означает, что две переменные изменяются вместе; причинность означает, что одна переменная напрямую вызывает изменения в другой. Корреляция не подразумевает причинность; смешивающие переменные могут объяснить эту связь.","zh":"相关意味着两个变量一起变化；因果意味着一个变量直接导致另一个变量的变化。相关不等于因果；混淆变量可能解释这种关系。","pt_BR":"Correlação significa que duas variáveis mudam juntas; causalidade significa que uma variável causa diretamente mudanças na outra. Correlação não implica causalidade; variáveis confundidoras podem explicar a relação.","pt_PT":"Correlação significa que duas variáveis mudam juntas; causalidade significa que uma variável causa diretamente mudanças na outra. Correlação não implica causalidade; variáveis confundidoras podem explicar a relação."}},
  { id: 'dc-psychology-0102', deck_id: 'deck-psychology', front: 'Case Study', back: 'An in-depth examination of a single individual, group, or event; provides rich, detailed data but cannot establish causation and may not generalize. Famous example: Phineas Gage.', sort_order: 102 , front_translations: {"es":"Estudo de Caso","de":"Fallstudie","fr":"Étude de cas","tr":"Vaka Çalışması","nl":"Casestudy","ru":"Исследование случая","zh":"个案研究","pt_BR":"Estudo de Caso","pt_PT":"Estudo de Caso"}, back_translations: {"es":"Un examen aprofundado de un único indivíduo, grupo o evento; proporciona datos ricos y detalhados, pero no puede estabelecer causalidad y puede no ser generalizable. Exemplo famoso: Phineas Gage.","de":"Eine eingehende Untersuchung einer einzelnen Person, Gruppe oder eines Ereignisses; liefert reichhaltige, detaillierte Daten, kann aber keine Kausalität nachweisen und ist möglicherweise nicht verallgemeinerbar. Berühmtes Beispiel: Phineas Gage.","fr":"Un examen approfondi d'un seul individu, groupe ou événement ; fournit des données riches et détaillées mais ne peut établir de causalité et peut ne pas être généralisable. Exemple célèbre : Phineas Gage.","tr":"Tek bir bireyin, grubun veya olayın derinlemesine incelenmesi; zengin, ayrıntılı veriler sağlar ancak nedensellik kuramaz ve genellenemeyebilir. Ünlü örnek: Phineas Gage.","nl":"Een diepgaand onderzoek van een enkel individu, groep of gebeurtenis; levert rijke, gedetailleerde gegevens op maar kan geen causaliteit vaststellen en is mogelijk niet generaliseerbaar. Beroemd voorbeeld: Phineas Gage.","ru":"Углублённое исследование отдельного человека, группы или события; предоставляет богатые, подробные данные, но не может установить причинно-следственную связь и может быть не обобщаемым. Известный пример: Финеас Гейдж.","zh":"对单个个体、群体或事件的深入研究；提供丰富详细的数据，但无法建立因果关系，且可能不具有推广性。著名案例：菲尼亚斯·盖奇。","pt_BR":"Um exame aprofundado de um único indivíduo, grupo ou evento; fornece dados ricos e detalhados, mas não pode estabelecer causalidade e pode não ser generalizável. Exemplo famoso: Phineas Gage.","pt_PT":"Um exame aprofundado de um único indivíduo, grupo ou evento; fornece dados ricos e detalhados, mas não pode estabelecer causalidade e pode não ser generalizável. Exemplo famoso: Phineas Gage."}},
  { id: 'dc-psychology-0103', deck_id: 'deck-psychology', front: 'Naturalistic Observation', back: 'Observing behavior in its natural environment without intervention; high ecological validity but cannot establish causation, and observer presence may alter behavior (Hawthorne effect).', sort_order: 103 , front_translations: {"es":"Observación Naturalística","de":"Naturalistische Beobachtung","fr":"Observation naturaliste","tr":"Doğal Gözlem","nl":"Naturalistische observatie","ru":"Натуралистическое наблюдение","zh":"自然观察法","pt_BR":"Observação Naturalística","pt_PT":"Observação Naturalista"}, back_translations: {"es":"Observar el comportamiento en su ambiente natural sin intervención; alta validad ecológica, pero no puede estabelecer causalidad, y a presencia del observador puede alterar el comportamiento (efecto Hawthorne).","de":"Beobachtung von Verhalten in seiner natürlichen Umgebung ohne Eingriff; hohe ökologische Validität, kann aber keine Kausalität nachweisen, und die Anwesenheit des Beobachters kann das Verhalten verändern (Hawthorne-Effekt).","fr":"Observer le comportement dans son environnement naturel sans intervention ; haute validité écologique mais ne peut établir de causalité, et la présence de l'observateur peut modifier le comportement (effet Hawthorne).","tr":"Davranışın müdahale olmaksızın doğal ortamında gözlemlenmesi; yüksek ekolojik geçerlilik sağlar ancak nedensellik kuramaz ve gözlemcinin varlığı davranışı değiştirebilir (Hawthorne etkisi).","nl":"Gedrag observeren in de natuurlijke omgeving zonder interventie; hoge ecologische validiteit maar kan geen causaliteit vaststellen, en de aanwezigheid van de waarnemer kan het gedrag beïnvloeden (Hawthorne-effect).","ru":"Наблюдение за поведением в естественной среде без вмешательства; высокая экологическая валидность, но не может установить причинно-следственную связь, а присутствие наблюдателя может изменить поведение (эффект Хоторна).","zh":"在不干预的情况下观察自然环境中的行为；具有高生态效度，但无法建立因果关系，且观察者的存在可能改变行为（霍桑效应）。","pt_BR":"Observar o comportamento em seu ambiente natural sem intervenção; alta validade ecológica, mas não pode estabelecer causalidade, e a presença do observador pode alterar o comportamento (efeito Hawthorne).","pt_PT":"Observar o comportamento no seu ambiente natural sem intervenção; alta validade ecológica, mas não pode estabelecer causalidade, e a presença do observador pode alterar o comportamento (efeito Hawthorne)."}},
  { id: 'dc-psychology-0104', deck_id: 'deck-psychology', front: 'Survey Research', back: 'Collecting self-reported data from a sample using questionnaires or interviews; efficient for large samples but susceptible to social desirability bias and inaccurate self-report.', sort_order: 104 , front_translations: {"es":"Pesquisa por Questionário","de":"Umfrageforschung","fr":"Recherche par sondage","tr":"Anket Araştırması","nl":"Enquêteonderzoek","ru":"Опросное исследование","zh":"调查研究","pt_BR":"Pesquisa por Questionário","pt_PT":"Investigação por Inquérito"}, back_translations: {"es":"Coleta de datos autorrelatados de una amostra usando questionários o entrevistas; eficiente para grandes amostras, pero suscetible al viés de desejabilidad social y autorrelato impreciso.","de":"Erhebung selbstberichteter Daten einer Stichprobe mittels Fragebögen oder Interviews; effizient für große Stichproben, aber anfällig für soziale Erwünschtheit und ungenaue Selbstberichte.","fr":"Collecte de données auto-déclarées auprès d'un échantillon à l'aide de questionnaires ou d'entretiens ; efficace pour les grands échantillons mais susceptible de biais de désirabilité sociale et d'auto-déclarations inexactes.","tr":"Anketler veya görüşmeler kullanarak bir örneklemden öz bildirime dayalı veri toplama; büyük örneklemler için verimlidir ancak sosyal beğenirlik yanlılığına ve hatalı öz bildirime duyarlıdır.","nl":"Het verzamelen van zelfgerapporteerde gegevens van een steekproef met behulp van vragenlijsten of interviews; efficiënt voor grote steekproeven maar vatbaar voor sociale wenselijkheidsbias en onnauwkeurige zelfrapportage.","ru":"Сбор самоотчётных данных от выборки с помощью анкет или интервью; эффективен для больших выборок, но подвержен эффекту социальной желательности и неточным самоотчётам.","zh":"使用问卷或访谈从样本中收集自我报告数据；对大样本高效，但容易受到社会期望偏差和不准确自我报告的影响。","pt_BR":"Coleta de dados autorrelatados de uma amostra usando questionários ou entrevistas; eficiente para grandes amostras, mas suscetível ao viés de desejabilidade social e autorrelato impreciso.","pt_PT":"Recolha de dados autorrelatados de uma amostra usando questionários ou entrevistas; eficiente para grandes amostras, mas suscetível ao viés de desejabilidade social e autorrelato impreciso."}},
  { id: 'dc-psychology-0105', deck_id: 'deck-psychology', front: 'Social Desirability Bias', back: 'The tendency of survey respondents to answer questions in a manner they believe will be viewed favorably by others, rather than answering honestly.', sort_order: 105 , front_translations: {"es":"Viés de Desejabilidad Social","de":"Soziale Erwünschtheit","fr":"Biais de désirabilité sociale","tr":"Sosyal Beğenirlik Yanlılığı","nl":"Sociale wenselijkheidsbias","ru":"Эффект социальной желательности","zh":"社会期望偏差","pt_BR":"Viés de Desejabilidade Social","pt_PT":"Viés de Desejabilidade Social"}, back_translations: {"es":"La tendencia de los respondentes de investigación a responder perguntas de una manera que acreditam ser vista favoravelmente por los outros, en vez de responder honestamente.","de":"Die Tendenz von Umfrageteilnehmern, Fragen so zu beantworten, wie sie glauben, dass es von anderen positiv gesehen wird, anstatt ehrlich zu antworten.","fr":"La tendance des répondants à un sondage à répondre aux questions d'une manière qu'ils pensent être perçue favorablement par les autres, plutôt que de répondre honnêtement.","tr":"Anket katılımcılarının soruları dürüstçe yanıtlamak yerine, başkaları tarafından olumlu karşılanacağına inandıkları şekilde yanıtlama eğilimi.","nl":"De neiging van enquêterespondenten om vragen te beantwoorden op een manier waarvan ze denken dat deze gunstig wordt beoordeeld door anderen, in plaats van eerlijk te antwoorden.","ru":"Склонность респондентов отвечать на вопросы так, как, по их мнению, будет одобрено окружающими, а не честно.","zh":"调查受访者倾向于以他们认为会被他人积极看待的方式回答问题，而非诚实作答。","pt_BR":"A tendência dos respondentes de pesquisa a responder perguntas de uma maneira que acreditam ser vista favoravelmente pelos outros, em vez de responder honestamente.","pt_PT":"A tendência dos respondentes de inquérito a responder a perguntas de uma forma que acreditam ser vista favoravelmente pelos outros, em vez de responder honestamente."}},
  { id: 'dc-psychology-0106', deck_id: 'deck-psychology', front: 'Working Memory', back: 'A limited-capacity system for temporarily holding and manipulating information during cognitive tasks; Baddeley\'s model includes the phonological loop, visuospatial sketchpad, and central executive.', sort_order: 106 , front_translations: {"es":"Memória de Trabalho","de":"Arbeitsgedächtnis","fr":"Mémoire de travail","tr":"Çalışma Belleği","nl":"Werkgeheugen","ru":"Рабочая память","zh":"工作记忆","pt_BR":"Memória de Trabalho","pt_PT":"Memória de Trabalho"}, back_translations: {"es":"Un sistema de capacidad limitada para mantener y manipular temporariamente informaciones durante tarefas cognitivas; el modelo de Baddeley incluye el laço fonológico, el esboço visuoespacial y el executivo central.","de":"Ein System mit begrenzter Kapazität zum vorübergehenden Halten und Verarbeiten von Informationen während kognitiver Aufgaben; Baddeleys Modell umfasst die phonologische Schleife, den visuell-räumlichen Notizblock und die zentrale Exekutive.","fr":"Un système à capacité limitée pour maintenir et manipuler temporairement des informations pendant les tâches cognitives ; le modèle de Baddeley comprend la boucle phonologique, le calepin visuospatial et l'administrateur central.","tr":"Bilişsel görevler sırasında bilgiyi geçici olarak tutmak ve işlemek için sınırlı kapasiteli bir sistem; Baddeley'nin modeli fonolojik döngü, görsel-uzamsal taslak defteri ve merkezi yöneticiyi içerir.","nl":"Een systeem met beperkte capaciteit voor het tijdelijk vasthouden en manipuleren van informatie tijdens cognitieve taken; Baddeley's model omvat de fonologische lus, het visuospatieel kladblok en de centrale executieve.","ru":"Система ограниченной ёмкости для временного хранения и обработки информации во время когнитивных задач; модель Баддели включает фонологическую петлю, зрительно-пространственный блокнот и центральный исполнитель.","zh":"一种容量有限的系统，用于在认知任务中临时保持和操控信息；巴德利的模型包括语音环路、视觉空间画板和中央执行系统。","pt_BR":"Um sistema de capacidade limitada para manter e manipular temporariamente informações durante tarefas cognitivas; o modelo de Baddeley inclui o laço fonológico, o esboço visuoespacial e o executivo central.","pt_PT":"Um sistema de capacidade limitada para manter e manipular temporariamente informações durante tarefas cognitivas; o modelo de Baddeley inclui o ciclo fonológico, o esboço visuoespacial e o executivo central."}},
  { id: 'dc-psychology-0107', deck_id: 'deck-psychology', front: 'Long-Term Memory', back: 'Relatively permanent memory storage with essentially unlimited capacity; divided into explicit (declarative: episodic and semantic) and implicit (procedural) memory.', sort_order: 107 , front_translations: {"es":"Memória de Longo Prazo","de":"Langzeitgedächtnis","fr":"Mémoire à long terme","tr":"Uzun Süreli Bellek","nl":"Langetermijngeheugen","ru":"Долговременная память","zh":"长期记忆","pt_BR":"Memória de Longo Prazo","pt_PT":"Memória de Longo Prazo"}, back_translations: {"es":"Armazenamento de memoria relativamente permanente con capacidad esencialmente ilimitada; dividido en memoria explícita (declarativa: episódica y semantica) y implícita (procedural).","de":"Relativ dauerhafter Gedächtnisspeicher mit im Wesentlichen unbegrenzter Kapazität; unterteilt in explizites (deklaratives: episodisches und semantisches) und implizites (prozedurales) Gedächtnis.","fr":"Stockage mnésique relativement permanent d'une capacité essentiellement illimitée ; divisé en mémoire explicite (déclarative : épisodique et sémantique) et implicite (procédurale).","tr":"Temelde sınırsız kapasiteli, nispeten kalıcı bellek deposu; açık (bildirimsel: epizodik ve semantik) ve örtük (prosedürel) bellek olarak ayrılır.","nl":"Relatief permanente geheugenopslag met in wezen onbeperkte capaciteit; onderverdeeld in expliciet (declaratief: episodisch en semantisch) en impliciet (procedureel) geheugen.","ru":"Относительно постоянное хранилище памяти с практически неограниченной ёмкостью; делится на эксплицитную (декларативную: эпизодическую и семантическую) и имплицитную (процедурную) память.","zh":"容量基本无限的相对永久记忆存储；分为外显记忆（陈述性：情景记忆和语义记忆）和内隐记忆（程序性记忆）。","pt_BR":"Armazenamento de memória relativamente permanente com capacidade essencialmente ilimitada; dividido em memória explícita (declarativa: episódica e semântica) e implícita (procedural).","pt_PT":"Armazenamento de memória relativamente permanente com capacidade essencialmente ilimitada; dividido em memória explícita (declarativa: episódica e semântica) e implícita (procedimental)."}},
  { id: 'dc-psychology-0108', deck_id: 'deck-psychology', front: 'Episodic Memory', back: 'A type of long-term explicit memory for autobiographical events — personal experiences tied to specific times and places; distinct from semantic memory for general facts.', sort_order: 108 , front_translations: {"es":"Memória Episódica","de":"Episodisches Gedächtnis","fr":"Mémoire épisodique","tr":"Epizodik Bellek","nl":"Episodisch geheugen","ru":"Эпизодическая память","zh":"情景记忆","pt_BR":"Memória Episódica","pt_PT":"Memória Episódica"}, back_translations: {"es":"Un tipo de memoria explícita de ancho prazo para eventos autobiográficos — experiencias pessoais ligadas a tiempos y lugares específicos; distinta de la memoria semantica para hechos gerais.","de":"Eine Art des expliziten Langzeitgedächtnisses für autobiografische Ereignisse — persönliche Erlebnisse, die an bestimmte Zeiten und Orte gebunden sind; unterschieden vom semantischen Gedächtnis für allgemeine Fakten.","fr":"Un type de mémoire explicite à long terme pour les événements autobiographiques — des expériences personnelles liées à des moments et des lieux spécifiques ; distinct de la mémoire sémantique pour les faits généraux.","tr":"Otobiyografik olaylar için bir tür uzun süreli açık bellek — belirli zaman ve yerlere bağlı kişisel deneyimler; genel bilgiler için semantik bellekten farklıdır.","nl":"Een type expliciet langetermijngeheugen voor autobiografische gebeurtenissen — persoonlijke ervaringen gekoppeld aan specifieke tijden en plaatsen; onderscheiden van semantisch geheugen voor algemene feiten.","ru":"Тип эксплицитной долговременной памяти для автобиографических событий — личных переживаний, привязанных к конкретным временам и местам; отличается от семантической памяти для общих фактов.","zh":"一种用于自传事件的外显长期记忆——与特定时间和地点相关的个人经历；与用于一般事实的语义记忆不同。","pt_BR":"Um tipo de memória explícita de longo prazo para eventos autobiográficos — experiências pessoais ligadas a tempos e lugares específicos; distinta da memória semântica para fatos gerais.","pt_PT":"Um tipo de memória explícita de longo prazo para eventos autobiográficos — experiências pessoais ligadas a tempos e lugares específicos; distinta da memória semântica para factos gerais."}},
  { id: 'dc-psychology-0109', deck_id: 'deck-psychology', front: 'Semantic Memory', back: 'Long-term memory for general factual knowledge about the world (e.g., knowing that Paris is the capital of France); not tied to specific personal experiences.', sort_order: 109 , front_translations: {"es":"Memória Semantica","de":"Semantisches Gedächtnis","fr":"Mémoire sémantique","tr":"Semantik Bellek","nl":"Semantisch geheugen","ru":"Семантическая память","zh":"语义记忆","pt_BR":"Memória Semântica","pt_PT":"Memória Semântica"}, back_translations: {"es":"Memória de ancho prazo para conocimiento factual geral sobre el mundo (ex.: saber que Paris es a capital de la França); no vinculada a experiencias pessoais específicas.","de":"Langzeitgedächtnis für allgemeines Faktenwissen über die Welt (z. B. zu wissen, dass Paris die Hauptstadt Frankreichs ist); nicht an bestimmte persönliche Erfahrungen gebunden.","fr":"Mémoire à long terme pour les connaissances factuelles générales sur le monde (par ex., savoir que Paris est la capitale de la France) ; non liée à des expériences personnelles spécifiques.","tr":"Dünya hakkındaki genel olgusal bilgi için uzun süreli bellek (ör. Paris'in Fransa'nın başkenti olduğunu bilmek); belirli kişisel deneyimlere bağlı değildir.","nl":"Langetermijngeheugen voor algemene feitelijke kennis over de wereld (bijv. weten dat Parijs de hoofdstad van Frankrijk is); niet gekoppeld aan specifieke persoonlijke ervaringen.","ru":"Долговременная память для общих фактических знаний о мире (например, знание того, что Париж — столица Франции); не привязана к конкретным личным переживаниям.","zh":"关于世界一般事实知识的长期记忆（例如，知道巴黎是法国的首都）；与特定个人经历无关。","pt_BR":"Memória de longo prazo para conhecimento factual geral sobre o mundo (ex.: saber que Paris é a capital da França); não vinculada a experiências pessoais específicas.","pt_PT":"Memória de longo prazo para conhecimento factual geral sobre o mundo (ex.: saber que Paris é a capital da França); não vinculada a experiências pessoais específicas."}},
  { id: 'dc-psychology-0110', deck_id: 'deck-psychology', front: 'Procedural Memory', back: 'A type of implicit long-term memory for how to perform skills and habits (e.g., riding a bike, typing); it operates unconsciously and is relatively resistant to forgetting.', sort_order: 110 , front_translations: {"es":"Memória Procedural","de":"Prozedurales Gedächtnis","fr":"Mémoire procédurale","tr":"Prosedürel Bellek","nl":"Procedureel geheugen","ru":"Процедурная память","zh":"程序性记忆","pt_BR":"Memória Procedural","pt_PT":"Memória Procedimental"}, back_translations: {"es":"Un tipo de memoria implícita de ancho prazo para como executar habilidades y hábitos (ex.: andar de bicicleta, digitar); opera inconscientemente y es relativamente resistente al esquecimento.","de":"Eine Art des impliziten Langzeitgedächtnisses für die Ausführung von Fertigkeiten und Gewohnheiten (z. B. Fahrradfahren, Tippen); es arbeitet unbewusst und ist relativ resistent gegen Vergessen.","fr":"Un type de mémoire implicite à long terme pour l'exécution de compétences et d'habitudes (par ex., faire du vélo, taper au clavier) ; elle fonctionne inconsciemment et est relativement résistante à l'oubli.","tr":"Becerilerin ve alışkanlıkların nasıl yapılacağına dair bir tür örtük uzun süreli bellek (ör. bisiklet sürmek, klavyede yazmak); bilinçdışı çalışır ve unutmaya karşı nispeten dirençlidir.","nl":"Een type impliciet langetermijngeheugen voor het uitvoeren van vaardigheden en gewoonten (bijv. fietsen, typen); het werkt onbewust en is relatief resistent tegen vergeten.","ru":"Тип имплицитной долговременной памяти для выполнения навыков и привычек (например, езда на велосипеде, печатание); работает бессознательно и относительно устойчива к забыванию.","zh":"一种用于执行技能和习惯的内隐长期记忆（例如骑自行车、打字）；它在无意识中运作，相对不容易遗忘。","pt_BR":"Um tipo de memória implícita de longo prazo para como executar habilidades e hábitos (ex.: andar de bicicleta, digitar); opera inconscientemente e é relativamente resistente ao esquecimento.","pt_PT":"Um tipo de memória implícita de longo prazo para como executar competências e hábitos (ex.: andar de bicicleta, escrever no teclado); opera inconscientemente e é relativamente resistente ao esquecimento."}},
  { id: 'dc-psychology-0111', deck_id: 'deck-psychology', front: 'Encoding, Storage, Retrieval', back: 'The three stages of memory: encoding (transforming information into a memory), storage (maintaining it over time), and retrieval (accessing stored information when needed).', sort_order: 111 , front_translations: {"es":"Codificación, Armazenamento, Recuperación","de":"Enkodierung, Speicherung, Abruf","fr":"Encodage, Stockage, Récupération","tr":"Kodlama, Depolama, Geri Çağırma","nl":"Encodering, Opslag, Ophalen","ru":"Кодирование, хранение, извлечение","zh":"编码、存储、提取","pt_BR":"Codificação, Armazenamento, Recuperação","pt_PT":"Codificação, Armazenamento, Recuperação"}, back_translations: {"es":"Los tres etapas de la memoria: codificación (transformar información en una memoria), almacenamiento (mante-la a lo ancho del tiempo) y recuperación (acessar informaciones armazenadas cuando necesario).","de":"Die drei Stufen des Gedächtnisses: Enkodierung (Umwandlung von Informationen in eine Erinnerung), Speicherung (Aufrechterhaltung über die Zeit) und Abruf (Zugriff auf gespeicherte Informationen bei Bedarf).","fr":"Les trois étapes de la mémoire : l'encodage (transformation de l'information en souvenir), le stockage (maintien dans le temps) et la récupération (accès aux informations stockées en cas de besoin).","tr":"Belleğin üç aşaması: kodlama (bilgiyi bir anıya dönüştürme), depolama (zaman içinde sürdürme) ve geri çağırma (gerektiğinde depolanmış bilgiye erişme).","nl":"De drie fasen van geheugen: encodering (informatie omzetten in een herinnering), opslag (het bewaren in de tijd) en ophalen (toegang krijgen tot opgeslagen informatie wanneer nodig).","ru":"Три стадии памяти: кодирование (преобразование информации в воспоминание), хранение (поддержание во времени) и извлечение (доступ к сохранённой информации при необходимости).","zh":"记忆的三个阶段：编码（将信息转化为记忆）、存储（随时间保持）和提取（在需要时访问存储的信息）。","pt_BR":"Os três estágios da memória: codificação (transformar informação em uma memória), armazenamento (mantê-la ao longo do tempo) e recuperação (acessar informações armazenadas quando necessário).","pt_PT":"As três fases da memória: codificação (transformar informação numa memória), armazenamento (mantê-la ao longo do tempo) e recuperação (aceder a informações armazenadas quando necessário)."}},
  { id: 'dc-psychology-0112', deck_id: 'deck-psychology', front: 'Elaborative Encoding', back: 'Processing new information by connecting it to existing knowledge, generating examples, or creating meaning; produces deeper encoding and better long-term retention than rote repetition.', sort_order: 112 , front_translations: {"es":"Codificación Elaborativa","de":"Elaborative Enkodierung","fr":"Encodage élaboratif","tr":"Ayrıntılandırıcı Kodlama","nl":"Elaboratieve encodering","ru":"Элаборативное кодирование","zh":"精细编码","pt_BR":"Codificação Elaborativa","pt_PT":"Codificação Elaborativa"}, back_translations: {"es":"Processamento de nuevas informaciones conectando-las al conocimiento existente, generando ejemplos o creando significado; produce codificación más profunda y mejor retención de ancho prazo del que a repetición mecánica.","de":"Verarbeitung neuer Informationen durch Verknüpfung mit vorhandenem Wissen, Generierung von Beispielen oder Schaffung von Bedeutung; führt zu tieferer Enkodierung und besserer Langzeitspeicherung als bloßes Wiederholen.","fr":"Traitement de nouvelles informations en les reliant aux connaissances existantes, en générant des exemples ou en créant du sens ; produit un encodage plus profond et une meilleure rétention à long terme que la répétition mécanique.","tr":"Yeni bilgiyi mevcut bilgiye bağlayarak, örnekler üreterek veya anlam yaratarak işleme; ezberlemeden daha derin kodlama ve daha iyi uzun süreli hatırlama sağlar.","nl":"Het verwerken van nieuwe informatie door het te verbinden met bestaande kennis, voorbeelden te genereren of betekenis te creëren; produceert diepere encodering en betere langetermijnretentie dan mechanische herhaling.","ru":"Обработка новой информации путём связывания с существующими знаниями, генерации примеров или создания смысла; обеспечивает более глубокое кодирование и лучшее долговременное удержание, чем механическое повторение.","zh":"通过将新信息与已有知识联系、生成示例或创造意义来处理新信息；比机械重复产生更深层的编码和更好的长期保持。","pt_BR":"Processamento de novas informações conectando-as ao conhecimento existente, gerando exemplos ou criando significado; produz codificação mais profunda e melhor retenção de longo prazo do que a repetição mecânica.","pt_PT":"Processamento de novas informações ligando-as ao conhecimento existente, gerando exemplos ou criando significado; produz codificação mais profunda e melhor retenção a longo prazo do que a repetição mecânica."}},
  { id: 'dc-psychology-0113', deck_id: 'deck-psychology', front: 'Spacing Effect', back: 'Learning is more effective when study sessions are distributed over time (spaced practice) rather than crammed in one session (massed practice); one of the most robust findings in memory research.', sort_order: 113 , front_translations: {"es":"Efeito de Espaçamento","de":"Spacing-Effekt","fr":"Effet d'espacement","tr":"Aralıklı Tekrar Etkisi","nl":"Spacing-effect","ru":"Эффект распределения","zh":"间隔效应","pt_BR":"Efeito de Espaçamento","pt_PT":"Efeito de Espaçamento"}, back_translations: {"es":"La aprendizaje es más eficaz cuando las sesiones de estudio son distribuídas a lo ancho del tiempo (prática espaçada) en vez de concentradas en una única sesión (prática massiva); una de las descubrimientos más robustas en la investigación sobre memoria.","de":"Lernen ist effektiver, wenn Lernsitzungen über die Zeit verteilt werden (verteiltes Üben) als wenn sie in einer Sitzung zusammengedrängt werden (massiertes Üben); einer der robustesten Befunde der Gedächtnisforschung.","fr":"L'apprentissage est plus efficace lorsque les sessions d'étude sont réparties dans le temps (pratique espacée) plutôt que concentrées en une seule session (pratique massée) ; l'un des résultats les plus robustes de la recherche sur la mémoire.","tr":"Öğrenme, çalışma oturumları tek bir oturuma sıkıştırılmak (yoğun çalışma) yerine zamana yayıldığında (aralıklı çalışma) daha etkilidir; bellek araştırmalarının en sağlam bulgularından biridir.","nl":"Leren is effectiever wanneer studiesessies over de tijd worden verspreid (gespreide oefening) in plaats van in één sessie worden samengeperst (massa-oefening); een van de meest robuuste bevindingen in geheugenonderzoek.","ru":"Обучение более эффективно, когда учебные занятия распределены во времени (распределённая практика), а не сконцентрированы в одном занятии (массированная практика); один из самых надёжных результатов в исследованиях памяти.","zh":"当学习分散在不同时间段（分散练习）而非集中在一次（集中练习）时，学习效果更好；这是记忆研究中最可靠的发现之一。","pt_BR":"A aprendizagem é mais eficaz quando as sessões de estudo são distribuídas ao longo do tempo (prática espaçada) em vez de concentradas em uma única sessão (prática massiva); uma das descobertas mais robustas na pesquisa sobre memória.","pt_PT":"A aprendizagem é mais eficaz quando as sessões de estudo são distribuídas ao longo do tempo (prática espaçada) em vez de concentradas numa única sessão (prática massiva); uma das descobertas mais robustas na investigação sobre memória."}},
  { id: 'dc-psychology-0114', deck_id: 'deck-psychology', front: 'Testing Effect (Retrieval Practice)', back: 'Actively retrieving information from memory strengthens retention more than passively re-reading; testing oneself is one of the most effective study strategies.', sort_order: 114 , front_translations: {"es":"Efeito de Teste (Prática de Recuperación)","de":"Testeffekt (Abrufübung)","fr":"Effet de test (Pratique de récupération)","tr":"Test Etkisi (Geri Çağırma Pratiği)","nl":"Testeffect (Oefenen met ophalen)","ru":"Эффект тестирования (Практика извлечения)","zh":"测试效应（提取练习）","pt_BR":"Efeito de Teste (Prática de Recuperação)","pt_PT":"Efeito de Teste (Prática de Recuperação)"}, back_translations: {"es":"Recuperar ativamente informaciones de la memoria fortalece a retención más del que a releitura passiva; testar a si mismo es una de las estrategias de estudio más eficazes.","de":"Aktives Abrufen von Informationen aus dem Gedächtnis stärkt die Behaltensleistung mehr als passives Wiederlesen; sich selbst zu testen ist eine der effektivsten Lernstrategien.","fr":"Récupérer activement des informations de la mémoire renforce la rétention plus que la relecture passive ; se tester soi-même est l'une des stratégies d'étude les plus efficaces.","tr":"Bilgiyi bellekten aktif olarak geri çağırmak, pasif yeniden okumadan daha fazla hatırlamayı güçlendirir; kendini test etmek en etkili çalışma stratejilerinden biridir.","nl":"Het actief ophalen van informatie uit het geheugen versterkt de retentie meer dan passief herlezen; jezelf testen is een van de meest effectieve studiestrategieën.","ru":"Активное извлечение информации из памяти укрепляет запоминание больше, чем пассивное перечитывание; самотестирование — одна из наиболее эффективных стратегий обучения.","zh":"主动从记忆中提取信息比被动重读更能增强记忆保持；自我测试是最有效的学习策略之一。","pt_BR":"Recuperar ativamente informações da memória fortalece a retenção mais do que a releitura passiva; testar a si mesmo é uma das estratégias de estudo mais eficazes.","pt_PT":"Recuperar ativamente informações da memória fortalece a retenção mais do que a releitura passiva; testar-se a si próprio é uma das estratégias de estudo mais eficazes."}},
  { id: 'dc-psychology-0115', deck_id: 'deck-psychology', front: 'Forgetting Curve (Ebbinghaus)', back: 'Hermann Ebbinghaus showed that forgetting is most rapid shortly after learning, then slows over time; spaced repetition counters this curve by reviewing material at optimal intervals.', sort_order: 115 , front_translations: {"es":"Curva del Esquecimento (Ebbinghaus)","de":"Vergessenskurve (Ebbinghaus)","fr":"Courbe de l'oubli (Ebbinghaus)","tr":"Unutma Eğrisi (Ebbinghaus)","nl":"Vergeetcurve (Ebbinghaus)","ru":"Кривая забывания (Эббингауз)","zh":"遗忘曲线（艾宾浩斯）","pt_BR":"Curva do Esquecimento (Ebbinghaus)","pt_PT":"Curva do Esquecimento (Ebbinghaus)"}, back_translations: {"es":"Hermann Ebbinghaus mostrou que el esquecimento es más rápido logo após a aprendizaje y después desacelera con el tiempo; a repetición espaçada combate essa curva revisando el material en intervalos ideais.","de":"Hermann Ebbinghaus zeigte, dass Vergessen kurz nach dem Lernen am schnellsten ist und dann mit der Zeit langsamer wird; verteilte Wiederholung wirkt dieser Kurve entgegen, indem Material in optimalen Abständen wiederholt wird.","fr":"Hermann Ebbinghaus a montré que l'oubli est le plus rapide peu après l'apprentissage, puis ralentit au fil du temps ; la répétition espacée contrecarre cette courbe en révisant le matériel à des intervalles optimaux.","tr":"Hermann Ebbinghaus, unutmanın öğrenmeden hemen sonra en hızlı olduğunu ve zamanla yavaşladığını gösterdi; aralıklı tekrar, materyali optimal aralıklarla gözden geçirerek bu eğriye karşı koyar.","nl":"Hermann Ebbinghaus toonde aan dat vergeten het snelst gaat kort na het leren en dan vertraagt in de loop van de tijd; gespreide herhaling gaat deze curve tegen door materiaal op optimale intervallen te herhalen.","ru":"Герман Эббингауз показал, что забывание наиболее быстрое сразу после заучивания, а затем замедляется со временем; интервальное повторение противодействует этой кривой, повторяя материал через оптимальные интервалы.","zh":"赫尔曼·艾宾浩斯证明遗忘在学习后不久最为迅速，然后随时间减缓；间隔重复通过在最佳间隔复习材料来对抗这条曲线。","pt_BR":"Hermann Ebbinghaus mostrou que o esquecimento é mais rápido logo após a aprendizagem e depois desacelera com o tempo; a repetição espaçada combate essa curva revisando o material em intervalos ideais.","pt_PT":"Hermann Ebbinghaus mostrou que o esquecimento é mais rápido logo após a aprendizagem e depois abranda com o tempo; a repetição espaçada combate esta curva revendo o material em intervalos ideais."}},
  { id: 'dc-psychology-0116', deck_id: 'deck-psychology', front: 'Proactive Interference', back: 'Old information interferes with the learning or retrieval of new information; e.g., remembering an old phone number makes it harder to recall a new one.', sort_order: 116 , front_translations: {"es":"Interferencia Proativa","de":"Proaktive Interferenz","fr":"Interférence proactive","tr":"İleriye Dönük Girişim","nl":"Proactieve interferentie","ru":"Проактивная интерференция","zh":"前摄干扰","pt_BR":"Interferência Proativa","pt_PT":"Interferência Proativa"}, back_translations: {"es":"Informaciones antigas interferem en la aprendizaje o recuperación de nuevas informaciones; ex.: lembrar de un número de telefone antigo torna más difícil recordar un nuevo.","de":"Alte Informationen stören das Lernen oder den Abruf neuer Informationen; z. B. die Erinnerung an eine alte Telefonnummer erschwert es, eine neue zu behalten.","fr":"Les anciennes informations interfèrent avec l'apprentissage ou la récupération de nouvelles informations ; par ex., se souvenir d'un ancien numéro de téléphone rend plus difficile le rappel d'un nouveau.","tr":"Eski bilgiler yeni bilgilerin öğrenilmesini veya geri çağrılmasını engeller; ör. eski bir telefon numarasını hatırlamak yeni birini hatırlamayı zorlaştırır.","nl":"Oude informatie interfereert met het leren of ophalen van nieuwe informatie; bijv. het onthouden van een oud telefoonnummer maakt het moeilijker om een nieuw nummer te herinneren.","ru":"Старая информация мешает усвоению или извлечению новой информации; например, запоминание старого номера телефона затрудняет вспоминание нового.","zh":"旧信息干扰新信息的学习或提取；例如，记住旧电话号码使得记住新号码更加困难。","pt_BR":"Informações antigas interferem na aprendizagem ou recuperação de novas informações; ex.: lembrar de um número de telefone antigo torna mais difícil recordar um novo.","pt_PT":"Informações antigas interferem na aprendizagem ou recuperação de novas informações; ex.: lembrar-se de um número de telefone antigo torna mais difícil recordar um novo."}},
  { id: 'dc-psychology-0117', deck_id: 'deck-psychology', front: 'Retroactive Interference', back: 'New information interferes with the retrieval of previously learned information; e.g., learning a new language makes it harder to recall a previously learned one.', sort_order: 117 , front_translations: {"es":"Interferencia Retroativa","de":"Retroaktive Interferenz","fr":"Interférence rétroactive","tr":"Geriye Dönük Girişim","nl":"Retroactieve interferentie","ru":"Ретроактивная интерференция","zh":"倒摄干扰","pt_BR":"Interferência Retroativa","pt_PT":"Interferência Retroativa"}, back_translations: {"es":"Novas informaciones interferem en la recuperación de informaciones aprendidas anteriormente; ex.: aprender un nuevo idioma torna más difícil recordar un idioma aprendido anteriormente.","de":"Neue Informationen stören den Abruf zuvor gelernter Informationen; z. B. das Erlernen einer neuen Sprache erschwert den Abruf einer zuvor gelernten Sprache.","fr":"Les nouvelles informations interfèrent avec la récupération d'informations apprises précédemment ; par ex., apprendre une nouvelle langue rend plus difficile le rappel d'une langue apprise auparavant.","tr":"Yeni bilgiler daha önce öğrenilmiş bilgilerin geri çağrılmasını engeller; ör. yeni bir dil öğrenmek daha önce öğrenilmiş bir dili hatırlamayı zorlaştırır.","nl":"Nieuwe informatie interfereert met het ophalen van eerder geleerde informatie; bijv. het leren van een nieuwe taal maakt het moeilijker om een eerder geleerde taal te herinneren.","ru":"Новая информация мешает извлечению ранее заученной информации; например, изучение нового языка затрудняет вспоминание ранее изученного.","zh":"新信息干扰对先前学习信息的提取；例如，学习一门新语言使得回忆先前学习的语言更加困难。","pt_BR":"Novas informações interferem na recuperação de informações aprendidas anteriormente; ex.: aprender um novo idioma torna mais difícil recordar um idioma aprendido anteriormente.","pt_PT":"Novas informações interferem na recuperação de informações aprendidas anteriormente; ex.: aprender uma nova língua torna mais difícil recordar uma língua aprendida anteriormente."}},
  { id: 'dc-psychology-0118', deck_id: 'deck-psychology', front: 'Misinformation Effect (Loftus)', back: 'Elizabeth Loftus showed that post-event information can alter memory; misleading questions after witnessing an event can create false memories, with implications for eyewitness testimony.', sort_order: 118 , front_translations: {"es":"Efeito de la Desinformación (Loftus)","de":"Fehlinformationseffekt (Loftus)","fr":"Effet de désinformation (Loftus)","tr":"Yanlış Bilgi Etkisi (Loftus)","nl":"Misinformatie-effect (Loftus)","ru":"Эффект дезинформации (Лофтус)","zh":"错误信息效应（洛夫特斯）","pt_BR":"Efeito da Desinformação (Loftus)","pt_PT":"Efeito da Desinformação (Loftus)"}, back_translations: {"es":"Elizabeth Loftus mostrou que informaciones pós-evento pueden alterar a memoria; perguntas enganosas após testemunhar un evento pueden criar falsas memorias, con implicaciones para el testemunho ocular.","de":"Elizabeth Loftus zeigte, dass Informationen nach einem Ereignis die Erinnerung verändern können; irreführende Fragen nach dem Beobachten eines Ereignisses können falsche Erinnerungen erzeugen, mit Auswirkungen auf die Zeugenaussage.","fr":"Elizabeth Loftus a montré que les informations post-événement peuvent altérer la mémoire ; des questions suggestives après avoir été témoin d'un événement peuvent créer de faux souvenirs, avec des implications pour le témoignage oculaire.","tr":"Elizabeth Loftus, olay sonrası bilgilerin hafızayı değiştirebileceğini gösterdi; bir olaya tanık olduktan sonra yönlendirici sorular yanlış anılar oluşturabilir ve bu durum görgü tanığı ifadeleri için önem taşır.","nl":"Elizabeth Loftus toonde aan dat informatie na een gebeurtenis het geheugen kan veranderen; misleidende vragen na het getuige zijn van een gebeurtenis kunnen valse herinneringen creëren, met implicaties voor getuigenverklaringen.","ru":"Элизабет Лофтус показала, что информация, полученная после события, может изменить воспоминание; наводящие вопросы после наблюдения события могут создавать ложные воспоминания, что имеет значение для показаний очевидцев.","zh":"伊丽莎白·洛夫特斯证明事后信息可以改变记忆；在目击事件后提出误导性问题可以产生虚假记忆，这对目击者证词有重要影响。","pt_BR":"Elizabeth Loftus mostrou que informações pós-evento podem alterar a memória; perguntas enganosas após testemunhar um evento podem criar falsas memórias, com implicações para o testemunho ocular.","pt_PT":"Elizabeth Loftus mostrou que informações pós-evento podem alterar a memória; perguntas enganadoras após testemunhar um evento podem criar falsas memórias, com implicações para o testemunho ocular."}},
  { id: 'dc-psychology-0119', deck_id: 'deck-psychology', front: 'Language Acquisition Device (Chomsky)', back: 'Noam Chomsky\'s proposed innate mental faculty enabling children to acquire language rapidly; evidenced by the universal grammar underlying all human languages.', sort_order: 119 , front_translations: {"es":"Dispositivo de Aquisición de la Linguaje (Chomsky)","de":"Spracherwerbsmechanismus (Chomsky)","fr":"Dispositif d'acquisition du langage (Chomsky)","tr":"Dil Edinim Aygıtı (Chomsky)","nl":"Taalverwervingsmechanisme (Chomsky)","ru":"Устройство усвоения языка (Хомский)","zh":"语言习得装置（乔姆斯基）","pt_BR":"Dispositivo de Aquisição da Linguagem (Chomsky)","pt_PT":"Dispositivo de Aquisição da Linguagem (Chomsky)"}, back_translations: {"es":"Faculdad mental inata proposta por Noam Chomsky que permite a las niños adquirir linguaje rápidamente; evidenciada por la gramática universal subjacente a todas las línguas humanas.","de":"Noam Chomskys vorgeschlagene angeborene geistige Fähigkeit, die es Kindern ermöglicht, Sprache schnell zu erwerben; belegt durch die allen menschlichen Sprachen zugrunde liegende Universalgrammatik.","fr":"La faculté mentale innée proposée par Noam Chomsky permettant aux enfants d'acquérir rapidement le langage ; attestée par la grammaire universelle sous-jacente à toutes les langues humaines.","tr":"Noam Chomsky'nin çocukların dili hızla edinmelerini sağlayan önerdiği doğuştan gelen zihinsel yeti; tüm insan dillerinin temelinde yatan evrensel dilbilgisi ile kanıtlanır.","nl":"Noam Chomsky's voorgestelde aangeboren mentale vermogen dat kinderen in staat stelt snel taal te verwerven; ondersteund door de universele grammatica die aan alle menselijke talen ten grondslag ligt.","ru":"Предложенная Ноамом Хомским врождённая ментальная способность, позволяющая детям быстро усваивать язык; подтверждается универсальной грамматикой, лежащей в основе всех человеческих языков.","zh":"诺姆·乔姆斯基提出的使儿童能够快速习得语言的先天心智能力；所有人类语言中的普遍语法为其提供了证据。","pt_BR":"Faculdade mental inata proposta por Noam Chomsky que permite às crianças adquirir linguagem rapidamente; evidenciada pela gramática universal subjacente a todas as línguas humanas.","pt_PT":"Faculdade mental inata proposta por Noam Chomsky que permite às crianças adquirir linguagem rapidamente; evidenciada pela gramática universal subjacente a todas as línguas humanas."}},
  { id: 'dc-psychology-0120', deck_id: 'deck-psychology', front: 'Sapir-Whorf Hypothesis (Linguistic Relativity)', back: 'The idea that language influences (or determines) thought and perception; the strong version (linguistic determinism) is largely rejected, but weaker versions have empirical support.', sort_order: 120 , front_translations: {"es":"Hipótese de Sapir-Whorf (Relatividad Linguística)","de":"Sapir-Whorf-Hypothese (Linguistische Relativität)","fr":"Hypothèse de Sapir-Whorf (Relativité linguistique)","tr":"Sapir-Whorf Hipotezi (Dilsel Görelilik)","nl":"Sapir-Whorf-hypothese (Taalkundige relativiteit)","ru":"Гипотеза Сепира-Уорфа (Лингвистическая относительность)","zh":"萨丕尔-沃尔夫假说（语言相对论）","pt_BR":"Hipótese de Sapir-Whorf (Relatividade Linguística)","pt_PT":"Hipótese de Sapir-Whorf (Relatividade Linguística)"}, back_translations: {"es":"La ideia de que a linguaje influencia (o determina) el pensamiento y a percepción; a versão fuerte (determinismo linguístico) es amplamente rejeitada, pero versões más débiles tienen suporte empírico.","de":"Die Idee, dass Sprache das Denken und die Wahrnehmung beeinflusst (oder bestimmt); die starke Version (linguistischer Determinismus) ist weitgehend widerlegt, aber schwächere Versionen haben empirische Unterstützung.","fr":"L'idée que la langue influence (ou détermine) la pensée et la perception ; la version forte (déterminisme linguistique) est largement rejetée, mais les versions plus faibles ont un soutien empirique.","tr":"Dilin düşünce ve algıyı etkilediği (veya belirlediği) fikri; güçlü versiyonu (dilsel belirleyicilik) büyük ölçüde reddedilmiştir, ancak daha zayıf versiyonları ampirik desteke sahiptir.","nl":"Het idee dat taal het denken en de waarneming beïnvloedt (of bepaalt); de sterke versie (taalkundig determinisme) is grotendeels verworpen, maar zwakkere versies hebben empirische ondersteuning.","ru":"Идея о том, что язык влияет (или определяет) мышление и восприятие; сильная версия (лингвистический детерминизм) в значительной степени отвергнута, но более слабые версии имеют эмпирическую поддержку.","zh":"语言影响（或决定）思维和感知的观点；强版本（语言决定论）基本已被否定，但较弱版本得到了实证支持。","pt_BR":"A ideia de que a linguagem influencia (ou determina) o pensamento e a percepção; a versão forte (determinismo linguístico) é amplamente rejeitada, mas versões mais fracas têm suporte empírico.","pt_PT":"A ideia de que a linguagem influencia (ou determina) o pensamento e a perceção; a versão forte (determinismo linguístico) é amplamente rejeitada, mas versões mais fracas têm suporte empírico."}},
  { id: 'dc-psychology-0121', deck_id: 'deck-psychology', front: 'Stress (Psychological)', back: 'A state of psychological and physiological arousal produced when demands exceed a person\'s perceived ability to cope; acute stress can be adaptive, but chronic stress causes harm.', sort_order: 121 , front_translations: {"es":"Estresse (Psicológico)","de":"Stress (Psychologisch)","fr":"Stress (Psychologique)","tr":"Stres (Psikolojik)","nl":"Stress (Psychologisch)","ru":"Стресс (Психологический)","zh":"压力（心理学）","pt_BR":"Estresse (Psicológico)","pt_PT":"Stress (Psicológico)"}, back_translations: {"es":"Un estado de excitación psicológica y fisiológica producido cuando las demandas excedem a capacidad percebida de enfrentamento de una persona; el estresse agudo puede ser adaptativo, pero el estresse crónico causa danos.","de":"Ein Zustand psychologischer und physiologischer Erregung, der entsteht, wenn Anforderungen die wahrgenommene Bewältigungsfähigkeit einer Person übersteigen; akuter Stress kann adaptiv sein, aber chronischer Stress verursacht Schäden.","fr":"Un état d'activation psychologique et physiologique produit lorsque les exigences dépassent la capacité perçue d'une personne à faire face ; le stress aigu peut être adaptatif, mais le stress chronique cause des dommages.","tr":"Talepler bir kişinin algılanan başa çıkma kapasitesini aştığında ortaya çıkan psikolojik ve fizyolojik uyarılma durumu; akut stres uyumsal olabilir, ancak kronik stres zarar verir.","nl":"Een staat van psychologische en fysiologische opwinding die ontstaat wanneer eisen het waargenomen vermogen van een persoon om ermee om te gaan overschrijden; acute stress kan adaptief zijn, maar chronische stress veroorzaakt schade.","ru":"Состояние психологического и физиологического возбуждения, возникающее, когда требования превышают воспринимаемую способность человека справляться; острый стресс может быть адаптивным, но хронический стресс наносит вред.","zh":"当需求超过个人感知的应对能力时产生的心理和生理唤醒状态；急性压力可以是适应性的，但慢性压力会造成伤害。","pt_BR":"Um estado de excitação psicológica e fisiológica produzido quando as demandas excedem a capacidade percebida de enfrentamento de uma pessoa; o estresse agudo pode ser adaptativo, mas o estresse crônico causa danos.","pt_PT":"Um estado de ativação psicológica e fisiológica produzido quando as exigências excedem a capacidade percebida de uma pessoa para lidar com elas; o stress agudo pode ser adaptativo, mas o stress crónico causa danos."}},
  { id: 'dc-psychology-0122', deck_id: 'deck-psychology', front: 'General Adaptation Syndrome (Selye)', back: 'Hans Selye\'s model of the physiological stress response in three stages: alarm (fight-or-flight activation), resistance (body adapts), and exhaustion (resources depleted, illness risk rises).', sort_order: 122 , front_translations: {"es":"Síndrome de Adaptación Geral (Selye)","de":"Allgemeines Adaptationssyndrom (Selye)","fr":"Syndrome général d'adaptation (Selye)","tr":"Genel Uyum Sendromu (Selye)","nl":"Algemeen adaptatiesyndroom (Selye)","ru":"Общий адаптационный синдром (Селье)","zh":"一般适应综合征（塞利）","pt_BR":"Síndrome de Adaptação Geral (Selye)","pt_PT":"Síndrome de Adaptação Geral (Selye)"}, back_translations: {"es":"El modelo de Hans Selye de la respuesta fisiológica al estresse en tres etapas: alarme (ativación de luta o fuga), resistencia (el cuerpo se adapta) y exaustão (recursos esgotados, riesgo de enfermedad aumenta).","de":"Hans Selyes Modell der physiologischen Stressreaktion in drei Phasen: Alarm (Kampf-oder-Flucht-Aktivierung), Widerstand (Körper passt sich an) und Erschöpfung (Ressourcen erschöpft, Krankheitsrisiko steigt).","fr":"Le modèle de Hans Selye de la réponse physiologique au stress en trois étapes : alarme (activation combat-fuite), résistance (le corps s'adapte) et épuisement (ressources épuisées, risque de maladie augmente).","tr":"Hans Selye'nin fizyolojik stres tepkisini üç aşamada açıklayan modeli: alarm (savaş ya da kaç aktivasyonu), direnç (vücut uyum sağlar) ve tükenme (kaynaklar tükenir, hastalık riski artar).","nl":"Hans Selye's model van de fysiologische stressrespons in drie fasen: alarm (vecht-of-vluchtactivering), weerstand (lichaam past zich aan) en uitputting (reserves uitgeput, ziekterisico stijgt).","ru":"Модель Ганса Селье физиологической реакции на стресс в три стадии: тревога (активация «бей или беги»), сопротивление (организм адаптируется) и истощение (ресурсы исчерпаны, возрастает риск заболеваний).","zh":"汉斯·塞利的生理应激反应三阶段模型：警觉期（战斗或逃跑激活）、抵抗期（身体适应）和衰竭期（资源耗尽，患病风险上升）。","pt_BR":"O modelo de Hans Selye da resposta fisiológica ao estresse em três estágios: alarme (ativação de luta ou fuga), resistência (o corpo se adapta) e exaustão (recursos esgotados, risco de doença aumenta).","pt_PT":"O modelo de Hans Selye da resposta fisiológica ao stress em três fases: alarme (ativação de luta ou fuga), resistência (o corpo adapta-se) e exaustão (recursos esgotados, risco de doença aumenta)."}},
  { id: 'dc-psychology-0123', deck_id: 'deck-psychology', front: 'Coping Strategies', back: 'Methods used to manage stress: problem-focused coping addresses the source of stress directly; emotion-focused coping manages emotional response. Adaptive coping improves well-being; maladaptive strategies worsen it.', sort_order: 123 , front_translations: {"es":"Estratégias de Enfrentamento","de":"Bewältigungsstrategien","fr":"Stratégies d'adaptation","tr":"Başa Çıkma Stratejileri","nl":"Copingstrategieën","ru":"Стратегии совладания","zh":"应对策略","pt_BR":"Estratégias de Enfrentamento","pt_PT":"Estratégias de Coping"}, back_translations: {"es":"Métodos usados para gerenciar el estresse: el enfrentamento focado en el problema aborda directamente a fonte del estresse; el enfrentamento focado en la emoción gerencia a respuesta emocional. El enfrentamento adaptativo melhora el bem-estar; estrategias mal-adaptativas el pioram.","de":"Methoden zur Stressbewältigung: problemfokussiertes Coping geht die Stressquelle direkt an; emotionsfokussiertes Coping bewältigt die emotionale Reaktion. Adaptives Coping verbessert das Wohlbefinden; maladaptive Strategien verschlechtern es.","fr":"Méthodes utilisées pour gérer le stress : le coping centré sur le problème s'attaque directement à la source du stress ; le coping centré sur l'émotion gère la réponse émotionnelle. Le coping adaptatif améliore le bien-être ; les stratégies inadaptées l'aggravent.","tr":"Stresi yönetmek için kullanılan yöntemler: problem odaklı başa çıkma stresin kaynağını doğrudan ele alır; duygu odaklı başa çıkma duygusal tepkiyi yönetir. Uyumlu başa çıkma iyilik halini artırır; uyumsuz stratejiler onu kötüleştirir.","nl":"Methoden om met stress om te gaan: probleemgerichte coping pakt de bron van stress direct aan; emotiegerichte coping beheert de emotionele reactie. Adaptieve coping verbetert het welzijn; maladaptieve strategieën verslechteren het.","ru":"Методы управления стрессом: проблемно-ориентированное совладание направлено непосредственно на источник стресса; эмоционально-ориентированное совладание управляет эмоциональной реакцией. Адаптивное совладание улучшает благополучие; дезадаптивные стратегии ухудшают его.","zh":"用于管理压力的方法：问题聚焦型应对直接处理压力来源；情绪聚焦型应对管理情绪反应。适应性应对改善幸福感；不适应策略使其恶化。","pt_BR":"Métodos usados para gerenciar o estresse: o enfrentamento focado no problema aborda diretamente a fonte do estresse; o enfrentamento focado na emoção gerencia a resposta emocional. O enfrentamento adaptativo melhora o bem-estar; estratégias mal-adaptativas o pioram.","pt_PT":"Métodos usados para gerir o stress: o coping focado no problema aborda diretamente a fonte do stress; o coping focado na emoção gere a resposta emocional. O coping adaptativo melhora o bem-estar; estratégias mal-adaptativas pioram-no."}},
  { id: 'dc-psychology-0124', deck_id: 'deck-psychology', front: 'Emotion (Basic)', back: 'Paul Ekman identified six universal basic emotions — happiness, sadness, fear, disgust, anger, and surprise — with cross-cultural facial expressions; evidence for a biological basis of emotion.', sort_order: 124 , front_translations: {"es":"Emoción (Básica)","de":"Emotion (Grundlagen)","fr":"Émotion (Fondamentales)","tr":"Duygu (Temel)","nl":"Emotie (Basis)","ru":"Эмоции (Базовые)","zh":"情绪（基本）","pt_BR":"Emoção (Básica)","pt_PT":"Emoção (Básica)"}, back_translations: {"es":"Paul Ekman identificou seis emociones básicas universais — felicidad, tristeza, medo, nojo, raiva y surpresa — con expresiones faciais transculturais; evidencia de una base biológica de la emoción.","de":"Paul Ekman identifizierte sechs universelle Grundemotionen — Freude, Traurigkeit, Angst, Ekel, Wut und Überraschung — mit kulturübergreifenden Gesichtsausdrücken; Hinweise auf eine biologische Grundlage von Emotionen.","fr":"Paul Ekman a identifié six émotions fondamentales universelles — bonheur, tristesse, peur, dégoût, colère et surprise — avec des expressions faciales interculturelles ; preuve d'une base biologique des émotions.","tr":"Paul Ekman altı evrensel temel duyguyu tanımladı — mutluluk, üzüntü, korku, tiksinme, öfke ve şaşkınlık — kültürler arası yüz ifadeleriyle; duygunun biyolojik temeline dair kanıt.","nl":"Paul Ekman identificeerde zes universele basisemoties — geluk, verdriet, angst, walging, woede en verrassing — met cross-culturele gezichtsuitdrukkingen; bewijs voor een biologische basis van emotie.","ru":"Пол Экман выделил шесть универсальных базовых эмоций — счастье, грусть, страх, отвращение, гнев и удивление — с межкультурными выражениями лица; свидетельство биологической основы эмоций.","zh":"保罗·埃克曼确定了六种普遍的基本情绪——快乐、悲伤、恐惧、厌恶、愤怒和惊讶——具有跨文化的面部表情；为情绪的生物学基础提供了证据。","pt_BR":"Paul Ekman identificou seis emoções básicas universais — felicidade, tristeza, medo, nojo, raiva e surpresa — com expressões faciais transculturais; evidência de uma base biológica da emoção.","pt_PT":"Paul Ekman identificou seis emoções básicas universais — felicidade, tristeza, medo, nojo, raiva e surpresa — com expressões faciais transculturais; evidência de uma base biológica da emoção."}},
  { id: 'dc-psychology-0125', deck_id: 'deck-psychology', front: 'James-Lange Theory of Emotion', back: 'Proposes that emotions result from our perception of physiological arousal: we see a bear → body reacts (heart races) → we feel afraid. Emotion follows physical response.', sort_order: 125 , front_translations: {"es":"Teoria de la Emoción de James-Lange","de":"James-Lange-Theorie der Emotion","fr":"Théorie des émotions de James-Lange","tr":"James-Lange Duygu Teorisi","nl":"James-Lange-theorie van emotie","ru":"Теория эмоций Джеймса-Ланге","zh":"詹姆斯-兰格情绪理论","pt_BR":"Teoria da Emoção de James-Lange","pt_PT":"Teoria da Emoção de James-Lange"}, back_translations: {"es":"Propõe que las emociones resultan de la nuestra percepción de la excitación fisiológica: vemos un urso → el cuerpo reage (corazón acelera) → sentimos medo. La emoción sigue a respuesta física.","de":"Besagt, dass Emotionen aus unserer Wahrnehmung physiologischer Erregung resultieren: Wir sehen einen Bären → der Körper reagiert (Herz rast) → wir empfinden Angst. Die Emotion folgt der körperlichen Reaktion.","fr":"Propose que les émotions résultent de notre perception de l'activation physiologique : nous voyons un ours → le corps réagit (le cœur s'accélère) → nous ressentons de la peur. L'émotion suit la réponse physique.","tr":"Duyguların fizyolojik uyarılma algımızdan kaynaklandığını öne sürer: bir ayı görürüz → vücut tepki verir (kalp hızlanır) → korku hissederiz. Duygu, fiziksel tepkiyi takip eder.","nl":"Stelt dat emoties voortkomen uit onze waarneming van fysiologische opwinding: we zien een beer → het lichaam reageert (hart gaat sneller slaan) → we voelen angst. Emotie volgt op de fysieke reactie.","ru":"Предполагает, что эмоции возникают в результате восприятия физиологического возбуждения: мы видим медведя → тело реагирует (сердце учащается) → мы чувствуем страх. Эмоция следует за физической реакцией.","zh":"认为情绪源于我们对生理唤醒的感知：我们看到熊→身体反应（心跳加速）→我们感到恐惧。情绪跟随生理反应而产生。","pt_BR":"Propõe que as emoções resultam da nossa percepção da excitação fisiológica: vemos um urso → o corpo reage (coração acelera) → sentimos medo. A emoção segue a resposta física.","pt_PT":"Propõe que as emoções resultam da nossa perceção da excitação fisiológica: vemos um urso → o corpo reage (coração acelera) → sentimos medo. A emoção segue a resposta física."}},
  { id: 'dc-psychology-0126', deck_id: 'deck-psychology', front: 'Cannon-Bard Theory of Emotion', back: 'Proposes that physiological arousal and emotional experience occur simultaneously and independently in response to a stimulus; challenges the James-Lange theory.', sort_order: 126 , front_translations: {"es":"Teoria de la Emoción de Cannon-Bard","de":"Cannon-Bard-Theorie der Emotion","fr":"Théorie des émotions de Cannon-Bard","tr":"Cannon-Bard Duygu Teorisi","nl":"Cannon-Bard-theorie van emotie","ru":"Теория эмоций Кэннона-Барда","zh":"坎农-巴德情绪理论","pt_BR":"Teoria da Emoção de Cannon-Bard","pt_PT":"Teoria da Emoção de Cannon-Bard"}, back_translations: {"es":"Propõe que a excitación fisiológica y a experiencia emocional ocurren simultáneamente y de forma independente en respuesta a un estímulo; desafia a teoría de James-Lange.","de":"Besagt, dass physiologische Erregung und emotionales Erleben gleichzeitig und unabhängig voneinander als Reaktion auf einen Reiz auftreten; stellt die James-Lange-Theorie in Frage.","fr":"Propose que l'activation physiologique et l'expérience émotionnelle se produisent simultanément et indépendamment en réponse à un stimulus ; remet en question la théorie de James-Lange.","tr":"Fizyolojik uyarılma ve duygusal deneyimin bir uyarana yanıt olarak eş zamanlı ve bağımsız olarak gerçekleştiğini öne sürer; James-Lange teorisine meydan okur.","nl":"Stelt dat fysiologische opwinding en emotionele ervaring gelijktijdig en onafhankelijk van elkaar optreden als reactie op een stimulus; daagt de James-Lange-theorie uit.","ru":"Предполагает, что физиологическое возбуждение и эмоциональное переживание возникают одновременно и независимо друг от друга в ответ на стимул; оспаривает теорию Джеймса-Ланге.","zh":"认为生理唤醒和情绪体验在对刺激的反应中同时且独立地发生；挑战了詹姆斯-兰格理论。","pt_BR":"Propõe que a excitação fisiológica e a experiência emocional ocorrem simultaneamente e de forma independente em resposta a um estímulo; desafia a teoria de James-Lange.","pt_PT":"Propõe que a excitação fisiológica e a experiência emocional ocorrem simultaneamente e de forma independente em resposta a um estímulo; desafia a teoria de James-Lange."}},
  { id: 'dc-psychology-0127', deck_id: 'deck-psychology', front: 'Two-Factor Theory (Schachter-Singer)', back: 'Emotion involves two factors: physiological arousal plus a cognitive label applied to the arousal based on context. The same arousal can produce different emotions depending on the situation.', sort_order: 127 , front_translations: {"es":"Teoria de los Dois Fatores (Schachter-Singer)","de":"Zwei-Faktoren-Theorie (Schachter-Singer)","fr":"Théorie bifactorielle (Schachter-Singer)","tr":"İki Faktör Teorisi (Schachter-Singer)","nl":"Tweefactorentheorie (Schachter-Singer)","ru":"Двухфакторная теория (Шехтер-Сингер)","zh":"两因素理论（沙赫特-辛格）","pt_BR":"Teoria dos Dois Fatores (Schachter-Singer)","pt_PT":"Teoria dos Dois Fatores (Schachter-Singer)"}, back_translations: {"es":"La emoción involucra de los fatores: excitación fisiológica más un rótulo cognitivo aplicado a la excitación con base en el contexto. La misma excitación puede produzir diferentes emociones dependendo de la situación.","de":"Emotion umfasst zwei Faktoren: physiologische Erregung plus eine kognitive Zuschreibung, die der Erregung je nach Kontext gegeben wird. Dieselbe Erregung kann je nach Situation unterschiedliche Emotionen hervorrufen.","fr":"L'émotion implique deux facteurs : l'activation physiologique plus une étiquette cognitive appliquée à l'activation en fonction du contexte. La même activation peut produire différentes émotions selon la situation.","tr":"Duygu iki faktör içerir: fizyolojik uyarılma artı bağlama göre uyarılmaya uygulanan bilişsel bir etiket. Aynı uyarılma duruma bağlı olarak farklı duygular üretebilir.","nl":"Emotie omvat twee factoren: fysiologische opwinding plus een cognitief label dat op basis van de context aan de opwinding wordt toegekend. Dezelfde opwinding kan verschillende emoties opleveren afhankelijk van de situatie.","ru":"Эмоция включает два фактора: физиологическое возбуждение плюс когнитивная интерпретация возбуждения на основе контекста. Одно и то же возбуждение может порождать разные эмоции в зависимости от ситуации.","zh":"情绪涉及两个因素：生理唤醒加上根据情境对唤醒进行的认知标记。相同的唤醒可以根据不同情境产生不同的情绪。","pt_BR":"A emoção envolve dois fatores: excitação fisiológica mais um rótulo cognitivo aplicado à excitação com base no contexto. A mesma excitação pode produzir diferentes emoções dependendo da situação.","pt_PT":"A emoção envolve dois fatores: excitação fisiológica mais um rótulo cognitivo aplicado à excitação com base no contexto. A mesma excitação pode produzir diferentes emoções dependendo da situação."}},
  { id: 'dc-psychology-0128', deck_id: 'deck-psychology', front: 'Emotional Intelligence (EI)', back: 'The ability to perceive, understand, manage, and use emotions effectively; Goleman\'s model includes self-awareness, self-regulation, motivation, empathy, and social skills.', sort_order: 128 , front_translations: {"es":"Inteligencia Emocional (IE)","de":"Emotionale Intelligenz (EI)","fr":"Intelligence émotionnelle (IE)","tr":"Duygusal Zekâ (DZ)","nl":"Emotionele intelligentie (EI)","ru":"Эмоциональный интеллект (ЭИ)","zh":"情商（EI）","pt_BR":"Inteligência Emocional (IE)","pt_PT":"Inteligência Emocional (IE)"}, back_translations: {"es":"La capacidad de perceber, compreender, gerenciar y usar emociones de forma eficaz; el modelo de Goleman incluye autoconsciencia, autorregulación, motivación, empatia y habilidades sociais.","de":"Die Fähigkeit, Emotionen effektiv wahrzunehmen, zu verstehen, zu steuern und zu nutzen; Golemans Modell umfasst Selbstwahrnehmung, Selbstregulierung, Motivation, Empathie und soziale Kompetenz.","fr":"La capacité de percevoir, comprendre, gérer et utiliser les émotions efficacement ; le modèle de Goleman comprend la conscience de soi, l'autorégulation, la motivation, l'empathie et les compétences sociales.","tr":"Duyguları etkili bir şekilde algılama, anlama, yönetme ve kullanma becerisi; Goleman'ın modeli öz farkındalık, öz düzenleme, motivasyon, empati ve sosyal becerileri içerir.","nl":"Het vermogen om emoties effectief waar te nemen, te begrijpen, te beheersen en te gebruiken; Golemans model omvat zelfbewustzijn, zelfregulering, motivatie, empathie en sociale vaardigheden.","ru":"Способность эффективно воспринимать, понимать, управлять и использовать эмоции; модель Гоулмана включает самосознание, саморегуляцию, мотивацию, эмпатию и социальные навыки.","zh":"有效感知、理解、管理和运用情绪的能力；戈尔曼的模型包括自我意识、自我调节、动机、共情和社交技能。","pt_BR":"A capacidade de perceber, compreender, gerenciar e usar emoções de forma eficaz; o modelo de Goleman inclui autoconsciência, autorregulação, motivação, empatia e habilidades sociais.","pt_PT":"A capacidade de perceber, compreender, gerir e usar emoções de forma eficaz; o modelo de Goleman inclui autoconsciência, autorregulação, motivação, empatia e competências sociais."}},
  { id: 'dc-psychology-0129', deck_id: 'deck-psychology', front: 'Empathy', back: 'The ability to understand and share the feelings of another person. Cognitive empathy is understanding another\'s perspective; affective empathy is sharing their emotional experience.', sort_order: 129 , front_translations: {"es":"Empatia","de":"Empathie","fr":"Empathie","tr":"Empati","nl":"Empathie","ru":"Эмпатия","zh":"共情","pt_BR":"Empatia","pt_PT":"Empatia"}, back_translations: {"es":"La capacidad de compreender y compartilhar los sentimientos de outra persona. La empatia cognitiva es compreender a perspectiva del outro; a empatia afectiva es compartilhar su experiencia emocional.","de":"Die Fähigkeit, die Gefühle einer anderen Person zu verstehen und zu teilen. Kognitive Empathie bedeutet, die Perspektive des anderen zu verstehen; affektive Empathie bedeutet, dessen emotionale Erfahrung zu teilen.","fr":"La capacité de comprendre et de partager les sentiments d'une autre personne. L'empathie cognitive consiste à comprendre la perspective de l'autre ; l'empathie affective consiste à partager son expérience émotionnelle.","tr":"Başka bir kişinin duygularını anlama ve paylaşma becerisi. Bilişsel empati başkasının bakış açısını anlamaktır; duygusal empati onun duygusal deneyimini paylaşmaktır.","nl":"Het vermogen om de gevoelens van een ander te begrijpen en te delen. Cognitieve empathie is het begrijpen van het perspectief van een ander; affectieve empathie is het delen van hun emotionele ervaring.","ru":"Способность понимать и разделять чувства другого человека. Когнитивная эмпатия — понимание точки зрения другого; аффективная эмпатия — разделение его эмоционального опыта.","zh":"理解和分享他人感受的能力。认知共情是理解他人的观点；情感共情是分享他人的情绪体验。","pt_BR":"A capacidade de compreender e compartilhar os sentimentos de outra pessoa. A empatia cognitiva é compreender a perspectiva do outro; a empatia afetiva é compartilhar sua experiência emocional.","pt_PT":"A capacidade de compreender e partilhar os sentimentos de outra pessoa. A empatia cognitiva é compreender a perspetiva do outro; a empatia afetiva é partilhar a sua experiência emocional."}},
  { id: 'dc-psychology-0130', deck_id: 'deck-psychology', front: 'Prosocial Behavior', back: 'Voluntary actions intended to benefit others, including helping, sharing, donating, and cooperating; influenced by empathy, social norms, and situational factors.', sort_order: 130 , front_translations: {"es":"Comportamento Prossocial","de":"Prosoziales Verhalten","fr":"Comportement prosocial","tr":"Prososyal Davranış","nl":"Prosociaal gedrag","ru":"Просоциальное поведение","zh":"亲社会行为","pt_BR":"Comportamento Prossocial","pt_PT":"Comportamento Prossocial"}, back_translations: {"es":"Aciones voluntárias destinadas a beneficiar los outros, incluyendo ajudar, compartilhar, doar y cooperar; influenciadas por la empatia, normas sociais y fatores situacionais.","de":"Freiwillige Handlungen zum Nutzen anderer, einschließlich Helfen, Teilen, Spenden und Kooperieren; beeinflusst durch Empathie, soziale Normen und situative Faktoren.","fr":"Actions volontaires destinées à bénéficier aux autres, y compris aider, partager, donner et coopérer ; influencées par l'empathie, les normes sociales et les facteurs situationnels.","tr":"Yardım etme, paylaşma, bağışta bulunma ve iş birliği yapma dahil olmak üzere başkalarına fayda sağlamaya yönelik gönüllü eylemler; empati, sosyal normlar ve durumsal faktörlerden etkilenir.","nl":"Vrijwillige acties bedoeld om anderen te helpen, waaronder hulpverlening, delen, doneren en samenwerken; beïnvloed door empathie, sociale normen en situationele factoren.","ru":"Добровольные действия, направленные на пользу другим, включая помощь, обмен, пожертвования и сотрудничество; зависят от эмпатии, социальных норм и ситуационных факторов.","zh":"旨在使他人受益的自愿行为，包括帮助、分享、捐赠和合作；受共情、社会规范和情境因素的影响。","pt_BR":"Ações voluntárias destinadas a beneficiar os outros, incluindo ajudar, compartilhar, doar e cooperar; influenciadas pela empatia, normas sociais e fatores situacionais.","pt_PT":"Ações voluntárias destinadas a beneficiar os outros, incluindo ajudar, partilhar, doar e cooperar; influenciadas pela empatia, normas sociais e fatores situacionais."}},
  { id: 'dc-psychology-0131', deck_id: 'deck-psychology', front: 'Altruism', back: 'Selfless behavior that benefits others at some cost to oneself, without expectation of reward; evolutionary explanations include kin selection and reciprocal altruism.', sort_order: 131 , front_translations: {"es":"Altruísmo","de":"Altruismus","fr":"Altruisme","tr":"Özgecilik","nl":"Altruïsme","ru":"Альтруизм","zh":"利他主义","pt_BR":"Altruísmo","pt_PT":"Altruísmo"}, back_translations: {"es":"Comportamento altruísta que beneficia los outros a algún costo para si mismo, sin expectativa de recompensa; explicaciones evolutivas incluyen seleción de parentesco y altruísmo recíproco.","de":"Selbstloses Verhalten, das anderen auf eigene Kosten nützt, ohne Erwartung einer Belohnung; evolutionäre Erklärungen umfassen Verwandtenselektion und reziproken Altruismus.","fr":"Comportement désintéressé qui profite aux autres au prix d'un coût pour soi-même, sans attente de récompense ; les explications évolutionnistes incluent la sélection de parentèle et l'altruisme réciproque.","tr":"Ödül beklentisi olmaksızın, kişinin kendisine bir maliyetle başkalarına fayda sağlayan özverili davranış; evrimsel açıklamalar akraba seçilimi ve karşılıklı özgeciliği içerir.","nl":"Onzelfzuchtig gedrag dat anderen ten goede komt ten koste van zichzelf, zonder verwachting van beloning; evolutionaire verklaringen omvatten verwantenselectie en wederkerig altruïsme.","ru":"Бескорыстное поведение, приносящее пользу другим ценой собственных затрат, без ожидания вознаграждения; эволюционные объяснения включают родственный отбор и взаимный альтруизм.","zh":"不期望回报的、以自身为代价使他人受益的无私行为；进化论解释包括亲缘选择和互惠利他主义。","pt_BR":"Comportamento altruísta que beneficia os outros a algum custo para si mesmo, sem expectativa de recompensa; explicações evolutivas incluem seleção de parentesco e altruísmo recíproco.","pt_PT":"Comportamento altruísta que beneficia os outros a algum custo para si próprio, sem expectativa de recompensa; explicações evolutivas incluem seleção de parentesco e altruísmo recíproco."}},
  { id: 'dc-psychology-0132', deck_id: 'deck-psychology', front: 'Aggression', back: 'Behavior intended to harm another person; can be physical or verbal, reactive (hostile, emotional) or proactive (instrumental, goal-directed). Influenced by biological, social, and situational factors.', sort_order: 132 , front_translations: {"es":"Agresión","de":"Aggression","fr":"Agression","tr":"Saldırganlık","nl":"Agressie","ru":"Агрессия","zh":"攻击行为","pt_BR":"Agressão","pt_PT":"Agressão"}, back_translations: {"es":"Comportamento destinado a prejudicar outra persona; puede ser físico o verbal, reativo (hostil, emocional) o proativo (instrumental, direcionado a un objetivo). Influenciado por fatores biológicos, sociais y situacionais.","de":"Verhalten mit der Absicht, einer anderen Person zu schaden; kann physisch oder verbal, reaktiv (feindselig, emotional) oder proaktiv (instrumentell, zielgerichtet) sein. Beeinflusst durch biologische, soziale und situative Faktoren.","fr":"Comportement destiné à nuire à autrui ; peut être physique ou verbal, réactif (hostile, émotionnel) ou proactif (instrumental, orienté vers un but). Influencé par des facteurs biologiques, sociaux et situationnels.","tr":"Başka bir kişiye zarar vermeye yönelik davranış; fiziksel veya sözel, tepkisel (düşmanca, duygusal) veya proaktif (araçsal, hedefe yönelik) olabilir. Biyolojik, sosyal ve durumsal faktörlerden etkilenir.","nl":"Gedrag bedoeld om een ander te schaden; kan fysiek of verbaal zijn, reactief (vijandig, emotioneel) of proactief (instrumenteel, doelgericht). Beïnvloed door biologische, sociale en situationele factoren.","ru":"Поведение, направленное на причинение вреда другому человеку; может быть физическим или вербальным, реактивным (враждебным, эмоциональным) или проактивным (инструментальным, целенаправленным). Зависит от биологических, социальных и ситуационных факторов.","zh":"旨在伤害他人的行为；可以是身体的或言语的，反应性的（敌意的、情绪性的）或主动性的（工具性的、目标导向的）。受生物、社会和情境因素的影响。","pt_BR":"Comportamento destinado a prejudicar outra pessoa; pode ser físico ou verbal, reativo (hostil, emocional) ou proativo (instrumental, direcionado a um objetivo). Influenciado por fatores biológicos, sociais e situacionais.","pt_PT":"Comportamento destinado a prejudicar outra pessoa; pode ser físico ou verbal, reativo (hostil, emocional) ou proativo (instrumental, dirigido a um objetivo). Influenciado por fatores biológicos, sociais e situacionais."}},
  { id: 'dc-psychology-0133', deck_id: 'deck-psychology', front: 'Frustration-Aggression Hypothesis', back: 'Proposes that frustration (the blocking of goal-directed behavior) always leads to aggression; later refined to suggest frustration increases the likelihood but does not inevitably cause aggression.', sort_order: 133 , front_translations: {"es":"Hipótese de la Frustración-Agresión","de":"Frustrations-Aggressions-Hypothese","fr":"Hypothèse frustration-agression","tr":"Engellenme-Saldırganlık Hipotezi","nl":"Frustratie-agressiehypothese","ru":"Гипотеза фрустрации-агрессии","zh":"挫折-攻击假说","pt_BR":"Hipótese da Frustração-Agressão","pt_PT":"Hipótese da Frustração-Agressão"}, back_translations: {"es":"Propõe que a frustración (el bloqueio de comportamiento direcionado a un objetivo) siempre leva a la agresión; posteriormente refinada para sugerir que a frustración aumenta a probabilidad, pero no causa inevitavelmente a agresión.","de":"Besagt, dass Frustration (die Blockierung zielgerichteten Verhaltens) immer zu Aggression führt; später dahingehend verfeinert, dass Frustration die Wahrscheinlichkeit erhöht, aber nicht zwangsläufig Aggression verursacht.","fr":"Propose que la frustration (le blocage d'un comportement dirigé vers un but) mène toujours à l'agression ; ultérieurement affinée pour suggérer que la frustration augmente la probabilité mais ne cause pas inévitablement l'agression.","tr":"Engellenmenin (hedefe yönelik davranışın engellenmesi) her zaman saldırganlığa yol açtığını öne sürer; daha sonra engellenmenin olasılığı artırdığı ancak kaçınılmaz olarak saldırganlığa neden olmadığı şeklinde revize edilmiştir.","nl":"Stelt dat frustratie (het blokkeren van doelgericht gedrag) altijd tot agressie leidt; later verfijnd om te suggereren dat frustratie de kans vergroot maar niet onvermijdelijk agressie veroorzaakt.","ru":"Предполагает, что фрустрация (блокирование целенаправленного поведения) всегда ведёт к агрессии; позднее уточнена: фрустрация повышает вероятность, но не обязательно вызывает агрессию.","zh":"认为挫折（目标导向行为的阻碍）总是导致攻击；后来被修正为挫折增加了攻击的可能性，但不一定会导致攻击。","pt_BR":"Propõe que a frustração (o bloqueio de comportamento direcionado a um objetivo) sempre leva à agressão; posteriormente refinada para sugerir que a frustração aumenta a probabilidade, mas não causa inevitavelmente a agressão.","pt_PT":"Propõe que a frustração (o bloqueio de comportamento dirigido a um objetivo) leva sempre à agressão; posteriormente refinada para sugerir que a frustração aumenta a probabilidade, mas não causa inevitavelmente a agressão."}},
  { id: 'dc-psychology-0134', deck_id: 'deck-psychology', front: 'Stereotyping', back: 'Applying oversimplified and generalized beliefs about the characteristics of a social group to all members; the cognitive component of prejudice that can lead to discrimination.', sort_order: 134 , front_translations: {"es":"Estereotipaje","de":"Stereotypisierung","fr":"Stéréotypage","tr":"Kalıp Yargı","nl":"Stereotypering","ru":"Стереотипизация","zh":"刻板印象","pt_BR":"Estereotipagem","pt_PT":"Estereotipagem"}, back_translations: {"es":"Aplicación de creencias simplificadas y generalizadas sobre las características de un grupo social a todos los membros; el componente cognitivo del preconceito que puede levar a la discriminación.","de":"Die Anwendung vereinfachter und verallgemeinerter Überzeugungen über die Merkmale einer sozialen Gruppe auf alle Mitglieder; die kognitive Komponente von Vorurteilen, die zu Diskriminierung führen kann.","fr":"L'application de croyances simplifiées et généralisées sur les caractéristiques d'un groupe social à tous ses membres ; la composante cognitive du préjugé qui peut mener à la discrimination.","tr":"Bir sosyal grubun özellikleri hakkındaki aşırı basitleştirilmiş ve genelleştirilmiş inançların tüm üyelere uygulanması; ayrımcılığa yol açabilen önyargının bilişsel bileşeni.","nl":"Het toepassen van oversimplificeerde en gegeneraliseerde overtuigingen over de kenmerken van een sociale groep op alle leden; de cognitieve component van vooroordelen die tot discriminatie kan leiden.","ru":"Применение упрощённых и обобщённых убеждений о характеристиках социальной группы ко всем её членам; когнитивный компонент предубеждения, который может вести к дискриминации.","zh":"将关于某社会群体特征的过度简化和概括化信念应用于所有成员；是偏见的认知成分，可能导致歧视。","pt_BR":"Aplicação de crenças simplificadas e generalizadas sobre as características de um grupo social a todos os membros; o componente cognitivo do preconceito que pode levar à discriminação.","pt_PT":"Aplicação de crenças simplificadas e generalizadas sobre as características de um grupo social a todos os membros; o componente cognitivo do preconceito que pode levar à discriminação."}},
  { id: 'dc-psychology-0135', deck_id: 'deck-psychology', front: 'Implicit Bias', back: 'Unconscious attitudes or stereotypes that influence judgments and behavior without conscious awareness; measured using the Implicit Association Test (IAT).', sort_order: 135 , front_translations: {"es":"Viés Implícito","de":"Implizite Voreingenommenheit","fr":"Biais implicite","tr":"Örtük Önyargı","nl":"Impliciete bias","ru":"Имплицитное предубеждение","zh":"内隐偏见","pt_BR":"Viés Implícito","pt_PT":"Viés Implícito"}, back_translations: {"es":"Atitudes o estereótipos inconscientes que influenciam julgamentos y comportamientos sin conciencia; medidos usando el Teste de Associación Implícita (IAT).","de":"Unbewusste Einstellungen oder Stereotypen, die Urteile und Verhalten ohne bewusstes Gewahrsein beeinflussen; gemessen mit dem Impliziten Assoziationstest (IAT).","fr":"Attitudes ou stéréotypes inconscients qui influencent les jugements et le comportement sans conscience ; mesurés à l'aide du Test d'Association Implicite (IAT).","tr":"Bilinçli farkındalık olmaksızın yargıları ve davranışı etkileyen bilinçdışı tutumlar veya kalıp yargılar; Örtük Çağrışım Testi (IAT) ile ölçülür.","nl":"Onbewuste attitudes of stereotypen die oordelen en gedrag beïnvloeden zonder bewuste waarneming; gemeten met de Impliciete Associatietest (IAT).","ru":"Бессознательные установки или стереотипы, влияющие на суждения и поведение без осознания; измеряются с помощью Теста имплицитных ассоциаций (IAT).","zh":"在无意识情况下影响判断和行为的无意识态度或刻板印象；通过内隐联想测验（IAT）来测量。","pt_BR":"Atitudes ou estereótipos inconscientes que influenciam julgamentos e comportamentos sem consciência; medidos usando o Teste de Associação Implícita (IAT).","pt_PT":"Atitudes ou estereótipos inconscientes que influenciam julgamentos e comportamentos sem consciência; medidos através do Teste de Associação Implícita (IAT)."}},
  { id: 'dc-psychology-0136', deck_id: 'deck-psychology', front: 'Mere Exposure Effect', back: 'The tendency to develop a preference for things simply because of familiarity with them; Zajonc demonstrated that repeated exposure to stimuli increases positive evaluations.', sort_order: 136 , front_translations: {"es":"Efeito de Mera Exposición","de":"Mere-Exposure-Effekt","fr":"Effet de simple exposition","tr":"Salt Maruz Kalma Etkisi","nl":"Mere-exposure-effect","ru":"Эффект простого воздействия","zh":"单纯曝光效应","pt_BR":"Efeito de Mera Exposição","pt_PT":"Efeito de Mera Exposição"}, back_translations: {"es":"La tendencia a desenvolver preferencia por coisas simplemente por familiaridad con elas; Zajonc demonstrou que a exposición repetida a estímulos aumenta las avaliaciones positivas.","de":"Die Tendenz, eine Vorliebe für Dinge zu entwickeln, einfach weil man mit ihnen vertraut ist; Zajonc zeigte, dass wiederholte Exposition gegenüber Reizen die positive Bewertung erhöht.","fr":"La tendance à développer une préférence pour les choses simplement en raison de la familiarité ; Zajonc a démontré que l'exposition répétée aux stimuli augmente les évaluations positives.","tr":"Sadece aşinalık nedeniyle şeylere karşı tercih geliştirme eğilimi; Zajonc, uyaranlara tekrarlı maruz kalmanın olumlu değerlendirmeleri artırdığını göstermiştir.","nl":"De neiging om een voorkeur te ontwikkelen voor dingen simpelweg vanwege vertrouwdheid; Zajonc toonde aan dat herhaalde blootstelling aan stimuli positieve beoordelingen verhoogt.","ru":"Склонность отдавать предпочтение вещам просто из-за знакомства с ними; Зайонц показал, что повторное воздействие стимулов повышает положительные оценки.","zh":"仅因为对事物熟悉就会产生偏好的倾向；扎荣茨证明，反复接触刺激会增加正面评价。","pt_BR":"A tendência a desenvolver preferência por coisas simplesmente por familiaridade com elas; Zajonc demonstrou que a exposição repetida a estímulos aumenta as avaliações positivas.","pt_PT":"A tendência a desenvolver preferência por coisas simplesmente por familiaridade com elas; Zajonc demonstrou que a exposição repetida a estímulos aumenta as avaliações positivas."}},
  { id: 'dc-psychology-0137', deck_id: 'deck-psychology', front: 'Reciprocity Principle', back: 'The social norm requiring people to return favors or concessions; a powerful influence technique — receiving a gift or small favor creates a sense of obligation to reciprocate.', sort_order: 137 , front_translations: {"es":"Princípio de la Reciprocidad","de":"Reziprozitätsprinzip","fr":"Principe de réciprocité","tr":"Karşılıklılık İlkesi","nl":"Wederkerigheidsprincipe","ru":"Принцип взаимности","zh":"互惠原则","pt_BR":"Princípio da Reciprocidade","pt_PT":"Princípio da Reciprocidade"}, back_translations: {"es":"La norma social que exige que las personas retribuam favores o concesiones; una técnica de influencia poderosa — recibir un presente o pequeño favor crea un senso de obrigación de retribuir.","de":"Die soziale Norm, die Menschen dazu verpflichtet, Gefälligkeiten oder Zugeständnisse zu erwidern; eine wirksame Einflusstechnik — ein Geschenk oder kleiner Gefallen erzeugt ein Gefühl der Verpflichtung zur Erwiderung.","fr":"La norme sociale exigeant que les gens rendent les faveurs ou les concessions ; une technique d'influence puissante — recevoir un cadeau ou une petite faveur crée un sentiment d'obligation de réciprocité.","tr":"İnsanların iyilikleri veya tavizleri geri vermesini gerektiren sosyal norm; güçlü bir etkileme tekniği — bir hediye veya küçük bir iyilik almak karşılık verme zorunluluğu hissi yaratır.","nl":"De sociale norm die vereist dat mensen gunsten of concessies beantwoorden; een krachtige beïnvloedingstechniek — het ontvangen van een geschenk of kleine gunst creëert een gevoel van verplichting om iets terug te doen.","ru":"Социальная норма, требующая от людей отвечать на услуги или уступки; мощная техника влияния — получение подарка или небольшой услуги создаёт чувство обязанности ответить взаимностью.","zh":"要求人们回报恩惠或让步的社会规范；一种强大的影响技术——接受礼物或小恩惠会产生回报的义务感。","pt_BR":"A norma social que exige que as pessoas retribuam favores ou concessões; uma técnica de influência poderosa — receber um presente ou pequeno favor cria um senso de obrigação de retribuir.","pt_PT":"A norma social que exige que as pessoas retribuam favores ou concessões; uma técnica de influência poderosa — receber um presente ou pequeno favor cria um sentido de obrigação de retribuir."}},
  { id: 'dc-psychology-0138', deck_id: 'deck-psychology', front: 'Foot-in-the-Door Technique', back: 'A persuasion strategy where a small initial request is followed by a larger target request; compliance with the first increases the likelihood of agreeing to the second.', sort_order: 138 , front_translations: {"es":"Técnica del Pé en la Porta","de":"Fuß-in-der-Tür-Technik","fr":"Technique du pied dans la porte","tr":"Kapıya Ayak Koyma Tekniği","nl":"Voet-tussen-de-deur-techniek","ru":"Техника «нога в двери»","zh":"登门槛技术","pt_BR":"Técnica do Pé na Porta","pt_PT":"Técnica do Pé na Porta"}, back_translations: {"es":"Una estrategia de persuasão en que un pequeño pedido inicial es seguido por un pedido-alvo mayor; a conformidad con el primero aumenta a probabilidad de concordar con el según.","de":"Eine Überzeugungsstrategie, bei der auf eine kleine anfängliche Bitte eine größere Zielbitte folgt; die Zustimmung zur ersten erhöht die Wahrscheinlichkeit, der zweiten zuzustimmen.","fr":"Une stratégie de persuasion où une petite demande initiale est suivie d'une demande cible plus importante ; la conformité à la première augmente la probabilité d'accepter la seconde.","tr":"Küçük bir başlangıç isteğinin ardından daha büyük bir hedef isteğin geldiği bir ikna stratejisi; birinciye uyum, ikinciye kabul olasılığını artırır.","nl":"Een overtuigingsstrategie waarbij een klein initieel verzoek wordt gevolgd door een groter doelverzoek; instemming met het eerste vergroot de kans op instemming met het tweede.","ru":"Стратегия убеждения, при которой за небольшой первоначальной просьбой следует более крупная целевая просьба; согласие с первой увеличивает вероятность согласия со второй.","zh":"一种说服策略，先提出一个小的初始请求，然后提出更大的目标请求；对第一个请求的顺从增加了同意第二个请求的可能性。","pt_BR":"Uma estratégia de persuasão em que um pequeno pedido inicial é seguido por um pedido-alvo maior; a conformidade com o primeiro aumenta a probabilidade de concordar com o segundo.","pt_PT":"Uma estratégia de persuasão em que um pequeno pedido inicial é seguido por um pedido-alvo maior; a conformidade com o primeiro aumenta a probabilidade de concordar com o segundo."}},
  { id: 'dc-psychology-0139', deck_id: 'deck-psychology', front: 'Door-in-the-Face Technique', back: 'A persuasion strategy where a large request is made first (knowing it will be refused), followed by the smaller target request; the contrast makes the second request seem more reasonable.', sort_order: 139 , front_translations: {"es":"Técnica de la Porta en la Cara","de":"Tür-ins-Gesicht-Technik","fr":"Technique de la porte au nez","tr":"Yüze Kapıyı Kapatma Tekniği","nl":"Deur-in-het-gezicht-techniek","ru":"Техника «дверь в лицо»","zh":"留面子技术","pt_BR":"Técnica da Porta na Cara","pt_PT":"Técnica da Porta na Cara"}, back_translations: {"es":"Una estrategia de persuasão en que un grande pedido es feito primero (sabendo que será recusado), seguido por el pedido-alvo menor; el contraste hace el según pedido parecer más razoable.","de":"Eine Überzeugungsstrategie, bei der zuerst eine große Bitte gestellt wird (in dem Wissen, dass sie abgelehnt wird), gefolgt von der kleineren Zielbitte; der Kontrast lässt die zweite Bitte vernünftiger erscheinen.","fr":"Une stratégie de persuasion où une grande demande est faite en premier (sachant qu'elle sera refusée), suivie de la demande cible plus petite ; le contraste rend la seconde demande plus raisonnable.","tr":"Önce büyük bir isteğin yapıldığı (reddedileceği bilinerek), ardından daha küçük hedef isteğin geldiği bir ikna stratejisi; karşıtlık ikinci isteği daha makul gösterir.","nl":"Een overtuigingsstrategie waarbij eerst een groot verzoek wordt gedaan (wetende dat het wordt geweigerd), gevolgd door het kleinere doelverzoek; het contrast maakt het tweede verzoek redelijker.","ru":"Стратегия убеждения, при которой сначала делается крупная просьба (заведомо обречённая на отказ), а затем меньшая целевая просьба; контраст делает вторую просьбу более приемлемой.","zh":"一种说服策略，先提出一个大的请求（知道会被拒绝），然后提出较小的目标请求；对比使第二个请求显得更合理。","pt_BR":"Uma estratégia de persuasão em que um grande pedido é feito primeiro (sabendo que será recusado), seguido pelo pedido-alvo menor; o contraste faz o segundo pedido parecer mais razoável.","pt_PT":"Uma estratégia de persuasão em que um grande pedido é feito primeiro (sabendo que será recusado), seguido pelo pedido-alvo menor; o contraste faz o segundo pedido parecer mais razoável."}},
  { id: 'dc-psychology-0140', deck_id: 'deck-psychology', front: 'Locus of Control', back: 'Julian Rotter\'s concept: people with an internal locus of control believe they control outcomes through their own actions; those with an external locus attribute outcomes to luck or external forces.', sort_order: 140 , front_translations: {"es":"Lócus de Controle","de":"Kontrollüberzeugung","fr":"Locus de contrôle","tr":"Kontrol Odağı","nl":"Locus of control","ru":"Локус контроля","zh":"控制点","pt_BR":"Lócus de Controle","pt_PT":"Lócus de Controlo"}, back_translations: {"es":"Conceito de Julian Rotter: personas con lócus de controle interno acreditam que controlan los resultados por medio de sus propias acciones; aquelas con lócus externo atribuem los resultados a la sorte o fuerzas externas.","de":"Julian Rotters Konzept: Menschen mit internaler Kontrollüberzeugung glauben, dass sie Ergebnisse durch eigene Handlungen kontrollieren; Menschen mit externaler Kontrollüberzeugung schreiben Ergebnisse Glück oder äußeren Kräften zu.","fr":"Concept de Julian Rotter : les personnes ayant un locus de contrôle interne croient contrôler les résultats par leurs propres actions ; celles ayant un locus externe attribuent les résultats à la chance ou aux forces extérieures.","tr":"Julian Rotter'ın kavramı: iç kontrol odağına sahip kişiler sonuçları kendi eylemleriyle kontrol ettiklerine inanır; dış kontrol odağına sahip olanlar sonuçları şansa veya dış güçlere atfeder.","nl":"Julian Rotters concept: mensen met een interne locus of control geloven dat ze resultaten controleren door hun eigen acties; mensen met een externe locus schrijven resultaten toe aan geluk of externe krachten.","ru":"Концепция Джулиана Роттера: люди с внутренним локусом контроля верят, что контролируют результаты своими действиями; люди с внешним локусом приписывают результаты удаче или внешним силам.","zh":"朱利安·罗特的概念：具有内控倾向的人相信自己通过行动控制结果；具有外控倾向的人将结果归因于运气或外部力量。","pt_BR":"Conceito de Julian Rotter: pessoas com lócus de controle interno acreditam que controlam os resultados por meio de suas próprias ações; aquelas com lócus externo atribuem os resultados à sorte ou forças externas.","pt_PT":"Conceito de Julian Rotter: pessoas com lócus de controlo interno acreditam que controlam os resultados através das suas próprias ações; aquelas com lócus externo atribuem os resultados à sorte ou forças externas."}},
  { id: 'dc-psychology-0141', deck_id: 'deck-psychology', front: 'Self-Efficacy (Bandura)', back: 'A person\'s belief in their own ability to succeed in specific situations or accomplish a task; high self-efficacy predicts greater effort, persistence, and achievement.', sort_order: 141 , front_translations: {"es":"Autoeficácia (Bandura)","de":"Selbstwirksamkeit (Bandura)","fr":"Auto-efficacité (Bandura)","tr":"Öz Yeterlik (Bandura)","nl":"Zelfeffectiviteit (Bandura)","ru":"Самоэффективность (Бандура)","zh":"自我效能感（班杜拉）","pt_BR":"Autoeficácia (Bandura)","pt_PT":"Autoeficácia (Bandura)"}, back_translations: {"es":"La creencia de una persona en su propia capacidad de ter éxito en situaciones específicas o realizar una tarefa; alta autoeficácia preve mayor esforço, persistencia y rendimiento.","de":"Der Glaube einer Person an die eigene Fähigkeit, in bestimmten Situationen erfolgreich zu sein oder eine Aufgabe zu bewältigen; hohe Selbstwirksamkeit sagt größere Anstrengung, Ausdauer und Leistung voraus.","fr":"La croyance d'une personne en sa propre capacité à réussir dans des situations spécifiques ou à accomplir une tâche ; une auto-efficacité élevée prédit un effort, une persévérance et une réussite plus grands.","tr":"Bir kişinin belirli durumlarda başarılı olma veya bir görevi yerine getirme konusundaki kendi yeteneğine olan inancı; yüksek öz yeterlik daha fazla çaba, sebat ve başarıyı öngörür.","nl":"Het geloof van een persoon in het eigen vermogen om te slagen in specifieke situaties of een taak te volbrengen; hoge zelfeffectiviteit voorspelt meer inspanning, doorzettingsvermogen en prestatie.","ru":"Вера человека в собственную способность добиться успеха в конкретных ситуациях или выполнить задачу; высокая самоэффективность предсказывает большие усилия, настойчивость и достижения.","zh":"一个人对自己在特定情境中成功或完成任务的能力的信念；高自我效能感预示着更大的努力、坚持和成就。","pt_BR":"A crença de uma pessoa em sua própria capacidade de ter sucesso em situações específicas ou realizar uma tarefa; alta autoeficácia prevê maior esforço, persistência e desempenho.","pt_PT":"A crença de uma pessoa na sua própria capacidade de ter sucesso em situações específicas ou realizar uma tarefa; elevada autoeficácia prevê maior esforço, persistência e desempenho."}},
  { id: 'dc-psychology-0142', deck_id: 'deck-psychology', front: 'Growth Mindset (Dweck)', back: 'Carol Dweck\'s concept that intelligence and abilities can be developed through dedication and hard work; contrasts with a fixed mindset (viewing traits as innate and unchangeable).', sort_order: 142 , front_translations: {"es":"Mentalidad de Crescimento (Dweck)","de":"Wachstumsdenken (Dweck)","fr":"État d'esprit de développement (Dweck)","tr":"Gelişim Zihniyeti (Dweck)","nl":"Groeimindset (Dweck)","ru":"Установка на рост (Дуэк)","zh":"成长型思维（德韦克）","pt_BR":"Mentalidade de Crescimento (Dweck)","pt_PT":"Mentalidade de Crescimento (Dweck)"}, back_translations: {"es":"Conceito de Carol Dweck de que a inteligencia y las habilidades pueden ser desarrolladas por medio de dedicación y trabajo árduo; contrasta con a mentalidad fixa (ver traços como inatos y imutables).","de":"Carol Dwecks Konzept, dass Intelligenz und Fähigkeiten durch Engagement und harte Arbeit entwickelt werden können; im Gegensatz zur fixen Denkweise (Eigenschaften als angeboren und unveränderlich betrachten).","fr":"Le concept de Carol Dweck selon lequel l'intelligence et les capacités peuvent être développées par le dévouement et le travail acharné ; s'oppose à l'état d'esprit fixe (considérer les traits comme innés et immuables).","tr":"Carol Dweck'in zekâ ve yeteneklerin özveri ve sıkı çalışmayla geliştirilebileceği kavramı; sabit zihniyetle (özellikleri doğuştan ve değiştirilemez olarak görmek) karşıtlık oluşturur.","nl":"Carol Dwecks concept dat intelligentie en vaardigheden ontwikkeld kunnen worden door toewijding en hard werken; contrasteert met een vaste mindset (eigenschappen als aangeboren en onveranderlijk beschouwen).","ru":"Концепция Кэрол Дуэк о том, что интеллект и способности можно развить благодаря усердию и упорному труду; противоположна фиксированной установке (восприятие качеств как врождённых и неизменных).","zh":"卡罗尔·德韦克的概念，认为智力和能力可以通过努力和勤奋来发展；与固定型思维（认为特质是天生的、不可改变的）形成对比。","pt_BR":"Conceito de Carol Dweck de que a inteligência e as habilidades podem ser desenvolvidas por meio de dedicação e trabalho árduo; contrasta com a mentalidade fixa (ver traços como inatos e imutáveis).","pt_PT":"Conceito de Carol Dweck de que a inteligência e as capacidades podem ser desenvolvidas através de dedicação e trabalho árduo; contrasta com a mentalidade fixa (ver traços como inatos e imutáveis)."}},
  { id: 'dc-psychology-0143', deck_id: 'deck-psychology', front: 'Positive Psychology', back: 'A field founded by Martin Seligman focusing on well-being, strengths, and flourishing rather than pathology; emphasizes concepts like PERMA (Positive emotion, Engagement, Relationships, Meaning, Achievement).', sort_order: 143 , front_translations: {"es":"Psicologia Positiva","de":"Positive Psychologie","fr":"Psychologie positive","tr":"Pozitif Psikoloji","nl":"Positieve psychologie","ru":"Позитивная психология","zh":"积极心理学","pt_BR":"Psicologia Positiva","pt_PT":"Psicologia Positiva"}, back_translations: {"es":"Un campo fundado por Martin Seligman focado en el bem-estar, fuerzas y florescimento en vez de la patologia; enfatiza conceptos como PERMA (emoción Positiva, Engajamento, Relacionamentos, Significado, Realización).","de":"Ein von Martin Seligman gegründetes Feld, das sich auf Wohlbefinden, Stärken und Aufblühen statt auf Pathologie konzentriert; betont Konzepte wie PERMA (Positive Emotion, Engagement, Beziehungen, Sinn, Leistung).","fr":"Un domaine fondé par Martin Seligman axé sur le bien-être, les forces et l'épanouissement plutôt que la pathologie ; met l'accent sur des concepts comme PERMA (émotion Positive, Engagement, Relations, Sens, Accomplissement).","tr":"Martin Seligman tarafından kurulan, patoloji yerine iyi oluş, güçlü yönler ve gelişmeye odaklanan bir alan; PERMA (Pozitif duygu, Bağlanma, İlişkiler, Anlam, Başarı) gibi kavramları vurgular.","nl":"Een door Martin Seligman opgericht vakgebied gericht op welzijn, sterke punten en floreren in plaats van pathologie; benadrukt concepten als PERMA (Positieve emotie, Engagement, Relaties, Meaning, Achievement).","ru":"Область, основанная Мартином Селигманом, сосредоточенная на благополучии, сильных сторонах и процветании, а не на патологии; подчёркивает концепции PERMA (Позитивные эмоции, Вовлечённость, Отношения, Смысл, Достижения).","zh":"由马丁·塞利格曼创立的领域，关注幸福、优势和繁荣而非病理；强调PERMA（积极情绪、投入、关系、意义、成就）等概念。","pt_BR":"Um campo fundado por Martin Seligman focado no bem-estar, forças e florescimento em vez da patologia; enfatiza conceitos como PERMA (emoção Positiva, Engajamento, Relacionamentos, Significado, Realização).","pt_PT":"Um campo fundado por Martin Seligman focado no bem-estar, forças e florescimento em vez da patologia; enfatiza conceitos como PERMA (emoção Positiva, Envolvimento, Relações, Significado, Realização)."}},
  { id: 'dc-psychology-0144', deck_id: 'deck-psychology', front: 'Flow State (Csikszentmihalyi)', back: 'A state of complete absorption in a challenging but achievable task, characterized by loss of self-consciousness, intrinsic motivation, and a sense of effortless engagement.', sort_order: 144 , front_translations: {"es":"Estado de Flow (Csikszentmihalyi)","de":"Flow-Zustand (Csikszentmihalyi)","fr":"État de flow (Csikszentmihalyi)","tr":"Akış Durumu (Csikszentmihalyi)","nl":"Flowstaat (Csikszentmihalyi)","ru":"Состояние потока (Чиксентмихайи)","zh":"心流状态（契克森米哈赖）","pt_BR":"Estado de Flow (Csikszentmihalyi)","pt_PT":"Estado de Flow (Csikszentmihalyi)"}, back_translations: {"es":"Un estado de absorción completa en una tarefa desafiadora pero alcançable, caracterizado por la perda de la autoconsciencia, motivación intrínseca y una sensación de envolvimento sin esforço.","de":"Ein Zustand vollständiger Vertiefung in eine herausfordernde, aber erreichbare Aufgabe, gekennzeichnet durch Verlust des Selbstbewusstseins, intrinsische Motivation und ein Gefühl müheloser Beteiligung.","fr":"Un état d'absorption complète dans une tâche stimulante mais réalisable, caractérisé par la perte de la conscience de soi, la motivation intrinsèque et un sentiment d'engagement sans effort.","tr":"Zorlu ama başarılabilir bir göreve tamamen dalma durumu; benlik bilincinin kaybı, içsel motivasyon ve zahmetsiz katılım hissiyle karakterize edilir.","nl":"Een staat van volledige absorptie in een uitdagende maar haalbare taak, gekenmerkt door verlies van zelfbewustzijn, intrinsieke motivatie en een gevoel van moeiteloze betrokkenheid.","ru":"Состояние полного погружения в сложную, но выполнимую задачу, характеризующееся потерей самосознания, внутренней мотивацией и ощущением непринуждённой вовлечённости.","zh":"完全沉浸在具有挑战性但可实现的任务中的状态，特征包括自我意识的丧失、内在动机和毫不费力的参与感。","pt_BR":"Um estado de absorção completa em uma tarefa desafiadora mas alcançável, caracterizado pela perda da autoconsciência, motivação intrínseca e uma sensação de envolvimento sem esforço.","pt_PT":"Um estado de absorção completa numa tarefa desafiante mas alcançável, caracterizado pela perda da autoconsciência, motivação intrínseca e uma sensação de envolvimento sem esforço."}},
  { id: 'dc-psychology-0145', deck_id: 'deck-psychology', front: 'Stanford Prison Experiment (Zimbardo)', back: '1971 study in which student participants assigned as "guards" or "prisoners" adopted their roles so intensely the experiment was terminated early; illustrates the power of situational roles.', sort_order: 145 , front_translations: {"es":"Experimento de la Prisão de Stanford (Zimbardo)","de":"Stanford-Gefängnisexperiment (Zimbardo)","fr":"Expérience de Stanford (Zimbardo)","tr":"Stanford Hapishane Deneyi (Zimbardo)","nl":"Stanford-gevangenisexperiment (Zimbardo)","ru":"Стэнфордский тюремный эксперимент (Зимбардо)","zh":"斯坦福监狱实验（津巴多）","pt_BR":"Experimento da Prisão de Stanford (Zimbardo)","pt_PT":"Experiência da Prisão de Stanford (Zimbardo)"}, back_translations: {"es":"Estudo de 1971 en el qual participantes estudantes designados como \"guardas\" o \"prisioneros\" adotaram sus papéis tão intensamente que el experimento fue encerrado prematuramente; ilustra el poder de los papéis situacionais.","de":"Studie von 1971, in der Studienteilnehmer, die als \"Wärter\" oder \"Gefangene\" eingeteilt wurden, ihre Rollen so intensiv übernahmen, dass das Experiment vorzeitig abgebrochen wurde; veranschaulicht die Macht situativer Rollen.","fr":"Étude de 1971 dans laquelle des participants étudiants assignés comme « gardiens » ou « prisonniers » ont adopté leurs rôles si intensément que l'expérience a été interrompue prématurément ; illustre le pouvoir des rôles situationnels.","tr":"1971'de öğrenci katılımcıların \"gardiyan\" veya \"mahkûm\" olarak atandığı ve rollerini o kadar yoğun benimsedikleri ki deneyin erken sonlandırıldığı çalışma; durumsal rollerin gücünü gösterir.","nl":"Studie uit 1971 waarin studentdeelnemers die als \"bewakers\" of \"gevangenen\" waren aangewezen hun rollen zo intens aannamen dat het experiment voortijdig werd beëindigd; illustreert de kracht van situationele rollen.","ru":"Исследование 1971 года, в котором студенты-участники, назначенные «охранниками» или «заключёнными», настолько вжились в свои роли, что эксперимент был досрочно прекращён; иллюстрирует силу ситуационных ролей.","zh":"1971年的研究中，被分配为「看守」或「囚犯」的学生参与者如此深入地进入角色，以至于实验被提前终止；说明了情境角色的力量。","pt_BR":"Estudo de 1971 no qual participantes estudantes designados como \"guardas\" ou \"prisioneiros\" adotaram seus papéis tão intensamente que o experimento foi encerrado prematuramente; ilustra o poder dos papéis situacionais.","pt_PT":"Estudo de 1971 no qual participantes estudantes designados como \"guardas\" ou \"prisioneiros\" adotaram os seus papéis tão intensamente que a experiência foi terminada prematuramente; ilustra o poder dos papéis situacionais."}},
  { id: 'dc-psychology-0146', deck_id: 'deck-psychology', front: 'Nature vs. Nurture', back: 'A longstanding debate in psychology over whether behavior is primarily determined by genetics (nature) or environment and experience (nurture); modern consensus holds that both interact.', sort_order: 146 , front_translations: {"es":"Natureza vs. Criación","de":"Anlage vs. Umwelt","fr":"Nature vs. culture","tr":"Doğa-Çevre Tartışması","nl":"Nature vs. nurture","ru":"Природа против воспитания","zh":"先天与后天","pt_BR":"Natureza vs. Criação","pt_PT":"Natureza vs. Criação"}, back_translations: {"es":"Un debate de ancha data en la psicologia sobre se el comportamiento es determinado principalmente por la genética (natureza) o por el ambiente y experiencia (criación); el consenso moderno sustenta que ambos interaje.","de":"Eine langjährige Debatte in der Psychologie darüber, ob Verhalten primär durch Genetik (Anlage) oder Umwelt und Erfahrung (Umwelt) bestimmt wird; der moderne Konsens besagt, dass beide zusammenwirken.","fr":"Un débat de longue date en psychologie sur la question de savoir si le comportement est principalement déterminé par la génétique (nature) ou l'environnement et l'expérience (culture) ; le consensus moderne considère que les deux interagissent.","tr":"Psikolojide davranışın öncelikle genetik (doğa) mi yoksa çevre ve deneyim (yetiştirme) mi tarafından belirlendiğine dair uzun süredir devam eden tartışma; modern uzlaşı her ikisinin etkileştiğini savunur.","nl":"Een langdurig debat in de psychologie over de vraag of gedrag voornamelijk wordt bepaald door genetica (nature) of omgeving en ervaring (nurture); de moderne consensus is dat beide samenwerken.","ru":"Давний спор в психологии о том, определяется ли поведение преимущественно генетикой (природой) или средой и опытом (воспитанием); современный консенсус состоит в том, что оба фактора взаимодействуют.","zh":"心理学中关于行为主要由遗传（先天）还是环境和经验（后天）决定的长期争论；现代共识认为两者相互作用。","pt_BR":"Um debate de longa data na psicologia sobre se o comportamento é determinado principalmente pela genética (natureza) ou pelo ambiente e experiência (criação); o consenso moderno sustenta que ambos interagem.","pt_PT":"Um debate de longa data na psicologia sobre se o comportamento é determinado principalmente pela genética (natureza) ou pelo ambiente e experiência (criação); o consenso moderno sustenta que ambos interagem."}},
  { id: 'dc-psychology-0147', deck_id: 'deck-psychology', front: 'Twin Studies', back: 'Research comparing identical (monozygotic) and fraternal (dizygotic) twins to disentangle genetic and environmental influences; identical twins sharing ~100% of genes allow heritability estimates.', sort_order: 147 , front_translations: {"es":"Estudos con Gemeos","de":"Zwillingsstudien","fr":"Études de jumeaux","tr":"İkiz Çalışmaları","nl":"Tweelingstudies","ru":"Близнецовые исследования","zh":"双生子研究","pt_BR":"Estudos com Gêmeos","pt_PT":"Estudos com Gémeos"}, back_translations: {"es":"Pesquisa comparando gemeos identicos (monozigóticos) y fraternos (dizigóticos) para separar influencias genéticas y ambientais; gemeos identicos compartilhando ~100% de los genes permiten estimativas de herdabilidad.","de":"Forschung, die eineiige (monozygote) und zweieiige (dizygote) Zwillinge vergleicht, um genetische und umweltbedingte Einflüsse zu entwirren; eineiige Zwillinge, die ca. 100 % der Gene teilen, ermöglichen Heritabilitätsschätzungen.","fr":"Recherches comparant les jumeaux identiques (monozygotes) et fraternels (dizygotes) pour démêler les influences génétiques et environnementales ; les jumeaux identiques partageant environ 100 % de leurs gènes permettent d'estimer l'héritabilité.","tr":"Genetik ve çevresel etkileri ayırt etmek için tek yumurta (monozigot) ve çift yumurta (dizigot) ikizleri karşılaştıran araştırma; genlerin yaklaşık %100'ünü paylaşan tek yumurta ikizleri kalıtılabilirlik tahminlerine olanak tanır.","nl":"Onderzoek dat eeneiige (monozygote) en twee-eiige (dizygote) tweelingen vergelijkt om genetische en omgevingsinvloeden te ontrafelen; eeneiige tweelingen die ~100% van hun genen delen maken erfelijkheidsschattingen mogelijk.","ru":"Исследования, сравнивающие однояйцевых (монозиготных) и разнояйцевых (дизиготных) близнецов для разделения генетических и средовых влияний; однояйцевые близнецы, имеющие ~100% общих генов, позволяют оценить наследуемость.","zh":"比较同卵（单卵）和异卵（双卵）双胞胎以区分遗传和环境影响的研究；共享约100%基因的同卵双胞胎可以进行遗传率估计。","pt_BR":"Pesquisa comparando gêmeos idênticos (monozigóticos) e fraternos (dizigóticos) para separar influências genéticas e ambientais; gêmeos idênticos compartilhando ~100% dos genes permitem estimativas de herdabilidade.","pt_PT":"Investigação comparando gémeos idênticos (monozigóticos) e fraternos (dizigóticos) para separar influências genéticas e ambientais; gémeos idênticos partilhando ~100% dos genes permitem estimativas de hereditariedade."}},
  { id: 'dc-psychology-0148', deck_id: 'deck-psychology', front: 'Heritability', back: 'The proportion of variance in a trait within a population attributable to genetic differences; a heritability of 0.5 means 50% of the variation in that trait is due to genetic factors.', sort_order: 148 , front_translations: {"es":"Herdabilidad","de":"Heritabilität","fr":"Héritabilité","tr":"Kalıtılabilirlik","nl":"Erfelijkheid","ru":"Наследуемость","zh":"遗传率","pt_BR":"Herdabilidade","pt_PT":"Hereditariedade"}, back_translations: {"es":"La proporción de la variancia de un traço dentro de una población atribuible a diferencias genéticas; una herdabilidad de 0,5 significa que 50% de la variación nesse traço se deve a fatores genéticos.","de":"Der Anteil der Varianz eines Merkmals innerhalb einer Population, der auf genetische Unterschiede zurückzuführen ist; eine Heritabilität von 0,5 bedeutet, dass 50 % der Variation dieses Merkmals auf genetische Faktoren zurückgehen.","fr":"La proportion de la variance d'un trait au sein d'une population attribuable aux différences génétiques ; une héritabilité de 0,5 signifie que 50 % de la variation de ce trait est due à des facteurs génétiques.","tr":"Bir popülasyon içinde bir özellikteki varyansın genetik farklılıklara atfedilebilen oranı; 0,5'lik bir kalıtılabilirlik, o özellikteki varyasyonun %50'sinin genetik faktörlerden kaynaklandığı anlamına gelir.","nl":"Het aandeel van de variatie in een eigenschap binnen een populatie dat toe te schrijven is aan genetische verschillen; een erfelijkheid van 0,5 betekent dat 50% van de variatie in die eigenschap te wijten is aan genetische factoren.","ru":"Доля дисперсии признака в популяции, обусловленная генетическими различиями; наследуемость 0,5 означает, что 50% вариации данного признака обусловлено генетическими факторами.","zh":"群体中某一特质的变异中可归因于遗传差异的比例；遗传率为0.5意味着该特质50%的变异归因于遗传因素。","pt_BR":"A proporção da variância de um traço dentro de uma população atribuível a diferenças genéticas; uma herdabilidade de 0,5 significa que 50% da variação nesse traço se deve a fatores genéticos.","pt_PT":"A proporção da variância de um traço dentro de uma população atribuível a diferenças genéticas; uma hereditariedade de 0,5 significa que 50% da variação nesse traço se deve a fatores genéticos."}},
  { id: 'dc-psychology-0149', deck_id: 'deck-psychology', front: 'Evolutionary Psychology', back: 'The study of human behavior and cognition through the lens of evolutionary adaptation; argues that many psychological traits evolved because they enhanced reproductive success.', sort_order: 149 , front_translations: {"es":"Psicologia Evolucionista","de":"Evolutionspsychologie","fr":"Psychologie évolutionniste","tr":"Evrimsel Psikoloji","nl":"Evolutionaire psychologie","ru":"Эволюционная психология","zh":"进化心理学","pt_BR":"Psicologia Evolucionista","pt_PT":"Psicologia Evolucionista"}, back_translations: {"es":"El estudio del comportamiento humano y de la cognición a través de la lente de la adaptación evolutiva; argumenta que muchos traços psicológicos evoluíram porque aumentaram el éxito reprodutivo.","de":"Die Untersuchung menschlichen Verhaltens und der Kognition durch die Linse evolutionärer Anpassung; argumentiert, dass viele psychologische Merkmale sich entwickelten, weil sie den Fortpflanzungserfolg steigerten.","fr":"L'étude du comportement humain et de la cognition à travers le prisme de l'adaptation évolutive ; soutient que de nombreux traits psychologiques ont évolué parce qu'ils amélioraient le succès reproductif.","tr":"İnsan davranışı ve bilişinin evrimsel adaptasyon perspektifinden incelenmesi; birçok psikolojik özelliğin üreme başarısını artırdığı için evrimleştiğini savunur.","nl":"De studie van menselijk gedrag en cognitie door de lens van evolutionaire aanpassing; stelt dat veel psychologische eigenschappen zijn geëvolueerd omdat ze het reproductief succes vergrootten.","ru":"Изучение человеческого поведения и когнитивных процессов через призму эволюционной адаптации; утверждает, что многие психологические черты эволюционировали, поскольку повышали репродуктивный успех.","zh":"通过进化适应的视角研究人类行为和认知；认为许多心理特征之所以进化是因为它们增强了繁殖成功率。","pt_BR":"O estudo do comportamento humano e da cognição através da lente da adaptação evolutiva; argumenta que muitos traços psicológicos evoluíram porque aumentaram o sucesso reprodutivo.","pt_PT":"O estudo do comportamento humano e da cognição através da lente da adaptação evolutiva; argumenta que muitos traços psicológicos evoluíram porque aumentaram o sucesso reprodutivo."}},
  { id: 'dc-psychology-0150', deck_id: 'deck-psychology', front: 'Cultural Psychology', back: 'The study of how cultural norms, practices, and values shape psychological processes; findings from Western, educated, industrialized, rich, democratic (WEIRD) samples may not generalize universally.', sort_order: 150 , front_translations: {"es":"Psicologia cultural","de":"Kulturpsychologie","fr":"Psychologie culturelle","tr":"Kültürel Psikoloji","nl":"Culturele psychologie","ru":"Культурная психология","zh":"文化心理学","pt_BR":"Psicologia cultural","pt_PT":"Psicologia cultural"}, back_translations: {"es":"El estudio de como normas culturais, práticas y valores moldam procesos psicológicos; achados de amostras ocidentais, educadas, industrializadas, ricas y democráticas (WEIRD) pueden no ser universalmente generalizables.","de":"Die Erforschung, wie kulturelle Normen, Praktiken und Werte psychologische Prozesse formen; Ergebnisse aus westlichen, gebildeten, industrialisierten, reichen, demokratischen (WEIRD) Stichproben sind möglicherweise nicht universell verallgemeinerbar.","fr":"L'étude de la façon dont les normes culturelles, les pratiques et les valeurs façonnent les processus psychologiques ; les résultats obtenus auprès d'échantillons occidentaux, éduqués, industrialisés, riches et démocratiques (WEIRD) ne sont pas nécessairement universels.","tr":"Kültürel normların, uygulamaların ve değerlerin psikolojik süreçleri nasıl şekillendirdiğini inceleyen alan; Batılı, eğitimli, sanayileşmiş, zengin, demokratik (WEIRD) örneklemlerden elde edilen bulgular evrensel olarak genellenemeyebilir.","nl":"De studie van hoe culturele normen, praktijken en waarden psychologische processen vormgeven; bevindingen van westerse, opgeleide, geïndustrialiseerde, rijke, democratische (WEIRD) steekproeven zijn mogelijk niet universeel generaliseerbaar.","ru":"Изучение того, как культурные нормы, практики и ценности формируют психологические процессы; результаты, полученные на западных, образованных, индустриализированных, богатых, демократических (WEIRD) выборках, могут не быть универсальными.","zh":"研究文化规范、实践和价值观如何塑造心理过程；来自西方、受过教育、工业化、富裕、民主（WEIRD）样本的发现可能不具有普遍适用性。","pt_BR":"O estudo de como normas culturais, práticas e valores moldam processos psicológicos; achados de amostras ocidentais, educadas, industrializadas, ricas e democráticas (WEIRD) podem não ser universalmente generalizáveis.","pt_PT":"O estudo de como as normas culturais, práticas e valores moldam os processos psicológicos; os resultados de amostras ocidentais, escolarizadas, industrializadas, ricas e democráticas (WEIRD) podem não ser universalmente generalizáveis."}},
];
